const getLibraryPreviewBlocks = (site: PublicSite) => {
  const blocks = [...(site.blocks || [])].sort((a, b) => a.sortOrder - b.sortOrder)
  if (!hasEditablePages(site)) return blocks.filter(block => !isPopupBlock(block)).slice(0, 4)

  const pages = normalizeFunnelPages(site)
  const firstPageId = pages[0]?.id || DEFAULT_FUNNEL_PAGE_ID
  const pageBlocks = blocks.filter(block => (
    !isPopupBlock(block) &&
    (isGlobalHeaderBlock(block) || getBlockPageId(block, pages) === firstPageId)
  ))
  return isLanding(site) ? pageBlocks : pageBlocks.slice(0, 4)
}

const getSettingString = (settings: Record<string, unknown>, key: string) => {
  const value = settings?.[key]
  return typeof value === 'string' ? value : ''
}

const getSettingBoolean = (settings: Record<string, unknown>, key: string, fallback = false) => {
  const value = settings?.[key]
  if (typeof value === 'boolean') return value
  if (typeof value === 'number') return value === 1
  if (typeof value === 'string') return ['1', 'true', 'yes', 'on', 'enabled'].includes(value.trim().toLowerCase())
  return fallback
}

type CountdownMode = 'date' | 'duration'
type CountdownVisitorMode = 'shared' | 'visitor'
type CountdownStorageUnit = 'days' | 'months'
type CountdownCompletionAction = 'none' | 'redirect' | 'hide_target' | 'show_target' | 'hide_self' | 'restart'

const countdownModeOptions: Array<{ value: CountdownMode; label: string }> = [
  { value: 'duration', label: 'Duración personalizada' },
  { value: 'date', label: 'Hasta una fecha específica' }
]

const countdownVisitorModeOptions: Array<{ value: CountdownVisitorMode; label: string }> = [
  { value: 'shared', label: 'Mismo contador para todos' },
  { value: 'visitor', label: 'Guardar por visitante' }
]

const countdownStorageUnitOptions: Array<{ value: CountdownStorageUnit; label: string }> = [
  { value: 'days', label: 'Días' },
  { value: 'months', label: 'Meses' }
]

const countdownCompletionActionOptions: Array<{ value: CountdownCompletionAction; label: string }> = [
  { value: 'none', label: 'No hacer nada' },
  { value: 'redirect', label: 'Redirigir a URL' },
  { value: 'hide_target', label: 'Ocultar elemento' },
  { value: 'show_target', label: 'Mostrar elemento' },
  { value: 'hide_self', label: 'Ocultar este contador' },
  { value: 'restart', label: 'Reiniciar automáticamente' }
]

const getCountdownMode = (settings: Record<string, unknown>): CountdownMode =>
  getSettingString(settings, 'countdownMode') === 'date' ? 'date' : 'duration'

const getCountdownVisitorMode = (settings: Record<string, unknown>): CountdownVisitorMode =>
  getSettingString(settings, 'countdownVisitorMode') === 'visitor' ? 'visitor' : 'shared'

const getCountdownStorageUnit = (settings: Record<string, unknown>): CountdownStorageUnit =>
  getSettingString(settings, 'countdownStorageUnit') === 'months' ? 'months' : 'days'

const getCountdownCompletionAction = (settings: Record<string, unknown>): CountdownCompletionAction => {
  const value = getSettingString(settings, 'countdownCompletionAction') as CountdownCompletionAction
  return countdownCompletionActionOptions.some(option => option.value === value) ? value : 'none'
}

const getCountdownDurationSeconds = (settings: Record<string, unknown>) => {
  const days = getSettingNumber(settings, 'countdownDurationDays', 1, 0, 3650)
  const hours = getSettingNumber(settings, 'countdownDurationHours', 0, 0, 23)
  const minutes = getSettingNumber(settings, 'countdownDurationMinutes', 0, 0, 59)
  const seconds = getSettingNumber(settings, 'countdownDurationSeconds', 0, 0, 59)
  return Math.max(1, days * 86400 + hours * 3600 + minutes * 60 + seconds)
}

const splitCountdownSeconds = (totalSeconds: number) => {
  const safe = Math.max(0, Math.floor(Number.isFinite(totalSeconds) ? totalSeconds : 0))
  const days = Math.floor(safe / 86400)
  const hours = Math.floor((safe % 86400) / 3600)
  const minutes = Math.floor((safe % 3600) / 60)
  const seconds = safe % 60
  return { days, hours, minutes, seconds }
}

const getCountdownPreviewParts = (settings: Record<string, unknown>) => {
  const now = Date.now()
  const mode = getCountdownMode(settings)
  if (mode === 'date') {
    const targetTime = Date.parse(getSettingString(settings, 'countdownTargetDate'))
    if (Number.isFinite(targetTime)) return splitCountdownSeconds(Math.max(0, Math.floor((targetTime - now) / 1000)))
  }
  return splitCountdownSeconds(getCountdownDurationSeconds(settings))
}

const formatCountdownPart = (value: number) => String(Math.max(0, Math.floor(value))).padStart(2, '0')

const isVideoControlsMode = (value: string): value is VideoControlsMode =>
  videoControlsModeOptions.some(option => option.value === value)

const getVideoControlsMode = (settings: Record<string, unknown>): VideoControlsMode => {
  const rawMode = getSettingString(settings, 'videoControlsMode')
  if (isVideoControlsMode(rawMode)) return rawMode
  if (settings.videoControls === false) return 'none'
  return DEFAULT_VIDEO_CONTROLS_MODE
}

const isVideoPlayIconStyle = (value: string): value is VideoPlayIconStyle =>
  videoPlayIconOptions.some(option => option.value === value)

const getVideoPlayIconStyle = (settings: Record<string, unknown>): VideoPlayIconStyle => {
  const rawStyle = getSettingString(settings, 'videoPlayIconStyle')
  return isVideoPlayIconStyle(rawStyle) ? rawStyle : DEFAULT_VIDEO_PLAY_ICON_STYLE
}

const isVideoPlayShape = (value: string): value is VideoPlayShape =>
  videoPlayShapeOptions.some(option => option.value === value)

const isLegacyDefaultVideoPlay = (settings: Record<string, unknown>) => {
  const rawShape = getSettingString(settings, 'videoPlayShape')
  const rawRadius = Number(settings.videoPlayRadius)
  const rawSize = Number(settings.videoPlaySize)
  const rawIconSize = Number(settings.videoPlayIconSize)

  return rawShape === 'round' &&
    rawRadius === LEGACY_VIDEO_PLAY_RADIUS &&
    (!Number.isFinite(rawSize) || rawSize === LEGACY_VIDEO_PLAY_SIZE) &&
    (!Number.isFinite(rawIconSize) || rawIconSize === LEGACY_VIDEO_PLAY_ICON_SIZE)
}

const getVideoPlayShape = (settings: Record<string, unknown>): VideoPlayShape => {
  const rawShape = getSettingString(settings, 'videoPlayShape')
  if (isVideoPlayShape(rawShape)) {
    return isLegacyDefaultVideoPlay(settings) ? DEFAULT_VIDEO_PLAY_SHAPE : rawShape
  }
  const radius = Number(settings.videoPlayRadius)
  return Number.isFinite(radius) && radius < 120 ? 'rectangle' : DEFAULT_VIDEO_PLAY_SHAPE
}

const getVideoPlaySizeValue = (settings: Record<string, unknown>) => {
  const rawSize = Number(settings.videoPlaySize)
  if (!Number.isFinite(rawSize)) return DEFAULT_VIDEO_PLAY_SIZE
  if (isLegacyDefaultVideoPlay(settings) || (rawSize === 64 && !Object.prototype.hasOwnProperty.call(settings, 'videoPlayShape'))) {
    return DEFAULT_VIDEO_PLAY_SIZE
  }
  return Math.min(VIDEO_PLAY_SIZE_MAX, Math.max(VIDEO_PLAY_SIZE_MIN, rawSize))
}

const getVideoPlayIconSizeValue = (settings: Record<string, unknown>) => {
  const rawSize = Number(settings.videoPlayIconSize)
  if (!Number.isFinite(rawSize)) return DEFAULT_VIDEO_PLAY_ICON_SIZE
  if (isLegacyDefaultVideoPlay(settings) || (rawSize === 22 && !Object.prototype.hasOwnProperty.call(settings, 'videoPlayShape'))) {
    return DEFAULT_VIDEO_PLAY_ICON_SIZE
  }
  return Math.min(VIDEO_PLAY_ICON_SIZE_MAX, Math.max(VIDEO_PLAY_ICON_SIZE_MIN, rawSize))
}

const getVideoPlayRadiusValue = (settings: Record<string, unknown>, shape: VideoPlayShape) => {
  if (isLegacyDefaultVideoPlay(settings)) return DEFAULT_VIDEO_PLAY_RADIUS
  const defaultRadius = shape === 'rectangle' ? DEFAULT_VIDEO_PLAY_RADIUS : LEGACY_VIDEO_PLAY_RADIUS
  return getSettingNumber(settings, 'videoPlayRadius', defaultRadius, 0, LEGACY_VIDEO_PLAY_RADIUS)
}

const getVideoControlPanelRadiusValue = (settings: Record<string, unknown>) =>
  getSettingNumber(settings, 'videoControlPanelRadius', DEFAULT_VIDEO_CONTROL_PANEL_RADIUS, 0, VIDEO_CONTROL_PANEL_RADIUS_MAX)

const shouldShowVideoControlBar = (settings: Record<string, unknown>) =>
  settings.videoControlBar !== false

const shouldShowVideoControlBarInitially = (settings: Record<string, unknown>) =>
  settings.videoControlBarInitiallyVisible !== false

const shouldShowVideoControlPlay = (settings: Record<string, unknown>) =>
  settings.videoControlPlay !== false

const shouldShowVideoControlSettings = (settings: Record<string, unknown>) =>
  settings.videoControlSettings !== false

const shouldShowVideoControlTime = (settings: Record<string, unknown>) =>
  settings.videoControlTime !== false

const getVideoTrickProgressRampPercent = (settings: Record<string, unknown>) =>
  getSettingNumber(settings, 'videoTrickProgressRampPercent', DEFAULT_VIDEO_TRICK_PROGRESS_RAMP_PERCENT, VIDEO_TRICK_PROGRESS_RAMP_MIN, VIDEO_TRICK_PROGRESS_RAMP_MAX)

const getVideoTrickProgressPeakPercent = (settings: Record<string, unknown>) => {
  const rampPercent = getVideoTrickProgressRampPercent(settings)
  const rawPeak = getSettingNumber(settings, 'videoTrickProgressPeakPercent', DEFAULT_VIDEO_TRICK_PROGRESS_PEAK_PERCENT, VIDEO_TRICK_PROGRESS_PEAK_MIN, VIDEO_TRICK_PROGRESS_PEAK_MAX)
  return Math.min(VIDEO_TRICK_PROGRESS_PEAK_MAX, Math.max(rawPeak, rampPercent + 5))
}

const getVideoTrickProgressRatio = (settings: Record<string, unknown>, realRatio: number) => {
  const ratio = Math.min(1, Math.max(0, Number.isFinite(realRatio) ? realRatio : 0))
  if (settings.videoTrickProgressEnabled !== true) return ratio

  const rampRatio = Math.min(0.95, Math.max(0.05, getVideoTrickProgressRampPercent(settings) / 100))
  const peakRatio = Math.min(0.98, Math.max(rampRatio + 0.05, getVideoTrickProgressPeakPercent(settings) / 100))
  if (ratio <= rampRatio) return (ratio / rampRatio) * peakRatio
  return peakRatio + ((ratio - rampRatio) / (1 - rampRatio)) * (1 - peakRatio)
}

const getVideoSoundNoticeText = (settings: Record<string, unknown>) => {
  if (Object.prototype.hasOwnProperty.call(settings, 'videoSoundNoticeText')) {
    const text = getSettingString(settings, 'videoSoundNoticeText').trim()
    return text === LEGACY_VIDEO_SOUND_NOTICE_TEXT ? DEFAULT_VIDEO_SOUND_NOTICE_TEXT : text
  }
  return DEFAULT_VIDEO_SOUND_NOTICE_TEXT
}

const getVideoSoundNoticeHideAfter = (settings: Record<string, unknown>) => {
  const value = Number(settings.videoSoundNoticeHideAfter)
  if (!Number.isFinite(value)) return DEFAULT_VIDEO_SOUND_NOTICE_HIDE_AFTER
  if (value <= 0) return 0
  return Math.min(12, Math.max(3, value))
}

const roundVideoPreviewSecond = (value: number) =>
  Math.round(value / VIDEO_PREVIEW_STEP_SECONDS) * VIDEO_PREVIEW_STEP_SECONDS

const getVideoPreviewMaxSeconds = (durationSeconds?: number) => {
  const duration = Number(durationSeconds)
  if (!Number.isFinite(duration) || duration <= 0) return VIDEO_PREVIEW_MAX_SPAN_SECONDS
  return Math.max(VIDEO_PREVIEW_STEP_SECONDS, roundVideoPreviewSecond(duration))
}

const getVideoPreviewMinimumSpan = (maxSeconds: number) =>
  Math.min(1, Math.max(VIDEO_PREVIEW_STEP_SECONDS, maxSeconds))

const normalizeVideoPreviewRange = (settings: Record<string, unknown>, durationSeconds?: number) => {
  const maxSeconds = getVideoPreviewMaxSeconds(durationSeconds)
  const minSpan = getVideoPreviewMinimumSpan(maxSeconds)
  const maxSpan = Math.min(VIDEO_PREVIEW_MAX_SPAN_SECONDS, maxSeconds)
  const fallbackEnd = Math.min(VIDEO_PREVIEW_DEFAULT_SECONDS, maxSeconds)
  const rawStart = Number(settings.videoPreviewStart)
  const rawEnd = Number(settings.videoPreviewEnd)
  const clampedStart = Math.min(
    Math.max(0, roundVideoPreviewSecond(Number.isFinite(rawStart) ? rawStart : 0)),
    Math.max(0, maxSeconds - minSpan)
  )
  const clampedEnd = Math.min(
    Math.max(clampedStart + minSpan, roundVideoPreviewSecond(Number.isFinite(rawEnd) ? rawEnd : fallbackEnd)),
    maxSeconds,
    clampedStart + maxSpan
  )

  return {
    start: Number(clampedStart.toFixed(2)),
    end: Number(clampedEnd.toFixed(2)),
    max: Number(maxSeconds.toFixed(2)),
    minSpan: Number(minSpan.toFixed(2)),
    maxSpan: Number(maxSpan.toFixed(2))
  }
}

const formatVideoPreviewSecond = (value: number) => {
  const safe = Math.max(0, Number.isFinite(value) ? value : 0)
  const minutes = Math.floor(safe / 60)
  const seconds = safe - minutes * 60
  const formattedSeconds = seconds % 1 === 0
    ? String(seconds).padStart(2, '0')
    : seconds.toFixed(1).padStart(4, '0')
  return `${minutes}:${formattedSeconds}`
}

const formatVideoProgressPercent = (value: number) => {
  const safe = Math.min(1, Math.max(0, Number.isFinite(value) ? value : 0))
  return `${Number((safe * 100).toFixed(3))}%`
}

const isVideoOrientation = (value: unknown): value is VideoOrientation =>
  videoOrientationOptions.some(option => option.value === value)

const getVideoOrientationFromDimensions = (width?: unknown, height?: unknown): Exclude<VideoOrientation, 'auto'> | '' => {
  const numericWidth = Number(width)
  const numericHeight = Number(height)
  if (!Number.isFinite(numericWidth) || !Number.isFinite(numericHeight) || numericWidth <= 0 || numericHeight <= 0) return ''
  return numericHeight > numericWidth ? 'portrait' : 'landscape'
}

const getVideoOrientationFromAsset = (asset?: MediaAsset | null): Exclude<VideoOrientation, 'auto'> | '' => {
  if (!asset) return ''
  const directOrientation = getVideoOrientationFromDimensions(asset.width, asset.height)
  if (directOrientation) return directOrientation

  const stream = asset.metadata?.stream
  if (stream && typeof stream === 'object') {
    const video = (stream as { video?: unknown }).video
    if (video && typeof video === 'object') {
      return getVideoOrientationFromDimensions(
        (video as { width?: unknown }).width,
        (video as { height?: unknown }).height
      )
    }
  }

  return ''
}

const getVideoOrientation = (settings: Record<string, unknown> = {}): VideoOrientation => {
  const value = getSettingString(settings, 'videoOrientation')
  return isVideoOrientation(value) ? value : DEFAULT_VIDEO_ORIENTATION
}

const getResolvedVideoOrientation = (
  settings: Record<string, unknown> = {},
  detectedOrientation: Exclude<VideoOrientation, 'auto'> | '' = ''
): Exclude<VideoOrientation, 'auto'> => {
  const configured = getVideoOrientation(settings)
  if (configured !== 'auto') return configured
  return detectedOrientation || 'landscape'
}

const getVideoAspectRatio = (orientation: Exclude<VideoOrientation, 'auto'>) =>
  orientation === 'portrait' ? DEFAULT_VIDEO_PORTRAIT_ASPECT_RATIO : DEFAULT_VIDEO_LANDSCAPE_ASPECT_RATIO

const getVideoAspectRatioNumber = (orientation: Exclude<VideoOrientation, 'auto'>) =>
  orientation === 'portrait' ? 9 / 16 : 16 / 9

const readCssPixelValue = (value: string | null | undefined) => {
  const parsed = Number.parseFloat(String(value || ''))
  return Number.isFinite(parsed) ? parsed : 0
}

const isVisibleLayoutElement = (element: HTMLElement | null) => {
  if (!element || element.hidden) return false
  const style = window.getComputedStyle(element)
  return style.display !== 'none' && style.visibility !== 'hidden'
}

const getLayoutElementHeight = (element: HTMLElement | null) => {
  if (!element) return 0
  const rectHeight = element.getBoundingClientRect().height
  return Math.ceil(Math.max(element.scrollHeight || 0, rectHeight || 0))
}

const getNaturalVideoGateWidth = (player: HTMLElement) => {
  const playerRect = player.getBoundingClientRect()
  const parentWidth = player.parentElement?.getBoundingClientRect().width || 0
  const mediaWidth = window.getComputedStyle(player).getPropertyValue('--rstk-media-width').trim()
  const percentMatch = mediaWidth.match(/^(\d+(?:\.\d+)?)%$/)
  if (percentMatch && parentWidth > 0) {
    return Math.max(1, parentWidth * Number(percentMatch[1]) / 100)
  }
  const pxMatch = mediaWidth.match(/^(\d+(?:\.\d+)?)px$/)
  if (pxMatch) return Math.max(1, Number(pxMatch[1]))
  return Math.max(1, playerRect.width || parentWidth || 1)
}

const sameVideoFormGateFit = (left: VideoFormGateFitState, right: VideoFormGateFitState) => (
  left.expanded === right.expanded &&
  left.wide === right.wide &&
  left.height === right.height &&
  left.width === right.width
)

const withDefaultVideoPlayerSettings = (settings: Record<string, unknown> = {}) => ({
  ...DEFAULT_VIDEO_PLAYER_SETTINGS,
  ...settings
})

const withUploadedVideoSettings = (
  settings: Record<string, unknown> = {},
  mediaUrl: string,
  asset?: MediaAsset | null
) => {
  const orientation = getVideoOrientationFromAsset(asset)
  const currentMediaWidth = Number(settings.mediaWidth)
  const shouldSetPortraitWidth = orientation === 'portrait' && (!Number.isFinite(currentMediaWidth) || currentMediaWidth >= 90)

  return {
    ...withDefaultVideoPlayerSettings(settings),
    mediaUrl,
    ...(orientation ? { videoOrientation: orientation } : {}),
    ...(shouldSetPortraitWidth ? { mediaWidth: DEFAULT_VIDEO_PORTRAIT_MEDIA_WIDTH } : {})
  }
}

const getVideoOrientationPatch = (
  settings: Record<string, unknown>,
  nextOrientation: VideoOrientation
) => {
  const currentMediaWidth = Number(settings.mediaWidth)
  const shouldSetPortraitWidth = nextOrientation === 'portrait' && (!Number.isFinite(currentMediaWidth) || currentMediaWidth >= 90)
  return {
    videoOrientation: nextOrientation,
    ...(shouldSetPortraitWidth ? { mediaWidth: DEFAULT_VIDEO_PORTRAIT_MEDIA_WIDTH } : {})
  }
}

const isPhoneCountrySelectorEnabled = (block: SiteBlock) => {
  const settings = block.settings || {}
  return settings.phoneCountrySelectorEnabled !== false &&
    settings.countrySelectorEnabled !== false &&
    settings.phoneCountrySelector !== false
}

const getSettingNumber = (settings: Record<string, unknown>, key: string, fallback: number, min: number, max: number) => {
  const value = Number(settings?.[key])
  if (!Number.isFinite(value)) return fallback
  return Math.min(max, Math.max(min, value))
}

const getThemeNumber = (theme: SiteTheme | undefined, key: keyof SiteTheme, fallback: number, min: number, max: number) => {
  const value = Number(theme?.[key])
  if (!Number.isFinite(value)) return fallback
  return Math.min(max, Math.max(min, value))
}

const getSettingHex = (settings: Record<string, unknown>, key: string, fallback: string) => {
  const value = getSettingString(settings, key)
  return isCssColor(value) ? normalizeCssColor(value, fallback) : fallback
}

const getSettingPaint = (settings: Record<string, unknown>, key: string, fallback: string) => {
  const value = getSettingString(settings, key)
  return isCssPaint(value) ? normalizeCssPaint(value, fallback) : fallback
}

const getThemePaint = (theme: SiteTheme | undefined, key: keyof SiteTheme, fallback: string) => {
  const value = theme?.[key]
  return typeof value === 'string' && isCssPaint(value) ? normalizeCssPaint(value, fallback) : fallback
}

const getThemeString = (theme: SiteTheme | undefined, key: keyof SiteTheme) => {
  const value = theme?.[key]
  return typeof value === 'string' ? value : ''
}

const getPopupTrigger = (theme?: SiteTheme | null): PopupTrigger => {
  const trigger = theme?.popupTrigger
  return trigger === 'delay' || trigger === 'exit_intent' || trigger === 'never' ? trigger : 'never'
}

const popupTriggerLabels: Record<PopupTrigger, string> = {
  never: 'Nunca',
  delay: 'Después de unos segundos',
  exit_intent: 'Cuando intenta salir'
}

const popupCloseDisplayLabels: Record<PopupCloseDisplay, string> = {
  icon: 'Solo icono',
  text: 'Solo texto',
  both: 'Icono y texto'
}

const popupCloseIconLabels: Record<PopupCloseIcon, string> = {
  x: 'X',
  arrow: 'Flechita',
  chevron: 'Chevron',
  none: 'Sin icono'
}

const normalizePopupCloseDisplay = (value?: SiteTheme['popupCloseDisplay']): PopupCloseDisplay => (
  value === 'text' || value === 'both' || value === 'icon' ? value : 'icon'
)

const normalizePopupCloseIcon = (value?: SiteTheme['popupCloseIcon']): PopupCloseIcon => (
  value === 'arrow' || value === 'chevron' || value === 'none' || value === 'x' ? value : 'x'
)

const getPopupCloseIconText = (value?: SiteTheme['popupCloseIcon']) => {
  const icon = normalizePopupCloseIcon(value)
  if (icon === 'arrow') return '←'
  if (icon === 'chevron') return '‹'
  if (icon === 'none') return ''
  return '×'
}

const hasThemePopupConfig = (theme?: SiteTheme | null) => Boolean(
  theme?.popupEnabled ||
  getPopupTrigger(theme) !== 'never' ||
  getThemeString(theme || undefined, 'popupTitle').trim() ||
  getThemeString(theme || undefined, 'popupBody').trim() ||
  getThemeString(theme || undefined, 'popupButtonText').trim() ||
  getThemeString(theme || undefined, 'popupButtonUrl').trim() ||
  getThemeString(theme || undefined, 'popupBackgroundColor').trim() ||
  getThemeString(theme || undefined, 'popupBackdropColor').trim() ||
  getThemeString(theme || undefined, 'importedPopupHtml').trim()
)

const getThemeBackgroundVideo = (theme: SiteTheme | undefined) => {
  const mediaType = getThemeString(theme, 'backgroundMediaType')
  const url = getThemeString(theme, 'backgroundImage').trim()
  if (mediaType !== 'video' || !url) return ''
  if (!/^https?:\/\//i.test(url) && !url.startsWith('/') && !/^data:video\//i.test(url)) return ''
  return url.replace(/["\\\n\r]/g, '')
}

