  type EditorDirtyScope = {
    site?: boolean
    blockIds?: string[]
  }

  type PendingEditorSaveOptions = {
    silent?: boolean
    statusOverride?: PublicSite['status']
    forceSite?: boolean
  }

  function resetPendingEditorSaveQueue() {
    pendingSiteSaveRef.current = false
    pendingCreatedBlockIdsRef.current.clear()
    pendingDeletedBlockIdsRef.current.clear()
    pendingBlockSaveIdsRef.current.clear()
    pendingBlockOrderScopesRef.current.clear()
    pendingImportedCodeDraftsRef.current.clear()
    pendingEmbeddedFormSourceDraftsRef.current.clear()
    pendingEmbeddedFormDeletedBlockIdsRef.current.clear()
  }

  function clearEditorDirtyState() {
    resetPendingEditorSaveQueue()
    setHasUnsavedChanges(false)
  }

  function getBlockOrderScopeKey(pageId?: string) {
    return pageId || BLOCK_ORDER_ALL_PAGES_KEY
  }

  function getBlockOrderPageId(scopeKey: string) {
    return scopeKey === BLOCK_ORDER_ALL_PAGES_KEY ? undefined : scopeKey
  }

  function markBlockOrderDirty(pageId?: string) {
    pendingBlockOrderScopesRef.current.add(getBlockOrderScopeKey(pageId))
  }

  function getBlocksForOrderScope(site: PublicSite, pageId?: string) {
    const sitePages = normalizeFunnelPages(site)
    const siteBlocks = site.blocks || []
    if (pageId === POPUP_SELECTED_ID) {
      return siteBlocks.filter(isPopupBlock).sort((a, b) => a.sortOrder - b.sortOrder)
    }
    if (pageId) {
      return siteBlocks
        .filter(block => {
          if (isPopupBlock(block)) return false
          const blockPageId = getBlockPageId(block, sitePages)
          return isGlobalHeaderBlock(block) || blockPageId === pageId
        })
        .sort((a, b) => a.sortOrder - b.sortOrder)
    }
    return siteBlocks.filter(block => !isPopupBlock(block)).sort((a, b) => a.sortOrder - b.sortOrder)
  }

  function applyBlockOrderLocal(site: PublicSite, orderedIds: string[], pageId?: string) {
    const orderById = new Map(orderedIds.map((id, index) => [id, index]))
    return {
      ...site,
      blocks: (site.blocks || []).map(block => (
        orderById.has(block.id) ? { ...block, sortOrder: orderById.get(block.id) || 0 } : block
      ))
    }
  }

  function createEditorLocalId() {
    if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) {
      return crypto.randomUUID()
    }

    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, char => {
      const value = Math.floor(Math.random() * 16)
      return (char === 'x' ? value : (value & 0x3) | 0x8).toString(16)
    })
  }

  function createLocalBlockFromPayload(
    site: PublicSite,
    payload: Partial<SiteBlock> & { blockType: SiteBlockType },
    sortOrder?: number,
    existingBlocks: SiteBlock[] = site.blocks || []
  ): SiteBlock {
    const uniquePayload = withUniqueBlockIdentity(payload, payload.blockType, existingBlocks)
    const now = new Date().toISOString()
    return {
      id: createEditorLocalId(),
      siteId: site.id,
      blockType: uniquePayload.blockType,
      label: uniquePayload.label || 'Nuevo bloque',
      content: uniquePayload.content || '',
      placeholder: uniquePayload.placeholder || '',
      required: Boolean(uniquePayload.required),
      options: Array.isArray(uniquePayload.options) ? uniquePayload.options : [],
      settings: { ...(uniquePayload.settings || {}) },
      sortOrder: Number.isFinite(Number(sortOrder)) ? Number(sortOrder) : (site.blocks || []).length,
      createdAt: now,
      updatedAt: now
    }
  }

  function markBlocksCreatedLocal(nextBlocks: SiteBlock[]) {
    for (const block of nextBlocks) {
      pendingCreatedBlockIdsRef.current.add(block.id)
      pendingBlockSaveIdsRef.current.add(block.id)
    }
  }

  function markBlocksDeletedLocal(blockIds: string[]) {
    for (const blockId of blockIds) {
      if (pendingCreatedBlockIdsRef.current.has(blockId)) {
        pendingCreatedBlockIdsRef.current.delete(blockId)
        pendingBlockSaveIdsRef.current.delete(blockId)
        pendingDeletedBlockIdsRef.current.delete(blockId)
        continue
      }
      pendingDeletedBlockIdsRef.current.add(blockId)
      pendingBlockSaveIdsRef.current.delete(blockId)
    }
  }

  function upsertSiteInEditorList(site: PublicSite) {
    const normalizedSite = normalizeSiteForEditor(site)
    setSites(current => {
      const exists = current.some(item => item.id === normalizedSite.id)
      if (!exists) return [normalizedSite, ...current]
      return current.map(item => item.id === normalizedSite.id ? { ...item, ...normalizedSite } : item)
    })
    return normalizedSite
  }

  function normalizeEmbeddedFormSourceBlocks(formId: string, fields: SiteBlock[]) {
    return fields.map((field, index) => ({
      ...cloneJson(field),
      siteId: formId,
      sortOrder: index,
      settings: cloneJson(field.settings || {}),
      updatedAt: new Date().toISOString()
    }))
  }

  function markEmbeddedFormSourceBlockDeleted(formId: string, blockId: string) {
    if (!formId || !blockId) return
    const deletedIds = pendingEmbeddedFormDeletedBlockIdsRef.current.get(formId) || new Set<string>()
    deletedIds.add(blockId)
    pendingEmbeddedFormDeletedBlockIdsRef.current.set(formId, deletedIds)
  }

  function syncEmbeddedFormSourceDraft(nextForm: PublicSite) {
    const normalizedForm = upsertSiteInEditorList(nextForm)
    pendingEmbeddedFormSourceDraftsRef.current.set(normalizedForm.id, normalizedForm)
    setHasUnsavedChanges(true)
    return normalizedForm
  }

  async function persistEmbeddedFormSourceDrafts() {
    const drafts = [...pendingEmbeddedFormSourceDraftsRef.current.entries()]
    for (const [formId, draftForm] of drafts) {
      const blocksForSave = normalizeEmbeddedFormSourceBlocks(formId, draftForm.blocks || [])
      const pagesForSave = normalizePagesForSave(getEmbeddedFormContentPagesFromSite(draftForm))
      let savedForm = await sitesService.updateSite(formId, {
        name: draftForm.name,
        slug: normalizeRouteInput(draftForm.slug) || normalizeRouteInput(draftForm.name) || 'formulario',
        siteType: draftForm.siteType,
        status: draftForm.status,
        title: getPublicTitleForSave(draftForm),
        description: draftForm.description,
        theme: {
          ...(draftForm.theme || {}),
          pages: pagesForSave
        },
        metaCapiEnabled: draftForm.metaCapiEnabled,
        metaEventName: draftForm.metaEventName
      })

      const deletedIds = [...(pendingEmbeddedFormDeletedBlockIdsRef.current.get(formId) || new Set<string>())]
        .filter(blockId => !blocksForSave.some(block => block.id === blockId))
      for (const blockId of deletedIds) {
        savedForm = await sitesService.deleteBlock(formId, blockId)
      }

      if (blocksForSave.length) {
        savedForm = await sitesService.restoreBlocks(formId, blocksForSave)
        savedForm = await sitesService.reorderBlocks(formId, blocksForSave.map(block => block.id))
      }

      upsertSiteInEditorList(savedForm)
    }
  }

  async function materializeDraftEmbeddedForms(siteToSave: PublicSite) {
    const siteBlocks = siteToSave.blocks || []
    if (!siteBlocks.length) return siteToSave

    let changed = false
    const nextBlocks: SiteBlock[] = []

    for (const [index, block] of siteBlocks.entries()) {
      const settings = block.settings || {}
      const hasDraftBlocks = Array.isArray(settings.embeddedBlocks)
      if (block.blockType !== 'form_embed' || getEmbeddedFormSourceId(block) || !hasDraftBlocks) {
        nextBlocks.push(block)
        continue
      }

      const draftPages = normalizeEmbeddedFormPages(settings.embeddedPages)
      const draftBlocks = getEmbeddedFormDraftBlocks(block)
      const formLabel = block.label || block.content || `Formulario ${index + 1}`
      const formName = `${siteToSave.name || 'Sitio web'} - ${formLabel}`
      let sourceForm = normalizeSiteForEditor(await sitesService.createSite({
        name: formName,
        siteType: 'standard_form',
        slug: normalizeRouteInput(`${siteToSave.slug || siteToSave.name || 'sitio'}-${formLabel}`),
        title: '',
        theme: {
          ...buildEmbeddedFormSourceTheme(siteToSave, settings, draftPages),
          blankCanvas: true
        },
        metaCapiEnabled: siteToSave.metaCapiEnabled,
        metaEventName: siteToSave.metaEventName
      }))

      const sourceBlocks = normalizeEmbeddedFormSourceBlocks(sourceForm.id, draftBlocks)
      if (sourceBlocks.length) {
        sourceForm = normalizeSiteForEditor(await sitesService.restoreBlocks(sourceForm.id, sourceBlocks))
        sourceForm = normalizeSiteForEditor(await sitesService.reorderBlocks(sourceForm.id, sourceBlocks.map(field => field.id)))
      }
      upsertSiteInEditorList(sourceForm)

      const nextBlock = {
        ...block,
        settings: stripEmbeddedFormDraftSettings(settings, sourceForm.id),
        updatedAt: new Date().toISOString()
      }
      pendingBlockSaveIdsRef.current.add(nextBlock.id)
      nextBlocks.push(nextBlock)
      changed = true
    }

    if (!changed) return siteToSave

    const nextSite = { ...siteToSave, blocks: nextBlocks }
    selectedSiteRef.current = nextSite
    setSelectedSite(nextSite)
    return nextSite
  }

  async function materializeDraftVideoFormGates(siteToSave: PublicSite) {
    const siteBlocks = siteToSave.blocks || []
    if (!siteBlocks.length) return siteToSave

    let changed = false
    const nextBlocks: SiteBlock[] = []

    for (const [index, block] of siteBlocks.entries()) {
      const settings = block.settings || {}
      const enabled = settings.videoFormGateEnabled === true
      const hasDraftBlocks = Array.isArray(settings.videoFormGateEmbeddedBlocks) || Array.isArray(settings.video_form_gate_embedded_blocks)
      const draftTheme = settings.videoFormGateEmbeddedTheme || settings.video_form_gate_embedded_theme
      const hasDraftTheme = Boolean(
        draftTheme &&
        typeof draftTheme === 'object' &&
        !Array.isArray(draftTheme)
      )

      if (block.blockType !== 'video' || !enabled || (!hasDraftBlocks && !hasDraftTheme)) {
        nextBlocks.push(block)
        continue
      }

      const draftBlocks = getVideoFormGateDraftBlocks(block)
      const sourceId = getVideoFormGateSourceId(block)
      const existingSource = sourceId ? forms.find(form => form.id === sourceId) || null : null
      if (!existingSource && !draftBlocks.length) {
        nextBlocks.push(block)
        continue
      }

      const formLabel = block.label || `Video ${index + 1}`
      const formName = existingSource?.name || `${siteToSave.name || 'Sitio web'} - Formulario de video ${formLabel}`
      let sourceForm = existingSource
        ? normalizeSiteForEditor(await sitesService.updateSite(existingSource.id, {
          name: formName,
          slug: normalizeRouteInput(existingSource.slug) || normalizeRouteInput(formName) || 'formulario-video',
          siteType: 'standard_form',
          status: existingSource.status,
          title: getPublicTitleForSave(existingSource),
          description: existingSource.description,
          theme: {
            ...(existingSource.theme || {}),
            ...buildVideoFormGateSourceTheme(siteToSave, settings),
            libraryFolderId: normalizeLibraryFolderId(existingSource.theme?.libraryFolderId) || VIDEO_FORMS_FOLDER_ID,
            librarySource: normalizeLibraryFolderId(existingSource.theme?.librarySource) || 'video_gate'
          },
          metaCapiEnabled: existingSource.metaCapiEnabled,
          metaEventName: existingSource.metaEventName
        }))
        : normalizeSiteForEditor(await sitesService.createSite({
          name: formName,
          siteType: 'standard_form',
          slug: normalizeRouteInput(`${siteToSave.slug || siteToSave.name || 'sitio'}-formulario-video-${formLabel}`),
          title: '',
          theme: {
            ...buildVideoFormGateSourceTheme(siteToSave, settings),
            blankCanvas: true
          },
          metaCapiEnabled: siteToSave.metaCapiEnabled,
          metaEventName: siteToSave.metaEventName
        }))

      if (hasDraftBlocks) {
        const sourceBlocks = normalizeVideoFormGateBlocks(draftBlocks, sourceForm.id)
        const sourceBlockIds = new Set(sourceBlocks.map(field => field.id))
        const removedFieldIds = (sourceForm.blocks || [])
          .filter(field => videoFormGateBlockTypeSet.has(field.blockType) && !sourceBlockIds.has(field.id))
          .map(field => field.id)
        for (const fieldId of removedFieldIds) {
          sourceForm = normalizeSiteForEditor(await sitesService.deleteBlock(sourceForm.id, fieldId))
        }
        if (sourceBlocks.length) {
          sourceForm = normalizeSiteForEditor(await sitesService.restoreBlocks(sourceForm.id, sourceBlocks))
          sourceForm = normalizeSiteForEditor(await sitesService.reorderBlocks(sourceForm.id, sourceBlocks.map(field => field.id)))
        }
      }
      upsertSiteInEditorList(sourceForm)

      const nextBlock = {
        ...block,
        settings: hasDraftBlocks
          ? stripVideoFormGateDraftSettings(settings, sourceForm.id)
          : { ...settings, videoFormGateFormSiteId: sourceForm.id },
        updatedAt: new Date().toISOString()
      }
      pendingBlockSaveIdsRef.current.add(nextBlock.id)
      nextBlocks.push(nextBlock)
      changed = changed || hasDraftBlocks || sourceId !== sourceForm.id
    }

    if (!changed) return siteToSave

    const nextSite = { ...siteToSave, blocks: nextBlocks }
    selectedSiteRef.current = nextSite
    setSelectedSite(nextSite)
    return nextSite
  }

  function addBlocksLocal(nextBlocks: SiteBlock[], selectBlockId?: string, orderPageId?: string) {
    const current = selectedSiteRef.current || selectedSite
    if (!current) return
    const next = {
      ...current,
      blocks: [...(current.blocks || []), ...nextBlocks]
    }
    selectedSiteRef.current = next
    setSelectedSite(next)
    markBlocksCreatedLocal(nextBlocks)
    if (orderPageId !== undefined) markBlockOrderDirty(orderPageId)
    setHasUnsavedChanges(true)
    if (selectBlockId) selectEditorBlock(selectBlockId)
  }

  async function flushPendingEditorSaves(options: PendingEditorSaveOptions = {}) {
    let siteToSave = selectedSiteRef.current || selectedSite
    if (!siteToSave || savingPendingEditorRef.current) return false

    if (options.statusOverride === 'published' && (!domainConfig.domain || !domainConfig.renderDomainVerified)) {
      showToast('error', 'Dominio requerido', 'Configura y verifica un dominio antes de publicar este sitio.')
      return false
    }

    try {
      siteToSave = await materializeDraftEmbeddedForms(siteToSave)
      siteToSave = await materializeDraftVideoFormGates(siteToSave)
    } catch (error) {
      showToast('error', 'Error', error instanceof Error ? error.message : 'No se pudo preparar el formulario')
      return false
    }
    const localBlocksById = new Map((siteToSave.blocks || []).map(block => [block.id, block]))
    const createdBlockIds = [...pendingCreatedBlockIdsRef.current].filter(blockId =>
      localBlocksById.has(blockId) && !pendingDeletedBlockIdsRef.current.has(blockId)
    )
    const deletedBlockIds = [...pendingDeletedBlockIdsRef.current].filter(blockId =>
      !pendingCreatedBlockIdsRef.current.has(blockId)
    )
    const blockIdsToSave = [...pendingBlockSaveIdsRef.current].filter(blockId =>
      localBlocksById.has(blockId) &&
      !pendingCreatedBlockIdsRef.current.has(blockId) &&
      !pendingDeletedBlockIdsRef.current.has(blockId)
    )
    const orderScopeKeys = [...pendingBlockOrderScopesRef.current]
    const importedCodeFilesToSave = [...pendingImportedCodeDraftsRef.current.entries()].map(([path, content]) => ({ path, content }))
    const embeddedFormSourceDraftsToSave = pendingEmbeddedFormSourceDraftsRef.current.size
    const shouldSaveSite = Boolean(options.forceSite || options.statusOverride || pendingSiteSaveRef.current)

    if (!shouldSaveSite && !createdBlockIds.length && !deletedBlockIds.length && !blockIdsToSave.length && !orderScopeKeys.length && !importedCodeFilesToSave.length && !embeddedFormSourceDraftsToSave) {
      clearEditorDirtyState()
      return true
    }

    savingPendingEditorRef.current = true
    setSaving(true)

    try {
      let site = siteToSave
      if (shouldSaveSite) {
        site = await sitesService.updateSite(siteToSave.id, {
          name: siteToSave.name,
          slug: normalizeRouteInput(siteToSave.slug) || normalizeRouteInput(siteToSave.name) || getDefaultRoutePrefix(siteToSave.siteType),
          siteType: siteToSave.siteType,
          status: options.statusOverride || siteToSave.status,
          title: getPublicTitleForSave(siteToSave),
          description: siteToSave.description,
          theme: siteToSave.theme,
          metaCapiEnabled: siteToSave.metaCapiEnabled,
          metaEventName: siteToSave.metaEventName
        })
      }

      for (const blockId of deletedBlockIds) {
        site = await sitesService.deleteBlock(siteToSave.id, blockId)
      }

      for (const blockId of createdBlockIds) {
        const block = localBlocksById.get(blockId)
        if (!block) continue
        site = await sitesService.createBlock(siteToSave.id, block)
      }

      for (const blockId of blockIdsToSave) {
        const block = localBlocksById.get(blockId)
        if (!block) continue
        site = await sitesService.updateBlock(siteToSave.id, block.id, block)
      }

      for (const scopeKey of orderScopeKeys) {
        const pageId = getBlockOrderPageId(scopeKey)
        const orderedIds = getBlocksForOrderScope(siteToSave, pageId).map(block => block.id)
        site = await sitesService.reorderBlocks(siteToSave.id, orderedIds, pageId)
      }

      if (importedCodeFilesToSave.length) {
        const result = await sitesService.updateImportedCodeFiles(siteToSave.id, {
          files: importedCodeFilesToSave
        })
        site = normalizeSiteForEditor(result.site)
        setSelectedImportData(result.import)
        setImportedCodeDrafts({})
      }

      if (embeddedFormSourceDraftsToSave) {
        await persistEmbeddedFormSourceDrafts()
      }

      syncSelectedSite(site)
      clearEditorDirtyState()
      setLastSavedAt(Date.now())
      if (!options.silent) {
        showToast('success', options.statusOverride === 'published' ? 'Publicado' : 'Guardado', 'Sitio actualizado')
      }
      return true
    } catch (error) {
      showToast('error', 'Error', error instanceof Error ? error.message : 'No se pudo guardar')
      return false
    } finally {
      savingPendingEditorRef.current = false
      setSaving(false)
    }
  }

  const handleConfirmLeaveEditor = useCallback((action?: () => void) => {
    allowNavigationRef.current = true
    guardHistoryArmedRef.current = false
    clearEditorDirtyState()

    action?.()

    window.setTimeout(() => {
      allowNavigationRef.current = false
    }, 500)
  }, [])

  const requestLeaveEditor = useCallback((action: () => void) => {
    if (!hasUnsavedChanges) {
      action()
      return
    }

    showConfirm(
      'Cambios sin guardar',
      'Hay cambios en el editor que todavía no se han guardado o publicado. Si sales ahora, esos ajustes se van a perder.',
      () => handleConfirmLeaveEditor(action),
      'Salir sin guardar',
      'Seguir editando',
      handleCancelLeaveEditor,
      {
        secondaryActionText: 'Salir y guardar',
        secondaryActionVariant: 'primary',
        onSecondaryAction: async () => {
          const saved = await flushPendingEditorSaves({ silent: true })
          if (saved) handleConfirmLeaveEditor(action)
          return saved
        }
      }
    )
  }, [flushPendingEditorSaves, handleCancelLeaveEditor, handleConfirmLeaveEditor, hasUnsavedChanges, showConfirm])

  const markEditorDirty = (scope: EditorDirtyScope = { site: true }) => {
    const site = selectedSiteRef.current || editorSite
    if (!site) return

    if (scope.site) pendingSiteSaveRef.current = true
    for (const blockId of scope.blockIds || []) {
      if (blockId) pendingBlockSaveIdsRef.current.add(blockId)
    }
    setHasUnsavedChanges(true)
  }

  const handleImportedCodeDraftChange = useCallback((filePath: string, content: string, originalContent: string) => {
    const key = getImportedCodeFileKey(filePath)
    const normalizedPath = getImportedCodeFilePathFromKey(key)

    setImportedCodeDrafts(current => {
      const next = { ...current }
      if (content === originalContent) {
        delete next[key]
      } else {
        next[key] = content
      }
      return next
    })

    if (content === originalContent) {
      pendingImportedCodeDraftsRef.current.delete(normalizedPath)
      return
    }

    pendingImportedCodeDraftsRef.current.set(normalizedPath, content)
    setHasUnsavedChanges(true)
  }, [])

  const markEditorSaved = useCallback(() => {
    resetPendingEditorSaveQueue()
    setImportedCodeDrafts({})
    setHasUnsavedChanges(false)
    setLastSavedAt(Date.now())
  }, [])

  useEffect(() => {
    loadSites(routeState.siteId || new URLSearchParams(window.location.search).get('siteEditor') || undefined, routeState.pageId || undefined)
    loadCalendarsForBuilder()
    loadCustomFieldsForBuilder()
  }, [])

