const hasImportedStandardAlias = (text: string, aliases: string[]) =>
  aliases.some(alias => {
    const normalized = normalizeImportedDestinationKey(alias, '')
    if (!normalized) return false
    return new RegExp(`(?:^|\\s)${normalized.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(?:\\s|$)`).test(text)
  })

const inferImportedStandardKey = (field: ImportedSiteFieldMapping) => {
  const current = normalizeImportedDestinationKey(field.destinationKey, '')
  if (importedStandardFieldOptions.some(option => option.value === current)) return current
  const type = normalizeImportedDestinationKey(field.type, '')
  const text = [
    field.type,
    field.sourceName,
    field.label
  ].map(value => normalizeImportedDestinationKey(value || '', '')).filter(Boolean).join(' ')
  if (type === 'email') return 'email'
  if (type === 'tel') return 'phone'
  if (hasImportedStandardAlias(text, importedStandardFieldAliases.email)) return 'email'
  if (hasImportedStandardAlias(text, importedStandardFieldAliases.phone)) return 'phone'
  if (hasImportedStandardAlias(text, importedStandardFieldAliases.last_name)) return 'last_name'
  if (hasImportedStandardAlias(text, importedStandardFieldAliases.first_name)) return 'first_name'
  if (hasImportedStandardAlias(text, importedStandardFieldAliases.full_name)) return 'full_name'
  if (hasImportedStandardAlias(text, importedStandardFieldAliases.message)) return 'message'
  return 'full_name'
}

const cloneImportedFormMappings = (mappings: ImportedSiteFormMapping[]) =>
  mappings.map(form => ({
    ...form,
    fields: form.fields.map(field => ({ ...field }))
  }))

const getImportedActiveCustomFields = (customFields: CustomFieldDefinition[]) =>
  customFields
    .filter(field => !field.archived && !isSystemCustomFieldDefinition(field))
    .sort((a, b) => {
      const folderCompare = (a.folderName || '').localeCompare(b.folderName || '')
      if (folderCompare !== 0) return folderCompare
      return (a.label || a.fieldKey || a.key).localeCompare(b.label || b.fieldKey || b.key)
    })

const getImportedFieldRouteType = (field: ImportedSiteFieldMapping): ImportedSiteFieldMapping['destinationType'] => {
  if (field.ignored || field.destinationType === 'ignored' || field.saveMode === 'ignored') return 'ignored'
  if (field.destinationType === 'standard' || field.saveMode === 'standard') return 'standard'
  if (field.destinationType === 'custom' || field.saveMode === 'custom' || field.destinationType === 'new_custom' || field.saveMode === 'new_custom') return 'custom'
  return 'custom'
}

const buildImportedSelectedFieldRouteContextKey = (context: ImportedSelectedFieldRouteContext | null) => (
  context
    ? [
      context.editId,
      context.fieldName,
      context.fieldHtmlId,
      context.label,
      context.placeholder,
      context.inputType,
      context.tagName
    ].join('|')
    : ''
)

const getImportedFieldRouteTokens = (context: ImportedSelectedFieldRouteContext | null) => {
  if (!context) return []
  return [
    context.editId,
    context.fieldName,
    context.fieldHtmlId,
    context.label,
    context.placeholder
  ]
    .map(value => normalizeImportedDestinationKey(value || '', ''))
    .filter(Boolean)
}

const getImportedMappingTokens = (field: ImportedSiteFieldMapping) => (
  [
    field.fieldId,
    field.sourceName,
    field.label,
    field.destinationKey,
    field.customFieldKey,
    field.customFieldLabel
  ]
    .map(value => normalizeImportedDestinationKey(value || '', ''))
    .filter(Boolean)
)

const findImportedFieldRouteMatch = (
  formMappings: ImportedSiteFormMapping[] | undefined,
  context: ImportedSelectedFieldRouteContext | null
): ImportedSelectedFieldRouteMatch | null => {
  const routeTokens = getImportedFieldRouteTokens(context)
  if (!formMappings?.length || !routeTokens.length) return null

  let bestMatch: ImportedSelectedFieldRouteMatch | null = null
  let bestScore = 0

  formMappings.forEach((form, formIndex) => {
    form.fields.forEach((field, fieldIndex) => {
      const mappingTokens = getImportedMappingTokens(field)
      if (!mappingTokens.length) return
      let score = 0
      routeTokens.forEach(token => {
        if (!token) return
        if (mappingTokens.includes(token)) {
          score += 4
          return
        }
        if (mappingTokens.some(mappingToken => mappingToken.includes(token) || token.includes(mappingToken))) {
          score += 1
        }
      })

      if (context?.inputType && field.type && normalizeImportedDestinationKey(field.type, '') === normalizeImportedDestinationKey(context.inputType, '')) {
        score += 1
      }

      if (score > bestScore) {
        bestScore = score
        bestMatch = { formIndex, fieldIndex, field }
      }
    })
  })

  return bestScore > 0 ? bestMatch : null
}

const getImportedFieldRouteDefaultKey = (context: ImportedSelectedFieldRouteContext | null) => (
  normalizeImportedDestinationKey(
    context?.fieldName || context?.fieldHtmlId || context?.label || context?.placeholder || '',
    'campo_personalizado'
  )
)

const buildImportedSelectedFieldRouteDraft = (
  match: ImportedSelectedFieldRouteMatch | null,
  context: ImportedSelectedFieldRouteContext | null
): ImportedSelectedFieldRouteDraft => {
  if (!match) {
    return {
      destinationType: 'custom',
      destinationKey: getImportedFieldRouteDefaultKey(context)
    }
  }

  const destinationType = getImportedFieldRouteType(match.field)
  return {
    destinationType,
    destinationKey: destinationType === 'standard'
      ? match.field.destinationKey || inferImportedStandardKey(match.field)
      : destinationType === 'custom'
        ? match.field.customFieldKey || match.field.destinationKey || getImportedFieldRouteDefaultKey(context)
        : match.field.destinationKey || getImportedFieldRouteDefaultKey(context),
    customFieldDefinitionId: match.field.customFieldDefinitionId || '',
    customFieldKey: match.field.customFieldKey || '',
    customFieldLabel: match.field.customFieldLabel || '',
    customFieldDataType: match.field.customFieldDataType || '',
    customFieldSyncTarget: match.field.customFieldSyncTarget || ''
  }
}

const findImportedCustomFieldDefinition = (
  customFields: CustomFieldDefinition[],
  field: ImportedSiteFieldMapping
) => {
  const definitionId = field.customFieldDefinitionId || ''
  const customKey = normalizeImportedDestinationKey(field.customFieldKey || field.destinationKey || '', '')
  return customFields.find(customField => (
    (definitionId && customField.definitionId === definitionId) ||
    (customKey && normalizeImportedDestinationKey(customField.fieldKey || customField.key, '') === customKey)
  )) || null
}

const findImportedCustomFieldDefinitionForDraft = (
  customFields: CustomFieldDefinition[],
  draft: ImportedSelectedFieldRouteDraft
) => {
  const definitionId = draft.customFieldDefinitionId || ''
  const customKey = normalizeImportedDestinationKey(draft.customFieldKey || draft.destinationKey || '', '')
  return customFields.find(customField => (
    (definitionId && customField.definitionId === definitionId) ||
    (customKey && normalizeImportedDestinationKey(customField.fieldKey || customField.key, '') === customKey)
  )) || null
}

const buildExistingImportedCustomFieldPatch = (field: CustomFieldDefinition): Partial<ImportedSiteFieldMapping> => ({
  destinationType: 'custom',
  ignored: false,
  saveMode: 'custom',
  destinationKey: field.fieldKey || field.key,
  customFieldDefinitionId: field.definitionId,
  customFieldKey: field.fieldKey || field.key,
  customFieldLabel: field.label || field.name || field.fieldKey || field.key,
  customFieldDataType: field.dataType || 'text',
  customFieldSyncTarget: field.syncTarget || 'local'
})

const clearImportedCustomFieldPatch: Partial<ImportedSiteFieldMapping> = {
  customFieldDefinitionId: '',
  customFieldKey: '',
  customFieldLabel: '',
  customFieldDataType: '',
  customFieldSyncTarget: ''
}

const ImportedHtmlReviewModal: React.FC<{
  review: ImportReviewState
  saving: boolean
  customFields: CustomFieldDefinition[]
  onClose: () => void
  onConfirm: (formMappings: ImportedSiteFormMapping[]) => void
}> = ({ review, saving, customFields, onClose, onConfirm }) => {
  const [draft, setDraft] = useState<ImportedSiteFormMapping[]>(() => cloneImportedFormMappings(review.importData.formMappings || []))
  const activeCustomFields = useMemo(() => getImportedActiveCustomFields(customFields), [customFields])

  useEffect(() => {
    setDraft(cloneImportedFormMappings(review.importData.formMappings || []))
  }, [review.importData])

  const patchField = (formIndex: number, fieldIndex: number, patch: Partial<ImportedSiteFieldMapping>) => {
    setDraft(current => current.map((form, currentFormIndex) => {
      if (currentFormIndex !== formIndex) return form
      return {
        ...form,
        fields: form.fields.map((field, currentFieldIndex) => (
          currentFieldIndex === fieldIndex ? { ...field, ...patch } : field
        ))
      }
    }))
  }

  const customRouteNeedsSelection = (field: ImportedSiteFieldMapping) => (
    getImportedFieldRouteType(field) === 'custom' &&
    !findImportedCustomFieldDefinition(activeCustomFields, field)
  )

  const hasUnresolvedCustomRoutes = draft.some(form => form.fields.some(customRouteNeedsSelection))

  const normalizeDraftForConfirm = () => draft.map(form => ({
    ...form,
    fields: form.fields.map(field => {
      if (getImportedFieldRouteType(field) !== 'custom') return field
      const selectedField = findImportedCustomFieldDefinition(activeCustomFields, field)
      if (selectedField) return { ...field, ...buildExistingImportedCustomFieldPatch(selectedField) }
      return {
        ...field,
        ...clearImportedCustomFieldPatch,
        destinationType: 'ignored' as const,
        ignored: true,
        saveMode: 'ignored'
      }
    })
  }))

  const updateDestinationType = (formIndex: number, fieldIndex: number, field: ImportedSiteFieldMapping, destinationType: ImportedSiteFieldMapping['destinationType']) => {
    if (destinationType === 'standard') {
      patchField(formIndex, fieldIndex, {
        ...clearImportedCustomFieldPatch,
        destinationType,
        ignored: false,
        saveMode: destinationType,
        destinationKey: inferImportedStandardKey(field)
      })
      return
    }

    if (destinationType === 'custom') {
      const selectedField = findImportedCustomFieldDefinition(activeCustomFields, field) || activeCustomFields[0]
      if (selectedField) {
        patchField(formIndex, fieldIndex, buildExistingImportedCustomFieldPatch(selectedField))
        return
      }
      patchField(formIndex, fieldIndex, {
        ...clearImportedCustomFieldPatch,
        destinationType: 'custom',
        ignored: false,
        saveMode: 'custom',
        destinationKey: ''
      })
      return
    }

    patchField(formIndex, fieldIndex, {
      ...clearImportedCustomFieldPatch,
      destinationType: 'ignored',
      ignored: true,
      saveMode: 'ignored',
      destinationKey: field.destinationKey
    })
  }

  return (
    <div className={styles.importReviewOverlay} role="dialog" aria-modal="true" aria-labelledby="import-review-title">
      <div className={styles.importReviewDialog}>
        <header className={styles.importReviewHeader}>
          <div>
            <span>Ruta de datos</span>
            <h2 id="import-review-title">Enruta los campos del formulario</h2>
            <p>Ristak ya lo hace automático; aquí puedes ajustar dónde se guarda cada dato de {review.importData.originalFilename || review.site.name}.</p>
          </div>
          <button type="button" className={styles.importReviewClose} onClick={onClose} aria-label="Cerrar">
            <X size={18} />
          </button>
        </header>

        {review.importData.securityReport?.length > 0 && (
          <div className={styles.importSecurityNote}>
            <AlertTriangle size={16} />
            <span>Se limpiaron partes inseguras del archivo antes de publicarlo.</span>
          </div>
        )}

        <div className={styles.importReviewForms}>
          {draft.length === 0 ? (
            <div className={styles.importEmptyFields}>
              <CheckCircle2 size={20} />
              <p>No encontramos formularios en este HTML. Puedes previsualizarlo y publicarlo como página informativa.</p>
            </div>
          ) : draft.map((form, formIndex) => (
            <section key={form.formId || formIndex} className={styles.importFormSection}>
              <div className={styles.importFormHeader}>
                <strong>{form.formTitle || `Formulario ${formIndex + 1}`}</strong>
                <span>{form.fields.length} campos detectados</span>
              </div>
              <div className={styles.importFieldList}>
                {form.fields.map((field, fieldIndex) => {
                  const destinationType = getImportedFieldRouteType(field)
                  const selectedCustomField = destinationType === 'custom'
                    ? findImportedCustomFieldDefinition(activeCustomFields, field)
                    : null
                  const selectedCustomFieldId = field.customFieldDefinitionId || selectedCustomField?.definitionId || ''
                  return (
                    <div key={`${field.fieldId}-${fieldIndex}`} className={styles.importFieldRow}>
                      <div className={styles.importFieldSource}>
                        <strong>{field.label || field.sourceName || `Campo ${fieldIndex + 1}`}</strong>
                        <span>{field.sourceName || field.fieldId}</span>
                      </div>
                      <label>
                        <span>Guardar como</span>
                        <CustomSelect
                          value={destinationType}
                          onChange={(event) => updateDestinationType(
                            formIndex,
                            fieldIndex,
                            field,
                            event.target.value as ImportedSiteFieldMapping['destinationType']
                          )}
                        >
                          <option value="standard">Dato del contacto</option>
                          <option value="custom">Campo personalizado</option>
                          <option value="ignored">No guardar</option>
                        </CustomSelect>
                      </label>
                      {destinationType === 'standard' ? (
                        <label>
                          <span>Dato</span>
                          <CustomSelect
                            value={field.destinationKey || inferImportedStandardKey(field)}
                            onChange={(event) => patchField(formIndex, fieldIndex, {
                              destinationKey: event.target.value,
                              ignored: false
                            })}
                          >
                            {importedStandardFieldOptions.map(option => (
                              <option key={option.value} value={option.value}>{option.label}</option>
                            ))}
                          </CustomSelect>
                        </label>
                      ) : destinationType === 'custom' ? (
                        <label>
                          <span>Campo personalizado</span>
                          <CustomSelect
                            value={selectedCustomFieldId}
                            onChange={(event) => {
                              if (!event.target.value) {
                                patchField(formIndex, fieldIndex, {
                                  ...clearImportedCustomFieldPatch,
                                  destinationType: 'custom',
                                  ignored: false,
                                  saveMode: 'custom',
                                  destinationKey: ''
                                })
                                return
                              }
                              const customField = activeCustomFields.find(item => item.definitionId === event.target.value)
                              if (!customField) return
                              patchField(formIndex, fieldIndex, buildExistingImportedCustomFieldPatch(customField))
                            }}
                          >
                            <option value="" disabled>
                              {activeCustomFields.length ? 'Elige un campo guardado' : 'No hay campos disponibles'}
                            </option>
                            {selectedCustomFieldId && !selectedCustomField && (
                              <option value={selectedCustomFieldId}>{field.customFieldLabel || field.destinationKey || 'Campo guardado'}</option>
                            )}
                            {activeCustomFields.map(customField => (
                              <option key={customField.definitionId} value={customField.definitionId}>
                                {customField.label || customField.name || customField.fieldKey}
                              </option>
                            ))}
                          </CustomSelect>
                        </label>
                      ) : (
                        <label>
                          <span>Dato</span>
                          <input value="No se guarda" disabled readOnly />
                        </label>
                      )}
                    </div>
                  )
                })}
              </div>
            </section>
          ))}
        </div>

        <footer className={styles.importReviewFooter}>
          <Button variant="secondary" onClick={onClose} disabled={saving}>
            Cerrar
          </Button>
          <Button onClick={() => onConfirm(normalizeDraftForConfirm())} loading={saving} disabled={hasUnresolvedCustomRoutes}>
            <Check size={15} />
            {hasUnresolvedCustomRoutes ? 'Elige campos guardados' : 'Guardar ruta de datos'}
          </Button>
        </footer>
      </div>
    </div>
  )
}

interface SitesLibraryPanelProps {
  section: SitesSection
  sites: PublicSite[]
  folders: SiteLibraryFolder[]
  viewMode: LibraryViewMode
  forms: PublicSite[]
  calendars: CalendarType[]
  selectedSiteId: string
  domainConfig: SitesDomainConfig
  onCreate: () => void
  onCreateFolder: (section: 'landings' | 'forms', name: string) => Promise<SiteLibraryFolder | null>
  onEdit: (siteId: string) => void
  onPreview: (site: PublicSite) => void
  onMoveToFolder: (site: PublicSite, folderId: string) => void
  onViewModeChange: (section: 'landings' | 'forms', viewMode: LibraryViewMode) => void
  responsesOpen: boolean
  responseRows: LeadRow[]
  responseFormId: string
  responseSite: PublicSite | null
  loadingResponses: boolean
  onOpenResponses: (site?: PublicSite) => void
  onCloseResponses: () => void
  onSelectResponsesForm: (siteId: string) => void
  onRefreshResponses: () => void
  onUpdateRoute: (site: PublicSite, slug: string) => Promise<void>
  onOpenSettings: (site: PublicSite) => void
  onDelete: (site: PublicSite) => void
}

const LibrarySitePreview: React.FC<{
  site: PublicSite
  forms: PublicSite[]
  calendars: CalendarType[]
}> = ({ site, forms, calendars }) => {
  const pages = hasEditablePages(site) ? normalizeFunnelPages(site) : []
  const activePageId = pages[0]?.id || DEFAULT_FUNNEL_PAGE_ID
  const blocks = getLibraryPreviewBlocks(site)
  const canvasTheme = buildCanvasTheme(site, 'desktop')
  const hasFields = isFormSite(site) && blocks.some(block => fieldBlockTypes.has(block.blockType))
  const isLandingPreview = isLanding(site)
  const previewDesignWidth = canvasTheme.designWidth
  const previewHeight = isLandingPreview ? 680 : 540
  const previewScale = Math.min(
    isLandingPreview ? 0.205 : 0.52,
    (isLandingPreview ? 304 : 286) / previewDesignWidth
  )
  const previewFrameStyle = {
    minHeight: previewHeight,
    ...(isLandingPreview ? {} : { padding: '20px 16px 42px' })
  } as React.CSSProperties
  const previewScalerStyle = {
    width: Math.round(previewDesignWidth * previewScale),
    height: Math.round(previewHeight * previewScale)
  } as React.CSSProperties
  const previewCanvasStyle = {
    ...canvasTheme.vars,
    width: previewDesignWidth,
    minHeight: previewHeight,
    transform: `scale(${previewScale})`,
    ['--rstk-scale' as string]: previewScale
  } as React.CSSProperties

  const renderBlockPreview = (block: SiteBlock) => (
    <div key={block.id} className={getBlockStyleClassName(block)} style={getBlockCanvasStyle(block)}>
      <BlockBackgroundVideo block={block} />
      <CanvasPreviewBlock
        block={block}
        site={site}
        blocks={blocks}
        forms={forms}
        calendars={calendars}
        pages={pages}
        activePageId={activePageId}
      />
    </div>
  )

  const renderLandingLane = (lane: LandingSectionLane) => {
    const section = lane.section

    if (!section) {
      return (
        <section key={lane.id} className="rstk-section-lane rstk-section-lane-legacy">
          <div className="rstk-section-inner">
            <div className="rstk-section-columns">
              {lane.columnBlocks.map((columnBlocks, columnIndex) => (
                <div key={`${lane.id}-${columnIndex}`} className="rstk-section-column">
                  {columnBlocks.map(renderBlockPreview)}
                </div>
              ))}
            </div>
          </div>
        </section>
      )
    }

    const settings = section.settings || {}
    const subtitle = getSettingString(settings, 'subtitle')
    const hasHeading = Boolean(section.content || subtitle)

    return (
      <section
        key={section.id}
        className={getBlockStyleClassName(section, 'rstk-section-lane')}
        style={getBlockCanvasStyle(section)}
      >
        <BlockBackgroundVideo block={section} />
        <div className="rstk-section-inner">
          {hasHeading && (
            <div className="rstk-section-heading">
              {section.content && <h2>{section.content}</h2>}
              {subtitle && <p>{subtitle}</p>}
            </div>
          )}
          <div className="rstk-section-columns">
            {lane.columnBlocks.map((columnBlocks, columnIndex) => (
              <div key={`${lane.id}-${columnIndex}`} className="rstk-section-column">
                {columnBlocks.map(renderBlockPreview)}
              </div>
            ))}
          </div>
        </div>
      </section>
    )
  }

  const renderLandingPreviewBlocks = () => {
    const lanes = buildLandingSectionLanes(blocks)
    const laneBySectionId = new Map(lanes.filter(lane => lane.section).map(lane => [lane.section!.id, lane]))
    const legacyLane = lanes.find(lane => !lane.section)
    let legacyRendered = false

    const renderedBlocks = blocks.map(block => {
      if (isPanelBlock(block)) return renderBlockPreview(block)

      if (!isSectionBlock(block)) {
        if (!legacyLane || legacyRendered || getBlockSectionId(block)) return null
        legacyRendered = true
        return renderLandingLane(legacyLane)
      }

      const lane = laneBySectionId.get(block.id)
      return lane ? renderLandingLane(lane) : null
    })

    if (legacyLane && !legacyRendered) renderedBlocks.push(renderLandingLane(legacyLane))

    return renderedBlocks
  }

  return (
    <div className={styles.libraryPreviewViewport} aria-hidden="true" inert>
      <div className={styles.libraryPreviewScaler} style={previewScalerStyle}>
        <div
          className={`rstkCanvas ${canvasTheme.bodyClass} ${styles.libraryPreviewCanvas}`}
          style={previewCanvasStyle}
        >
          <div className="rstk-frame" style={previewFrameStyle}>
            <CanvasBackgroundVideo theme={site.theme} />
            <main className="rstk-page">
              <div className="rstk-shell">
                {blocks.length ? (
                  isLandingPreview ? renderLandingPreviewBlocks() : blocks.map(renderBlockPreview)
                ) : (
                  <div className="rstkDropEmpty">
                    {isLandingPreview ? <LayoutTemplate size={22} /> : <FormInput size={22} />}
                    <p>Sin bloques todavía</p>
                  </div>
                )}
                {hasFields && (
                  <div className="rstk-actions">
                    <button type="button" data-submit><SubmitButtonContent theme={site.theme} /></button>
                  </div>
                )}
              </div>
            </main>
          </div>
        </div>
      </div>
    </div>
  )
}

const SitesLibraryPanel: React.FC<SitesLibraryPanelProps> = ({
  section,
  sites,
  folders,
  viewMode,
  forms,
  calendars,
  selectedSiteId,
  domainConfig,
  onCreate,
  onCreateFolder,
  onEdit,
  onPreview,
  onMoveToFolder,
  onViewModeChange,
  responsesOpen,
  responseRows,
  responseFormId,
  responseSite,
  loadingResponses,
  onOpenResponses,
  onCloseResponses,
  onSelectResponsesForm,
  onRefreshResponses,
  onUpdateRoute,
  onOpenSettings,
  onDelete
}) => {
  const isLandingLibrary = section === 'landings'
  const librarySection: 'landings' | 'forms' = isLandingLibrary ? 'landings' : 'forms'
  const [routeEditingId, setRouteEditingId] = useState<string | null>(null)
  const [routeDraft, setRouteDraft] = useState('')
  const [routeSavingId, setRouteSavingId] = useState<string | null>(null)
  const [activeFolderId, setActiveFolderId] = useState(SITE_LIBRARY_ROOT_ID)
  const [searchQuery, setSearchQuery] = useState('')
  const [folderDraft, setFolderDraft] = useState('')
  const [folderCreateOpen, setFolderCreateOpen] = useState(false)
  const [folderSaving, setFolderSaving] = useState(false)
  const [draggingSiteId, setDraggingSiteId] = useState('')
  const [dragOverFolderId, setDragOverFolderId] = useState('')
  const stopCardAction = (event: React.SyntheticEvent) => event.stopPropagation()
  const sectionFolders = useMemo<LibraryFolderDefinition[]>(() => {
    const customFolders = folders
      .filter(folder => folder.section === librarySection && !folder.archived)
      .map(folder => ({ ...folder, system: false }))
    const systemFolders = librarySection === 'forms' ? SYSTEM_FORM_FOLDERS : []
    return [...systemFolders, ...customFolders]
      .sort((a, b) => (a.sortOrder - b.sortOrder) || a.name.localeCompare(b.name))
  }, [folders, librarySection])
  const folderCounts = useMemo(() => {
    const counts = new Map<string, number>()
    counts.set(SITE_LIBRARY_ROOT_ID, 0)
    sectionFolders.forEach(folder => counts.set(folder.id, 0))
    sites.forEach(site => {
      const folderId = getSiteLibraryFolderId(site)
      counts.set(folderId, (counts.get(folderId) || 0) + 1)
    })
    return counts
  }, [sectionFolders, sites])
  const activeFolder = sectionFolders.find(folder => folder.id === activeFolderId) || null
  const normalizedQuery = searchQuery.trim().toLowerCase()
  const visibleSites = useMemo(() => (
    sites.filter(site => {
      const folderId = getSiteLibraryFolderId(site)
      const matchesQuery = !normalizedQuery || [
        site.name,
        getSiteTypeLabel(site),
        getPublicRouteLabel(site, domainConfig),
        getStatusLabel(site, domainConfig)
      ].some(value => value.toLowerCase().includes(normalizedQuery))
      if (!matchesQuery) return false
      return normalizedQuery ? true : folderId === activeFolderId
    })
  ), [activeFolderId, domainConfig, normalizedQuery, sites])
  const canShowFolders = activeFolderId === SITE_LIBRARY_ROOT_ID && !normalizedQuery

  useEffect(() => {
    setActiveFolderId(SITE_LIBRARY_ROOT_ID)
    setSearchQuery('')
    setFolderCreateOpen(false)
    setFolderDraft('')
  }, [librarySection])

  useEffect(() => {
    if (activeFolderId === SITE_LIBRARY_ROOT_ID) return
    if (!sectionFolders.some(folder => folder.id === activeFolderId)) {
      setActiveFolderId(SITE_LIBRARY_ROOT_ID)
    }
  }, [activeFolderId, sectionFolders])

  const startRouteEdit = (site: PublicSite) => {
    setRouteEditingId(site.id)
    setRouteDraft(getRouteEditorValue(site))
  }
  const cancelRouteEdit = () => {
    if (routeSavingId) return
    setRouteEditingId(null)
    setRouteDraft('')
  }
  const saveRouteEdit = async (site: PublicSite) => {
    const nextSlug = normalizeRouteEditorInput(routeDraft, domainConfig) || getDefaultRoutePrefix(site.siteType)
    if (nextSlug === getRouteEditorValue(site)) {
      cancelRouteEdit()
      return
    }

    setRouteSavingId(site.id)
    try {
      await onUpdateRoute(site, nextSlug)
      cancelRouteEdit()
    } catch {
      // The parent already shows the error; keep the input open so the route can be fixed.
    } finally {
      setRouteSavingId(null)
    }
  }
  const routeEditingSite = routeEditingId ? sites.find(site => site.id === routeEditingId) || null : null
  const submitFolderCreate = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    const name = folderDraft.trim()
    if (!name) return

    setFolderSaving(true)
    try {
      const folder = await onCreateFolder(librarySection, name)
      if (folder) {
        setFolderDraft('')
        setFolderCreateOpen(false)
        setActiveFolderId(folder.id)
      }
    } finally {
      setFolderSaving(false)
    }
  }
  const handleDragStart = (event: React.DragEvent<HTMLElement>, site: PublicSite) => {
    setDraggingSiteId(site.id)
    event.dataTransfer.effectAllowed = 'move'
    event.dataTransfer.setData('text/plain', site.id)
  }
  const handleDragEnd = () => {
    setDraggingSiteId('')
    setDragOverFolderId('')
  }
  const handleFolderDragOver = (event: React.DragEvent<HTMLElement>, folderId: string) => {
    if (!draggingSiteId) return
    event.preventDefault()
    event.dataTransfer.dropEffect = 'move'
    setDragOverFolderId(folderId)
  }
  const handleFolderDrop = (event: React.DragEvent<HTMLElement>, folderId: string) => {
    event.preventDefault()
    const siteId = event.dataTransfer.getData('text/plain') || draggingSiteId
    const site = sites.find(item => item.id === siteId)
    setDraggingSiteId('')
    setDragOverFolderId('')
    if (!site || getSiteLibraryFolderId(site) === folderId) return
    onMoveToFolder(site, folderId)
  }
  const renderMoveItems = (site: PublicSite) => (
    <>
      <DropdownMenuSeparator />
      <DropdownMenuItem onSelect={(event) => { event.stopPropagation(); onMoveToFolder(site, SITE_LIBRARY_ROOT_ID) }}>
        <FolderOpen size={15} />
        Sin carpeta
      </DropdownMenuItem>
      {sectionFolders.map(folder => (
        <DropdownMenuItem key={folder.id} onSelect={(event) => { event.stopPropagation(); onMoveToFolder(site, folder.id) }}>
          <Folder size={15} />
          {folder.name}
        </DropdownMenuItem>
      ))}
    </>
  )
  const renderActionsMenu = (site: PublicSite, siteKindLabel: string, buttonClassName = styles.libraryCardMenuButton) => (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button
          type="button"
          className={buttonClassName}
          aria-label={`Acciones para ${site.name}`}
          data-library-card-action="true"
          onPointerDown={(event) => event.stopPropagation()}
          onMouseDown={(event) => event.stopPropagation()}
          onMouseUp={(event) => event.stopPropagation()}
          onClick={(event) => event.stopPropagation()}
          onKeyDown={(event) => event.stopPropagation()}
        >
          <MoreVertical size={17} />
        </button>
      </DropdownMenuTrigger>
      <DropdownMenuContent
        align="end"
        sideOffset={6}
        className={styles.pageMenu}
        onPointerDown={(event) => event.stopPropagation()}
        onClick={(event) => event.stopPropagation()}
      >
        <DropdownMenuItem onSelect={(event) => { event.stopPropagation(); onEdit(site.id) }}>
          <Pencil size={15} />
          Editar {siteKindLabel}
        </DropdownMenuItem>
        <DropdownMenuItem onSelect={(event) => { event.stopPropagation(); startRouteEdit(site) }}>
          <Settings2 size={15} />
          Editar ruta
        </DropdownMenuItem>
        <DropdownMenuItem onSelect={(event) => { event.stopPropagation(); onOpenSettings(site) }}>
          <Settings2 size={15} />
          Más ajustes
        </DropdownMenuItem>
        {!isLanding(site) && (
          <DropdownMenuItem onSelect={(event) => { event.stopPropagation(); onOpenResponses(site) }}>
            <ListChecks size={15} />
            Ver respuestas
          </DropdownMenuItem>
        )}
        {renderMoveItems(site)}
        <DropdownMenuSeparator />
        <DropdownMenuItem className={styles.pageMenuDanger} onSelect={(event) => { event.stopPropagation(); onDelete(site) }}>
          <Trash2 size={15} />
          Eliminar {siteKindLabel}
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  )
  const renderSiteStatus = (site: PublicSite) => (
    <Badge variant={getStatusVariant(site, domainConfig)}>{getStatusLabel(site, domainConfig)}</Badge>
  )
  const renderGalleryCard = (site: PublicSite) => {
    const siteKindLabel = isLanding(site) ? 'sitio' : 'formulario'

    return (
      <article
        key={site.id}
        className={`${styles.libraryCard} ${selectedSiteId === site.id ? styles.libraryCardActive : ''} ${draggingSiteId === site.id ? styles.explorerItemDragging : ''}`}
        draggable
        onDragStart={(event) => handleDragStart(event, site)}
        onDragEnd={handleDragEnd}
      >
        <div className={styles.libraryCardPreview}>
          <span className={styles.libraryThumbLabel}>{getSiteTypeLabel(site)}</span>
          <span className={styles.libraryCardStatus}>{renderSiteStatus(site)}</span>
          <LibrarySitePreview site={site} forms={forms} calendars={calendars} />
          <div className={styles.libraryCardHoverActions} data-library-card-action="true">
            <button type="button" onClick={() => onEdit(site.id)}>
              <Pencil size={16} />
              <span>Editar</span>
            </button>
            <button type="button" onClick={() => onPreview(site)}>
              {isPublicSiteLive(site, domainConfig) ? <ExternalLink size={16} /> : <Eye size={16} />}
              <span>{isPublicSiteLive(site, domainConfig) ? 'Ver en vivo' : 'Previsualizar'}</span>
            </button>
            {renderActionsMenu(site, siteKindLabel)}
          </div>
        </div>

        <div className={styles.libraryCardBody}>
          <div className={styles.libraryCardTitleRow}>
            <strong>{site.name}</strong>
          </div>
          <div className={styles.libraryCardMeta}>
            <span className={styles.siteDomain}>{getPublicRouteLabel(site, domainConfig)}</span>
            {formatSiteEdited(site.updatedAt) && (
              <time dateTime={site.updatedAt || undefined}>Editado {formatSiteEdited(site.updatedAt)}</time>
            )}
          </div>
        </div>
      </article>
    )
  }
  const renderListItem = (site: PublicSite) => {
    const siteKindLabel = isLanding(site) ? 'sitio' : 'formulario'
    return (
      <article
        key={site.id}
        className={`${styles.explorerListItem} ${selectedSiteId === site.id ? styles.explorerListItemActive : ''} ${draggingSiteId === site.id ? styles.explorerItemDragging : ''}`}
        draggable
        onDragStart={(event) => handleDragStart(event, site)}
        onDragEnd={handleDragEnd}
      >
        <button type="button" className={styles.explorerListMain} onClick={() => onEdit(site.id)}>
          <span className={styles.explorerFileIcon}>{isLanding(site) ? <LayoutTemplate size={18} /> : <FormInput size={18} />}</span>
          <span>
            <strong>{site.name}</strong>
            <small>{getPublicRouteLabel(site, domainConfig)}</small>
          </span>
        </button>
        <span className={styles.explorerListType}>{getSiteTypeLabel(site)}</span>
        <span className={styles.explorerListStatus}>{renderSiteStatus(site)}</span>
        <span className={styles.explorerListDate}>{formatSiteEdited(site.updatedAt) || 'Sin cambios'}</span>
        <div className={styles.explorerListActions}>
          <button type="button" onClick={() => onPreview(site)} aria-label={`Previsualizar ${site.name}`}>
            {isPublicSiteLive(site, domainConfig) ? <ExternalLink size={16} /> : <Eye size={16} />}
          </button>
          {renderActionsMenu(site, siteKindLabel, styles.explorerActionButton)}
        </div>
      </article>
    )
  }
  const renderFolderCards = () => (
    <div className={styles.explorerFolderGrid}>
      {sectionFolders.map(folder => (
        <button
          key={folder.id}
          type="button"
          className={`${styles.explorerFolderCard} ${dragOverFolderId === folder.id ? styles.explorerFolderDropActive : ''}`}
          onClick={() => setActiveFolderId(folder.id)}
          onDragOver={(event) => handleFolderDragOver(event, folder.id)}
          onDragLeave={() => setDragOverFolderId('')}
          onDrop={(event) => handleFolderDrop(event, folder.id)}
        >
          <span className={styles.explorerFolderIcon}>
            <Folder size={20} />
          </span>
          <span className={styles.explorerFolderText}>
            <strong>{folder.name}</strong>
            <small>{folder.description || `${folderCounts.get(folder.id) || 0} elementos`}</small>
          </span>
          <span className={styles.explorerFolderCount}>{folderCounts.get(folder.id) || 0}</span>
        </button>
      ))}
    </div>
  )

  return (
    <section className={styles.libraryPanel}>
      <div className={styles.libraryHeader}>
        <div>
          <span>{isLandingLibrary ? 'Sitios web y embudos' : 'Captura de prospectos'}</span>
          <h2>{getLibraryTitle(section)}</h2>
          <p>{getLibraryDescription(section)}</p>
        </div>
        <div className={styles.libraryHeaderActions}>
          {!isLandingLibrary && (
            <Button variant="secondary" size="sm" onClick={() => onOpenResponses()} leftIcon={<ListChecks size={16} />}>
              Ver respuestas
            </Button>
          )}
          <Button variant="secondary" size="sm" onClick={() => setFolderCreateOpen(value => !value)} leftIcon={<FolderPlus size={16} />}>
            Nueva carpeta
          </Button>
          <Button size="sm" onClick={onCreate} leftIcon={<Plus size={16} />}>
            {getCreateButtonLabel(section)}
          </Button>
        </div>
      </div>

      {folderCreateOpen && (
        <form className={styles.explorerFolderCreate} onSubmit={submitFolderCreate}>
          <FolderPlus size={17} />
          <input
            value={folderDraft}
            placeholder="Nombre de la carpeta"
            disabled={folderSaving}
            autoFocus
            onChange={(event) => setFolderDraft(event.target.value)}
          />
          <Button size="sm" loading={folderSaving} disabled={!folderDraft.trim()}>
            Crear
          </Button>
          <Button type="button" variant="ghost" size="sm" disabled={folderSaving} onClick={() => { setFolderCreateOpen(false); setFolderDraft('') }}>
            Cancelar
          </Button>
        </form>
      )}

      {!isLandingLibrary && responsesOpen && (
        <FormResponsesQuickPanel
          forms={sites}
          selectedFormId={responseFormId}
          selectedSite={responseSite}
          rows={responseRows}
          loading={loadingResponses}
          onSelectForm={onSelectResponsesForm}
          onRefresh={onRefreshResponses}
          onClose={onCloseResponses}
        />
      )}

      <div className={styles.explorerToolbar}>
        <div
          className={`${styles.explorerCrumbs} ${dragOverFolderId === SITE_LIBRARY_ROOT_ID ? styles.explorerRootDropActive : ''}`}
          onDragOver={(event) => handleFolderDragOver(event, SITE_LIBRARY_ROOT_ID)}
          onDragLeave={() => setDragOverFolderId('')}
          onDrop={(event) => handleFolderDrop(event, SITE_LIBRARY_ROOT_ID)}
        >
          <button type="button" onClick={() => setActiveFolderId(SITE_LIBRARY_ROOT_ID)}>
            <FolderOpen size={16} />
            Todos
          </button>
          {activeFolder && (
            <>
              <ChevronRight size={14} />
              <span>{activeFolder.name}</span>
            </>
          )}
        </div>
        <SearchField
          className={styles.explorerSearch}
          size="sm"
          placeholder={isLandingLibrary ? 'Buscar sitios...' : 'Buscar formularios...'}
          value={searchQuery}
          onChange={setSearchQuery}
          onClear={() => setSearchQuery('')}
        />
        <div className={styles.explorerViewSwitch} aria-label="Cambiar vista">
          {([
            ['gallery', 'Galería', <Grid2X2 size={15} />],
            ['list', 'Lista', <Rows3 size={15} />],
            ['table', 'Tabla', <Table2 size={15} />]
          ] as Array<[LibraryViewMode, string, React.ReactNode]>).map(([mode, label, icon]) => (
            <button
              key={mode}
              type="button"
              aria-pressed={viewMode === mode}
              onClick={() => onViewModeChange(librarySection, mode)}
              title={label}
            >
              {icon}
              <span>{label}</span>
            </button>
          ))}
        </div>
      </div>

      {canShowFolders && sectionFolders.length > 0 && renderFolderCards()}

      {viewMode === 'gallery' ? (
        <div className={styles.libraryGrid}>
          <button type="button" className={styles.createLibraryCard} onClick={onCreate}>
            <span className={styles.createLibraryIcon}>
              <Plus size={22} />
            </span>
            <strong>{getCreateButtonLabel(section)}</strong>
            <small>
              {sites.length === 0
                ? getLibraryEmptyMessage(section)
                : isLandingLibrary
                  ? 'Agrega otra página o embudo a tu biblioteca.'
                  : 'Agrega otro formulario público a tu biblioteca.'}
            </small>
          </button>
          {visibleSites.map(renderGalleryCard)}
        </div>
      ) : viewMode === 'list' ? (
        <div className={styles.explorerList}>
          {visibleSites.map(renderListItem)}
        </div>
      ) : (
        <div className={styles.explorerSheet} data-ristak-table>
          <table data-ristak-table-element>
            <thead>
              <tr>
                <th>Nombre</th>
                <th>Tipo</th>
                <th>Estado</th>
                <th>Actualización</th>
                <th aria-label="Acciones" />
              </tr>
            </thead>
            <tbody>
              {visibleSites.map(site => {
                const siteKindLabel = isLanding(site) ? 'sitio' : 'formulario'
                return (
                  <tr
                    key={site.id}
                    draggable
                    className={draggingSiteId === site.id ? styles.explorerItemDragging : undefined}
                    onDragStart={(event) => handleDragStart(event, site)}
                    onDragEnd={handleDragEnd}
                  >
                    <td>
                      <button type="button" className={styles.explorerSheetName} onClick={() => onEdit(site.id)}>
                        <span className={styles.explorerFileIcon}>{isLanding(site) ? <LayoutTemplate size={17} /> : <FormInput size={17} />}</span>
                        <span>
                          <strong>{site.name}</strong>
                          <small>{getPublicRouteLabel(site, domainConfig)}</small>
                        </span>
                      </button>
                    </td>
                    <td>{getSiteTypeLabel(site)}</td>
                    <td>{renderSiteStatus(site)}</td>
                    <td>{formatSiteEdited(site.updatedAt) || 'Sin cambios'}</td>
                    <td>
                      <div className={styles.explorerSheetActions}>
                        <button type="button" onClick={() => onPreview(site)} aria-label={`Previsualizar ${site.name}`}>
                          {isPublicSiteLive(site, domainConfig) ? <ExternalLink size={16} /> : <Eye size={16} />}
                        </button>
                        {renderActionsMenu(site, siteKindLabel, styles.explorerActionButton)}
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      )}

      {!visibleSites.length && (
        <div className={styles.explorerEmpty}>
          <FolderOpen size={24} />
          <strong>{normalizedQuery ? 'Sin resultados' : activeFolder ? 'Carpeta vacía' : 'Sin elementos sueltos'}</strong>
          <p>{normalizedQuery ? 'Prueba con otro nombre o ruta.' : 'Crea algo nuevo o arrastra elementos a una carpeta para ordenar la biblioteca.'}</p>
        </div>
      )}

      {routeEditingSite && (
        <div className={styles.libraryRouteOverlay} data-overlay="" role="presentation" onMouseDown={(event) => {
          if (event.target === event.currentTarget) cancelRouteEdit()
        }}>
          <form
            className={styles.libraryRouteEditor}
            data-modal=""
            role="dialog"
            aria-modal="true"
            aria-labelledby="library-route-title"
            data-library-card-action="true"
            onMouseDown={stopCardAction}
            onClick={stopCardAction}
            onSubmit={(event) => {
              event.preventDefault()
              void saveRouteEdit(routeEditingSite)
            }}
          >
            <div className={styles.libraryRouteEditorHeader}>
              <div>
                <span>Ruta pública</span>
                <strong id="library-route-title">{routeEditingSite.name}</strong>
              </div>
              <button type="button" className={styles.libraryRouteClose} disabled={routeSavingId === routeEditingSite.id} onClick={cancelRouteEdit} aria-label="Cerrar editor de ruta">
                <X size={17} />
              </button>
            </div>
            <label className={styles.libraryRouteField} data-ristak-unstyled>
              <span className={styles.libraryRouteDomain} title={getPublicDomainPreview(domainConfig)}>
                {getPublicDomainPreview(domainConfig)}
              </span>
              <span className={styles.libraryRouteSlash} aria-hidden="true">/</span>
              <input
                value={routeDraft}
                aria-label={`Ruta de ${routeEditingSite.name}`}
                autoFocus
                disabled={routeSavingId === routeEditingSite.id}
                placeholder={routeEditingSite.siteType === 'landing_page' ? 'sitio-01' : 'formulario-01'}
                onFocus={(event) => event.currentTarget.select()}
                onChange={(event) => setRouteDraft(normalizeRouteEditorInput(event.target.value, domainConfig))}
                onKeyDown={(event) => {
                  if (event.key === 'Escape') {
                    event.preventDefault()
                    cancelRouteEdit()
                  }
                }}
              />
              <span className={styles.libraryRouteEditHint} aria-hidden="true">
                <Pencil size={16} />
              </span>
            </label>
            <div className={styles.libraryRouteActions}>
              <button type="button" disabled={routeSavingId === routeEditingSite.id} onClick={cancelRouteEdit}>Cancelar</button>
              <button type="submit" disabled={routeSavingId === routeEditingSite.id}>
                <Check size={16} />
                Guardar ruta
              </button>
            </div>
          </form>
        </div>
      )}
    </section>
  )
}

