const clampNumber = (value: number, min: number, max: number) =>
  Math.min(max, Math.max(min, Number.isFinite(value) ? value : min))

interface DimensionFieldProps {
  label: string
  value: number
  min: number
  max: number
  step?: number
  unit?: string
  onChange: (value: number) => void
  onCommit: () => void
}

// Numeric box only: spacing/size edits should feel exact, not like a fader.
const DimensionField: React.FC<DimensionFieldProps> = ({ label, value, min, max, step = 1, unit = 'px', onChange, onCommit }) => {
  const set = (raw: number) => onChange(clampNumber(raw, min, max))
  return (
    <label className={styles.dimensionField}>
      <span>{label}</span>
      <div className={styles.dimensionTextRow}>
        <div className={styles.dimensionBox} data-ristak-unstyled>
          <NumberInput
            min={min}
            max={max}
            step={step}
            value={value}
            onValueChange={set}
            onBlur={onCommit}
          />
          <small>{unit}</small>
        </div>
      </div>
    </label>
  )
}

const VideoDimensionSliderField: React.FC<DimensionFieldProps> = ({ label, value, min, max, step = 1, unit = 'px', onChange, onCommit }) => {
  const set = (raw: number) => onChange(clampNumber(raw, min, max))
  const commitFromKey = (event: React.KeyboardEvent<HTMLInputElement>) => {
    if (['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown', 'Home', 'End', 'PageUp', 'PageDown'].includes(event.key)) {
      window.setTimeout(onCommit, 0)
    }
  }

  return (
    <label className={`${styles.dimensionField} ${styles.videoDimensionField}`}>
      <span>{label}</span>
      <div className={styles.videoDimensionRow}>
        <input
          className={styles.videoDimensionSlider}
          type="range"
          min={min}
          max={max}
          step={step}
          value={value}
          onChange={(event) => set(Number(event.target.value))}
          onPointerUp={onCommit}
          onTouchEnd={onCommit}
          onKeyUp={commitFromKey}
          onBlur={onCommit}
          aria-label={label}
        />
        <div className={styles.dimensionBox} data-ristak-unstyled>
          <NumberInput
            min={min}
            max={max}
            step={step}
            value={value}
            onValueChange={set}
            onBlur={onCommit}
          />
          <small>{unit}</small>
        </div>
      </div>
    </label>
  )
}

