const VideoPreviewRangeControl: React.FC<{
  settings: Record<string, unknown>
  durationSeconds: number
  onPatchSettings: (patch: Record<string, unknown>) => void
  onSave: () => void
}> = ({ settings, durationSeconds, onPatchSettings, onSave }) => {
  const trackRef = useRef<HTMLDivElement | null>(null)
  const dragStateRef = useRef<{ startX: number; start: number; end: number; width: number } | null>(null)
  const range = normalizeVideoPreviewRange(settings, durationSeconds)
  const startPercent = range.max > 0 ? (range.start / range.max) * 100 : 0
  const endPercent = range.max > 0 ? (range.end / range.max) * 100 : 100

  const patchRange = useCallback((nextStart: number, nextEnd: number, commit = false) => {
    const normalized = normalizeVideoPreviewRange({
      ...settings,
      videoPreviewStart: nextStart,
      videoPreviewEnd: nextEnd
    }, durationSeconds)

    onPatchSettings({
      videoPreviewStart: normalized.start,
      videoPreviewEnd: normalized.end
    })
    if (commit) window.setTimeout(onSave, 0)
  }, [durationSeconds, onPatchSettings, onSave, settings])

  const handleStartChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const requestedStart = Math.min(
      Math.max(0, Number(event.target.value)),
      Math.max(0, range.max - range.minSpan)
    )
    const currentSpan = Math.min(range.maxSpan, Math.max(range.minSpan, range.end - range.start))
    const nextEnd = requestedStart > range.end - range.minSpan
      ? Math.min(range.max, requestedStart + currentSpan)
      : range.end
    patchRange(requestedStart, nextEnd)
  }

  const handleEndChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const nextEnd = Math.min(
      Math.max(Number(event.target.value), range.start + range.minSpan),
      range.start + range.maxSpan
    )
    patchRange(range.start, nextEnd)
  }

  const handleSelectionPointerDown = (event: React.PointerEvent<HTMLDivElement>) => {
    if (range.end <= range.start) return
    const track = trackRef.current
    if (!track) return
    const rect = track.getBoundingClientRect()
    dragStateRef.current = {
      startX: event.clientX,
      start: range.start,
      end: range.end,
      width: rect.width || 1
    }
    event.currentTarget.setPointerCapture(event.pointerId)
  }

  const handleSelectionPointerMove = (event: React.PointerEvent<HTMLDivElement>) => {
    const dragState = dragStateRef.current
    if (!dragState) return
    const deltaSeconds = ((event.clientX - dragState.startX) / dragState.width) * range.max
    const span = dragState.end - dragState.start
    const nextStart = Math.min(Math.max(0, dragState.start + deltaSeconds), Math.max(0, range.max - span))
    patchRange(nextStart, nextStart + span)
  }

  const handleSelectionPointerUp = (event: React.PointerEvent<HTMLDivElement>) => {
    if (!dragStateRef.current) return
    dragStateRef.current = null
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId)
    }
    window.setTimeout(onSave, 0)
  }

  return (
    <div className={styles.videoPreviewRange}>
      <div className={styles.videoPreviewRangeHeader}>
        <span>Loop del preview</span>
        <strong>{formatVideoPreviewSecond(range.start)} - {formatVideoPreviewSecond(range.end)}</strong>
      </div>
      <div
        ref={trackRef}
        className={styles.videoPreviewTrack}
        style={{
          ['--video-preview-start' as string]: `${startPercent}%`,
          ['--video-preview-end' as string]: `${endPercent}%`
        } as React.CSSProperties}
      >
        <div className={styles.videoPreviewTrackBase} aria-hidden="true" />
        <div
          className={styles.videoPreviewSelection}
          onPointerDown={handleSelectionPointerDown}
          onPointerMove={handleSelectionPointerMove}
          onPointerUp={handleSelectionPointerUp}
          onPointerCancel={handleSelectionPointerUp}
          aria-hidden="true"
        />
        <input
          className={styles.videoPreviewThumb}
          type="range"
          min={0}
          max={range.max}
          step={VIDEO_PREVIEW_STEP_SECONDS}
          value={range.start}
          aria-label="Inicio del loop"
          onChange={handleStartChange}
          onMouseUp={onSave}
          onTouchEnd={onSave}
        />
        <input
          className={styles.videoPreviewThumb}
          type="range"
          min={0}
          max={range.max}
          step={VIDEO_PREVIEW_STEP_SECONDS}
          value={range.end}
          aria-label="Fin del loop"
          onChange={handleEndChange}
          onMouseUp={onSave}
          onTouchEnd={onSave}
        />
      </div>
      <div className={styles.videoPreviewRangeFooter}>
        <span>0:00</span>
        <span>Max {formatVideoPreviewSecond(range.max)}</span>
      </div>
    </div>
  )
}

const VideoSettingsElementPreview: React.FC<{
  settings: Record<string, unknown>
  type: 'bar' | 'play' | 'sound'
}> = ({ settings, type }) => {
  const playShape = getVideoPlayShape(settings)
  const playIconStyle = getVideoPlayIconStyle(settings)
  const playerColor = getSettingString(settings, 'videoPlayerColor') || DEFAULT_VIDEO_PLAYER_COLOR
  const playColor = getSettingString(settings, 'videoPlayColor') || DEFAULT_VIDEO_PLAY_COLOR
  const playSizeValue = getVideoPlaySizeValue(settings)
  const playWidthValue = playShape === 'rectangle' ? Math.round(playSizeValue * 1.45) : playSizeValue
  const playIconSizeValue = getVideoPlayIconSizeValue(settings)
  const playPreviewScale = Math.min(1, 150 / Math.max(1, playWidthValue), 86 / Math.max(1, playSizeValue))
  const playRadius = `${getVideoPlayRadiusValue(settings, playShape)}px`
  const soundColor = getSettingString(settings, 'videoSoundColor') || playColor
  const showControlPlay = shouldShowVideoControlPlay(settings)
  const showControlVolume = settings.videoControlVolume !== false
  const showControlSpeed = settings.videoControlSpeed !== false
  const showControlSettings = shouldShowVideoControlSettings(settings)
  const showControlTime = shouldShowVideoControlTime(settings)
  const controlPanelRadius = `${getVideoControlPanelRadiusValue(settings)}px`

  return (
    <div
      className={styles.videoElementPreview}
      style={{
        ['--video-settings-play-bg' as string]: playerColor,
        ['--video-settings-play-color' as string]: playColor,
        ['--video-settings-play-preview-width' as string]: `${Math.max(1, Math.round(playWidthValue * playPreviewScale))}px`,
        ['--video-settings-play-preview-size' as string]: `${Math.max(1, Math.round(playSizeValue * playPreviewScale))}px`,
        ['--video-settings-play-radius' as string]: playRadius,
        ['--video-settings-play-icon-size' as string]: `${Math.max(1, Math.round(playIconSizeValue * playPreviewScale))}px`,
        ['--video-settings-control-radius' as string]: controlPanelRadius,
        ['--video-settings-sound-color' as string]: soundColor
      } as React.CSSProperties}
    >
      {type === 'bar' && (
        <span className={styles.videoElementBarSample}>
          {showControlPlay && <span className={styles.videoElementBarPlay}><Play size={11} fill="currentColor" /></span>}
          <i />
          {showControlTime && <em>0:12 / -2:18</em>}
          {showControlVolume && <span className={styles.videoElementBarVolume}><Volume2 size={12} /></span>}
          {showControlSpeed && (
            <span className={styles.videoElementBarSpeed}>
              {showControlSettings && <Settings2 size={11} />}
              <small>1x</small>
            </span>
          )}
        </span>
      )}
      {type === 'play' && (
        <span className={`${styles.videoElementPlaySample} ${playShape === 'round' ? styles.videoElementPlayRound : ''}`}>
          <VideoPlayGlyph iconStyle={playIconStyle} size={playIconSizeValue} />
        </span>
      )}
      {type === 'sound' && (
        <span className={styles.videoElementSoundSample}>
          <span className={styles.videoElementSoundIcon}>
            <Volume2 size={16} />
          </span>
          <small>{getVideoSoundNoticeText(settings)}</small>
        </span>
      )}
    </div>
  )
}

const VideoPlayerSettingsControls: React.FC<{
  settings: Record<string, unknown>
  mediaUrl?: string
  sections?: 'all' | 'playback' | 'chrome'
  onPatchSettings: (patch: Record<string, unknown>) => void
  onSave: () => void
}> = ({ settings, mediaUrl = '', sections = 'all', onPatchSettings, onSave }) => {
  const controlsMode = getVideoControlsMode(settings)
  const showCustomControls = controlsMode === 'clean'
  const showPlaybackSections = sections === 'all' || sections === 'playback'
  const showChromeSections = sections === 'all' || sections === 'chrome'
  const showCustomControlBar = shouldShowVideoControlBar(settings)
  const playShape = getVideoPlayShape(settings)
  const soundNoticeHideAfter = getVideoSoundNoticeHideAfter(settings)
  const trickProgressEnabled = settings.videoTrickProgressEnabled === true
  const [metadataDuration, setMetadataDuration] = useState(0)
  const metadataSource = mediaUrl || getSettingString(settings, 'mediaUrl')
  const metadataPreviewEnabled = settings.videoPreviewEnabled !== false

  useEffect(() => {
    const source = safePublicMediaUrl(metadataSource, 'video')
    if (!source || !metadataPreviewEnabled) {
      setMetadataDuration(0)
      return
    }

    let cancelled = false
    const probe = document.createElement('video')
    probe.preload = 'metadata'
    probe.src = appendEditorNoTrackParam(source)
    probe.onloadedmetadata = () => {
      if (!cancelled) setMetadataDuration(Number.isFinite(probe.duration) ? probe.duration : 0)
    }
    probe.onerror = () => {
      if (!cancelled) setMetadataDuration(0)
    }

    return () => {
      cancelled = true
      probe.removeAttribute('src')
      probe.load()
    }
  }, [metadataPreviewEnabled, metadataSource])

  if (sections === 'chrome' && !showCustomControls) return null

  return (
    <div className={styles.videoSettingsBox}>
      {showPlaybackSections && (
        <>
          <section className={styles.videoSettingsSection}>
            <div className={styles.videoSettingsSectionHeader}>
              <span>Video</span>
              <strong>Marco y ajuste</strong>
            </div>
            <label className={styles.field}>
              <span>Estilo del reproductor</span>
              <CustomSelect
                value={controlsMode}
                onChange={(event) => {
                  const nextMode = isVideoControlsMode(event.target.value) ? event.target.value : DEFAULT_VIDEO_CONTROLS_MODE
                  onPatchSettings({
                    videoControlsMode: nextMode,
                    videoControls: nextMode === 'native'
                  })
                }}
                onBlur={onSave}
              >
                {videoControlsModeOptions.map(option => (
                  <option key={option.value} value={option.value}>{option.label}</option>
                ))}
              </CustomSelect>
            </label>
            <div className={styles.twoColumn}>
              <label className={styles.field}>
                <span>Formato</span>
                <CustomSelect
                  value={getVideoOrientation(settings)}
                  onChange={(event) => {
                    const nextOrientation = isVideoOrientation(event.target.value) ? event.target.value : DEFAULT_VIDEO_ORIENTATION
                    onPatchSettings(getVideoOrientationPatch(settings, nextOrientation))
                  }}
                  onBlur={onSave}
                >
                  {videoOrientationOptions.map(option => (
                    <option key={option.value} value={option.value}>{option.label}</option>
                  ))}
                </CustomSelect>
              </label>
              <label className={styles.field}>
                <span>Ajuste</span>
                <CustomSelect value={getSettingString(settings, 'videoFit') || 'cover'} onChange={(event) => onPatchSettings({ videoFit: event.target.value })} onBlur={onSave}>
                  <option value="cover">Cubrir espacio</option>
                  <option value="contain">Mostrar completo</option>
                  <option value="fill">Estirar</option>
                </CustomSelect>
              </label>
            </div>
            <div className={styles.twoColumn}>
              <ColorField label="Fondo del video" value={getSettingString(settings, 'videoPlayerBackground') || DEFAULT_VIDEO_PLAYER_BACKGROUND} allowGradient={false} onChange={(value) => onPatchSettings({ videoPlayerBackground: value })} onCommit={onSave} />
              <ColorField
                label="Borde del video"
                value={getSettingString(settings, 'videoPlayerBorderColor') || DEFAULT_VIDEO_TRANSPARENT}
                allowGradient={false}
                onChange={(value) => {
                  const patch: Record<string, unknown> = { videoPlayerBorderColor: value }
                  if (!isTransparentCssColorValue(value) && getSettingNumber(settings, 'videoPlayerBorderWidth', 0, 0, 12) === 0) {
                    patch.videoPlayerBorderWidth = 1
                  }
                  onPatchSettings(patch)
                }}
                onCommit={onSave}
              />
            </div>
            <div className={styles.twoColumn}>
              <VideoDimensionSliderField
                label="Radio del video"
                value={getSettingNumber(settings, 'videoPlayerRadius', 18, 0, 80)}
                min={0}
                max={80}
                onChange={(value) => onPatchSettings({ videoPlayerRadius: value })}
                onCommit={onSave}
              />
              <VideoDimensionSliderField
                label="Borde del video"
                value={getSettingNumber(settings, 'videoPlayerBorderWidth', 0, 0, 12)}
                min={0}
                max={12}
                onChange={(value) => onPatchSettings({ videoPlayerBorderWidth: value })}
                onCommit={onSave}
              />
            </div>
          </section>

          <section className={styles.videoSettingsSection}>
            <div className={styles.videoSettingsSectionHeader}>
              <span>Reproducción</span>
              <strong>Inicio y preview</strong>
            </div>
            <div className={styles.twoColumn}>
              <label className={styles.field}>
                <span>Velocidad inicial</span>
                <CustomSelect
                  value={String(getSettingNumber(settings, 'videoDefaultSpeed', 1, 0.25, 4))}
                  onChange={(event) => onPatchSettings({ videoDefaultSpeed: Number(event.target.value) })}
                  onBlur={onSave}
                >
                  {videoSpeedOptions.map(option => <option key={option.value} value={option.value}>{option.label}</option>)}
                </CustomSelect>
              </label>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={Boolean(settings.videoAutoplay)}
                  onChange={(event) => {
                    onPatchSettings({ videoAutoplay: event.target.checked, videoMuted: event.target.checked ? true : settings.videoMuted })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Autoplay</span>
              </label>
            </div>
            <div className={styles.twoColumn}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={settings.videoPreviewEnabled !== false}
                  onChange={(event) => {
                    onPatchSettings({ videoPreviewEnabled: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Preview de primeros segundos</span>
              </label>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={settings.videoMuted !== false}
                  onChange={(event) => {
                    onPatchSettings({ videoMuted: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Iniciar silenciado</span>
              </label>
            </div>

            {settings.videoPreviewEnabled !== false && (
              <VideoPreviewRangeControl
                settings={settings}
                durationSeconds={metadataDuration}
                onPatchSettings={onPatchSettings}
                onSave={onSave}
              />
            )}

            <div className={styles.twoColumn}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={Boolean(settings.videoLoop)}
                  onChange={(event) => {
                    onPatchSettings({ videoLoop: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Repetir video</span>
              </label>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={settings.videoDisableEditorPlayback === true}
                  onChange={(event) => {
                    onPatchSettings({ videoDisableEditorPlayback: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>No reproducir mientras se edita</span>
              </label>
            </div>
          </section>

        </>
      )}

      {showChromeSections && showCustomControls && (
        <>
          <section className={styles.videoSettingsSection}>
            <div className={styles.videoSettingsSectionHeader}>
              <span>Barra</span>
              <strong>Controles inferiores</strong>
            </div>
            <VideoSettingsElementPreview settings={settings} type="bar" />
            <div className={styles.twoColumn}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={showCustomControlBar}
                  onChange={(event) => {
                    onPatchSettings({ videoControlBar: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Barra del reproductor</span>
              </label>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={shouldShowVideoControlBarInitially(settings)}
                  disabled={!showCustomControlBar}
                  onChange={(event) => {
                    onPatchSettings({ videoControlBarInitiallyVisible: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Mostrar al reproducir</span>
              </label>
            </div>
            <div className={styles.twoColumn}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={shouldShowVideoControlPlay(settings)}
                  disabled={!showCustomControlBar}
                  onChange={(event) => {
                    onPatchSettings({ videoControlPlay: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Botón play</span>
              </label>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={settings.videoControlVolume !== false}
                  disabled={!showCustomControlBar}
                  onChange={(event) => {
                    onPatchSettings({ videoControlVolume: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Volumen</span>
              </label>
            </div>
            <div className={styles.twoColumn}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={settings.videoControlSpeed !== false}
                  disabled={!showCustomControlBar}
                  onChange={(event) => {
                    onPatchSettings({ videoControlSpeed: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Velocidad</span>
              </label>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={shouldShowVideoControlSettings(settings)}
                  disabled={!showCustomControlBar || settings.videoControlSpeed === false}
                  onChange={(event) => {
                    onPatchSettings({ videoControlSettings: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Configuración</span>
              </label>
            </div>
            <div className={styles.twoColumn}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={shouldShowVideoControlTime(settings)}
                  disabled={!showCustomControlBar}
                  onChange={(event) => {
                    onPatchSettings({ videoControlTime: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Marcador de tiempo</span>
              </label>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={trickProgressEnabled}
                  disabled={!showCustomControlBar}
                  onChange={(event) => {
                    onPatchSettings({ videoTrickProgressEnabled: event.target.checked })
                    window.setTimeout(onSave, 0)
                  }}
                />
                <span>Reproductor truqueado</span>
              </label>
            </div>
            {trickProgressEnabled && (
              <div className={styles.videoTrickProgressBox}>
                <div className={styles.videoTrickProgressHeader}>
                  <span>Avance visual</span>
                  <strong>{getVideoTrickProgressRampPercent(settings)}% real a {getVideoTrickProgressPeakPercent(settings)}% visible</strong>
                </div>
                <p>
                  La barra corre rápido al inicio y desde ese punto se frena para volver al progreso natural.
                </p>
                <VideoDimensionSliderField
                  label="Volver a normal en"
                  value={getVideoTrickProgressRampPercent(settings)}
                  min={VIDEO_TRICK_PROGRESS_RAMP_MIN}
                  max={VIDEO_TRICK_PROGRESS_RAMP_MAX}
                  unit="%"
                  onChange={(value) => onPatchSettings({ videoTrickProgressRampPercent: value })}
                  onCommit={onSave}
                />
                <VideoDimensionSliderField
                  label="Marcador aparente"
                  value={getVideoTrickProgressPeakPercent(settings)}
                  min={VIDEO_TRICK_PROGRESS_PEAK_MIN}
                  max={VIDEO_TRICK_PROGRESS_PEAK_MAX}
                  unit="%"
                  onChange={(value) => onPatchSettings({ videoTrickProgressPeakPercent: value })}
                  onCommit={onSave}
                />
              </div>
            )}
            <VideoDimensionSliderField
              label="Radio del panel"
              value={getVideoControlPanelRadiusValue(settings)}
              min={0}
              max={VIDEO_CONTROL_PANEL_RADIUS_MAX}
              onChange={(value) => onPatchSettings({ videoControlPanelRadius: value })}
              onCommit={onSave}
            />
          </section>

          <section className={styles.videoSettingsSection}>
            <div className={styles.videoSettingsSectionHeader}>
              <span>Botón play</span>
              <strong>Forma, color y tamaño</strong>
            </div>
            <VideoSettingsElementPreview settings={settings} type="play" />
            <label className={styles.field}>
              <span>Tipo de play</span>
              <CustomSelect
                value={getVideoPlayIconStyle(settings)}
                onChange={(event) => {
                  const nextStyle = isVideoPlayIconStyle(event.target.value) ? event.target.value : DEFAULT_VIDEO_PLAY_ICON_STYLE
                  onPatchSettings({ videoPlayIconStyle: nextStyle })
                }}
                onBlur={onSave}
              >
                {videoPlayIconOptions.map(option => (
                  <option key={option.value} value={option.value}>{option.label}</option>
                ))}
              </CustomSelect>
            </label>
            {playShape === 'rectangle' ? (
              <div className={styles.twoColumn}>
                <label className={styles.field}>
                  <span>Forma del play</span>
                  <CustomSelect
                    value={playShape}
                    onChange={(event) => {
                      const nextShape = isVideoPlayShape(event.target.value) ? event.target.value : DEFAULT_VIDEO_PLAY_SHAPE
                      onPatchSettings({
                        videoPlayShape: nextShape,
                        videoPlayRadius: nextShape === 'rectangle' ? DEFAULT_VIDEO_PLAY_RADIUS : LEGACY_VIDEO_PLAY_RADIUS
                      })
                    }}
                    onBlur={onSave}
                  >
                    {videoPlayShapeOptions.map(option => (
                      <option key={option.value} value={option.value}>{option.label}</option>
                    ))}
                  </CustomSelect>
                </label>
                <VideoDimensionSliderField
                  label="Radio del player"
                  value={getVideoPlayRadiusValue(settings, playShape)}
                  min={0}
                  max={LEGACY_VIDEO_PLAY_RADIUS}
                  onChange={(value) => onPatchSettings({ videoPlayRadius: value, videoPlayShape: playShape })}
                  onCommit={onSave}
                />
              </div>
            ) : (
              <label className={styles.field}>
                <span>Forma del play</span>
                <CustomSelect
                  value={playShape}
                  onChange={(event) => {
                    const nextShape = isVideoPlayShape(event.target.value) ? event.target.value : DEFAULT_VIDEO_PLAY_SHAPE
                    onPatchSettings({
                      videoPlayShape: nextShape,
                      videoPlayRadius: nextShape === 'rectangle' ? DEFAULT_VIDEO_PLAY_RADIUS : LEGACY_VIDEO_PLAY_RADIUS
                    })
                  }}
                  onBlur={onSave}
                >
                  {videoPlayShapeOptions.map(option => (
                    <option key={option.value} value={option.value}>{option.label}</option>
                  ))}
                </CustomSelect>
              </label>
            )}
            <div className={styles.twoColumn}>
              <ColorField label="Fondo del player" value={getSettingString(settings, 'videoPlayerColor') || DEFAULT_VIDEO_PLAYER_COLOR} allowGradient={false} onChange={(value) => onPatchSettings({ videoPlayerColor: value })} onCommit={onSave} />
              <ColorField label="Ícono play" value={getSettingString(settings, 'videoPlayColor') || DEFAULT_VIDEO_PLAY_COLOR} allowGradient={false} onChange={(value) => onPatchSettings({ videoPlayColor: value })} onCommit={onSave} />
            </div>
            <div className={styles.twoColumn}>
              <VideoDimensionSliderField
                label="Tamaño del play"
                value={getVideoPlaySizeValue(settings)}
                min={VIDEO_PLAY_SIZE_MIN}
                max={VIDEO_PLAY_SIZE_MAX}
                onChange={(value) => onPatchSettings({ videoPlaySize: value, videoPlayShape: getVideoPlayShape(settings) })}
                onCommit={onSave}
              />
              <VideoDimensionSliderField
                label="Ícono play"
                value={getVideoPlayIconSizeValue(settings)}
                min={VIDEO_PLAY_ICON_SIZE_MIN}
                max={VIDEO_PLAY_ICON_SIZE_MAX}
                onChange={(value) => onPatchSettings({ videoPlayIconSize: value, videoPlayShape: getVideoPlayShape(settings) })}
                onCommit={onSave}
              />
            </div>
          </section>

          <section className={styles.videoSettingsSection}>
            <div className={styles.videoSettingsSectionHeader}>
              <span>Bocina</span>
              <strong>Aviso de sonido</strong>
            </div>
            <VideoSettingsElementPreview settings={settings} type="sound" />
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={settings.videoSoundHint !== false}
                onChange={(event) => {
                  onPatchSettings({ videoSoundHint: event.target.checked })
                  window.setTimeout(onSave, 0)
                }}
              />
              <span>Mostrar bocina animada</span>
            </label>
            {settings.videoSoundHint !== false && (
              <>
                <ColorField label="Color de bocina" value={getSettingString(settings, 'videoSoundColor') || DEFAULT_VIDEO_PLAY_COLOR} allowGradient={false} onChange={(value) => onPatchSettings({ videoSoundColor: value })} onCommit={onSave} />
                <div className={styles.twoColumn}>
                  <label className={styles.field}>
                    <span>Texto bocina (opcional)</span>
                    <input
                      value={getVideoSoundNoticeText(settings)}
                      placeholder={DEFAULT_VIDEO_SOUND_NOTICE_TEXT}
                      onChange={(event) => onPatchSettings({ videoSoundNoticeText: event.target.value })}
                      onBlur={onSave}
                    />
                  </label>
                  <label className={styles.field}>
                    <span>Ocultar bocina</span>
                    <CustomSelect
                      value={String(soundNoticeHideAfter)}
                      onChange={(event) => onPatchSettings({ videoSoundNoticeHideAfter: Number(event.target.value) })}
                      onBlur={onSave}
                    >
                      {videoSoundNoticeDurationOptions.map(option => (
                        <option key={option.value} value={option.value}>{option.label}</option>
                      ))}
                    </CustomSelect>
                  </label>
                </div>
              </>
            )}
          </section>
        </>
      )}
    </div>
  )
}

const CanvasBackgroundVideo: React.FC<{ theme?: SiteTheme }> = ({ theme }) => {
  const src = getThemeBackgroundVideo(theme)
  if (!src) return null

  return (
    <video className="rstk-bg-video" src={src} autoPlay muted loop playsInline aria-hidden="true" />
  )
}

const BlockBackgroundVideo: React.FC<{ block: SiteBlock }> = ({ block }) => {
  const settings = block.settings || {}
  if (getSettingString(settings, 'blockBackgroundMediaType') !== 'video') return null
  const src = safePublicMediaUrl(getSettingString(settings, 'blockBackgroundImage'), 'video')
  if (!src) return null
  return <video className="rstk-block-bg-video" src={src} autoPlay muted loop playsInline aria-hidden="true" />
}

