const hasBlockExtraSettingsContent = (block: SiteBlock) => (
  isPanelBlock(block) ||
  block.blockType === SECTION_BLOCK_TYPE ||
  [
    'hero',
    'cta',
    'button',
    'social_profile',
    'image',
    'video',
    'countdown',
    'calendar_embed',
    'form_embed'
  ].includes(block.blockType)
)

const PageInspector: React.FC<{
  site: PublicSite
  pages: SitePage[]
  activePageId: string
  metaPixelConnected: boolean
  onPatchSite: (patch: Partial<PublicSite>) => void
  onPatchTheme: (patch: Partial<SiteTheme>) => void
  onSaveSite: () => void
}> = ({ site, pages, activePageId, metaPixelConnected, onPatchSite, onPatchTheme, onSaveSite }) => {
  const [formMetaParamsOpen, setFormMetaParamsOpen] = useState(false)
  const theme = site.theme || {}
  const formEventName = normalizeMetaEventName(site.metaEventName, 'none')
  const formHasConversion = formEventName !== 'none'
  const formHasParameters = hasMetaEventParameters(theme.metaEventParameters)

  useEffect(() => {
    if (!site.metaCapiEnabled || !formHasConversion) {
      setFormMetaParamsOpen(false)
    }
  }, [formHasConversion, site.metaCapiEnabled])

  const pageConfigContent = (
    <>
      <ActivePageSettings site={site} pages={pages} activePageId={activePageId} onPatchTheme={onPatchTheme} onSaveSite={onSaveSite} />
      {metaPixelConnected && isFormSite(site) && (
        <div className={styles.settingsGroup}>
          <div className={styles.panelSubheader}>Conversión del formulario</div>
          <div className={`${styles.metaCard} ${formHasConversion && site.metaCapiEnabled ? styles.metaCardActive : ''}`}>
            <span className={styles.metaMark} aria-hidden="true">∞</span>
            <div className={styles.metaCardInfo}>
              <strong>{formHasConversion ? 'Evento de submit' : 'Sin evento'}</strong>
              <small>{!site.metaCapiEnabled ? 'Requiere Meta del sitio' : formHasConversion ? 'Se envía al enviar formulario' : 'Solo PageView global'}</small>
            </div>
          </div>
          <label className={styles.field}>
            <span>Evento de submit</span>
            <CustomSelect
              value={formEventName}
              disabled={!site.metaCapiEnabled}
              onChange={(event) => {
                const metaEventName = event.target.value
                onPatchSite({ metaEventName })
                onPatchTheme({
                  metaEventParameters: pruneMetaEventParametersForEvent(theme.metaEventParameters, metaEventName)
                })
              }}
              onBlur={onSaveSite}
            >
              {metaEventOptions.map(option => (
                <option key={option.value} value={option.value}>{option.label}</option>
              ))}
            </CustomSelect>
          </label>
          {formHasConversion && (
            <div className={styles.metaParametersInspector}>
              <button
                type="button"
                className={[
                  styles.metaParametersInspectorToggle,
                  formMetaParamsOpen ? styles.metaParametersInspectorToggleActive : '',
                  formHasParameters ? styles.metaParametersInspectorToggleFilled : ''
                ].filter(Boolean).join(' ')}
                disabled={!site.metaCapiEnabled}
                aria-expanded={formMetaParamsOpen}
                onClick={() => setFormMetaParamsOpen(open => !open)}
              >
                <Settings2 size={14} />
                <span>Parámetros Meta</span>
                <ChevronDown size={13} />
              </button>
              {formMetaParamsOpen && (
                <MetaEventParametersEditor
                  eventName={formEventName}
                  parameters={theme.metaEventParameters}
                  disabled={!site.metaCapiEnabled}
                  onChange={(metaEventParameters) => onPatchTheme({ metaEventParameters })}
                  onCommit={onSaveSite}
                />
              )}
            </div>
          )}
          {isStandardForm(site) && (
            <>
              <label className={styles.field}>
                <span>Al enviar formulario</span>
                <CustomSelect
                  value={getThemeFormCompletionAction(theme)}
                  onChange={(event) => onPatchTheme({ formCompletionAction: event.target.value as FormCompletionAction })}
                  onBlur={onSaveSite}
                >
                  <option value="next_page_if_qualified">Mostrar Agradecimiento o Descalificacion segun resultado</option>
                  <option value="redirect_qualified">Redirigir calificados a una URL</option>
                  <option value="next_page">Siempre mostrar página Agradecimiento</option>
                  <option value="form_default">Mostrar mensaje en este formulario</option>
                </CustomSelect>
              </label>
              {getThemeFormCompletionAction(theme) === 'redirect_qualified' && (
                <label className={styles.field}>
                  <span>URL para calificados</span>
                  <input
                    type="url"
                    value={theme.formQualifiedRedirectUrl || ''}
                    placeholder="https://tudominio.com/gracias"
                    onChange={(event) => onPatchTheme({ formQualifiedRedirectUrl: event.target.value })}
                    onBlur={onSaveSite}
                  />
                </label>
              )}
              <label className={styles.field}>
                <span>Mensaje si califica</span>
                <textarea
                  rows={2}
                  value={theme.finalMessages?.success || ''}
                  placeholder="Listo. Recibimos tu información."
                  onChange={(event) => onPatchTheme({ finalMessages: { ...(theme.finalMessages || {}), success: event.target.value } })}
                  onBlur={onSaveSite}
                />
              </label>
              <label className={styles.field}>
                <span>Mensaje si no califica</span>
                <textarea
                  rows={2}
                  value={theme.finalMessages?.disqualified || ''}
                  placeholder="Gracias por responder. Por ahora no parece ser el siguiente paso ideal."
                  onChange={(event) => onPatchTheme({ finalMessages: { ...(theme.finalMessages || {}), disqualified: event.target.value } })}
                  onBlur={onSaveSite}
                />
              </label>
            </>
          )}
        </div>
      )}
    </>
  )

  const pageDesignContent = (
    <div className={styles.settingsGroup}>
      <div className={styles.panelSubheader}>Colores</div>
      <div className={styles.twoColumn}>
        <ColorField
          label="Fondo de página"
          value={getThemePaint(theme, 'backgroundColor', userBgColor(site) || resolvedPageBg(site))}
          allowGradient
          onChange={(value) => onPatchTheme({ backgroundColor: value })}
          onCommit={onSaveSite}
        />
        <ColorField
          label="Texto de página"
          value={getThemePaint(theme, 'textColor', isSiteDark(site) ? '#ffffff' : '#111827')}
          allowGradient
          onChange={(value) => onPatchTheme({ textColor: value, textColorCustom: true })}
          onCommit={onSaveSite}
        />
      </div>
      <ColorField
        label="Acento"
        value={getThemePaint(theme, 'accentColor', userAccentColor(site) || (isSiteDark(site) ? '#ffffff' : '#111827'))}
        allowGradient
        onChange={(value) => onPatchTheme({ accentColor: value })}
        onCommit={onSaveSite}
      />
      <div className={styles.twoColumn}>
        <label className={styles.field}>
          <span>Tipo</span>
          <CustomSelect
            value={getThemeString(theme, 'backgroundMediaType') || 'image'}
            onChange={(event) => onPatchTheme({ backgroundMediaType: event.target.value as SiteTheme['backgroundMediaType'] })}
            onBlur={onSaveSite}
          >
            {backgroundMediaTypeOptions.map(option => (
              <option key={option.value} value={option.value}>{option.label}</option>
            ))}
          </CustomSelect>
        </label>
        <label className={styles.field}>
          <span>Visualización</span>
          <CustomSelect
            value={getBackgroundVisualValue(theme)}
            onChange={(event) => onPatchTheme(backgroundVisualPatch(event.target.value))}
            onBlur={onSaveSite}
          >
            {backgroundVisualOptions.map(option => (
              <option key={option.value} value={option.value}>{option.label}</option>
            ))}
          </CustomSelect>
        </label>
      </div>
      <MediaUploadControl
        kind={theme.backgroundMediaType === 'video' ? 'video' : 'image'}
        label={theme.backgroundMediaType === 'video' ? 'Elegir video de fondo' : 'Elegir imagen de fondo'}
        moduleEntityId={site.id}
        currentUrl={getThemeString(theme, 'backgroundImage')}
        onUploaded={(url) => onPatchTheme({
          backgroundImage: url,
          backgroundMediaType: theme.backgroundMediaType === 'video' ? 'video' : 'image'
        })}
        onCommit={onSaveSite}
      />
      <label className={styles.field}>
        <span>URL de fondo</span>
        <input
          value={getThemeString(theme, 'backgroundImage')}
          placeholder={theme.backgroundMediaType === 'video' ? 'https://.../video.mp4' : 'https://...'}
          onChange={(event) => onPatchTheme({ backgroundImage: event.target.value })}
          onBlur={onSaveSite}
        />
      </label>

      <div className={styles.panelSubheader}>Dimensiones</div>
      <DimensionField
        label="Ancho máximo"
        value={isLanding(site) && Number(theme.pageMaxWidth) === 1160 ? 1440 : getThemeNumber(theme, 'pageMaxWidth', isLanding(site) ? 1440 : 520, 360, 1440)}
        min={360}
        max={1440}
        step={10}
        onChange={(value) => onPatchTheme({ pageMaxWidth: value })}
        onCommit={onSaveSite}
      />
      <div className={styles.twoColumn}>
        <DimensionField
          label="Relleno de página"
          value={getThemeNumber(theme, 'pagePadding', isLanding(site) ? LANDING_DEFAULT_PAGE_PADDING : 22, 0, 120)}
          min={0}
          max={120}
          onChange={(value) => onPatchTheme({ pagePadding: value })}
          onCommit={onSaveSite}
        />
        <DimensionField
          label="Radio"
          value={getThemeNumber(theme, 'pageRadius', isLanding(site) ? 0 : 24, 0, 40)}
          min={0}
          max={40}
          onChange={(value) => onPatchTheme({ pageRadius: value })}
          onCommit={onSaveSite}
        />
      </div>
      <div className={styles.panelSubheader}>Borde de página</div>
      <div className={styles.twoColumn}>
        <DimensionField
          label="Grosor"
          value={getThemeNumber(theme, 'pageBorderWidth', 0, 0, 12)}
          min={0}
          max={12}
          onChange={(value) => onPatchTheme({ pageBorderWidth: value })}
          onCommit={onSaveSite}
        />
        <ColorField
          label="Color"
          value={getThemePaint(theme, 'pageBorderColor', '#dbe3ef')}
          allowGradient
          onChange={(value) => onPatchTheme({ pageBorderColor: value })}
          onCommit={onSaveSite}
        />
      </div>
    </div>
  )

  const pageGlobalContent = (
    <>
      <SiteGlobalSettings site={site} onPatchSite={onPatchSite} onSaveSite={onSaveSite} />
      {isFormSite(site) && (
        <FormGlobalStyleControls site={site} onPatchTheme={onPatchTheme} onSaveSite={onSaveSite} />
      )}
    </>
  )

  return (
    <InspectorTabbedPanel
      title="Página"
      subtitle={isLanding(site) ? (site.theme?.pageMode === 'website' ? 'Sitio web' : 'Embudo') : 'Formulario'}
      tabs={[
        { value: 'edit', label: 'Editar', icon: <Pencil size={14} />, content: pageConfigContent },
        { value: 'design', label: 'Diseño', icon: <Sparkles size={14} />, content: pageDesignContent },
        { value: 'settings', label: 'Global', icon: <Globe2 size={14} />, content: pageGlobalContent }
      ]}
    />
  )
}

type CustomFieldQuickDraft = {
  label: string
  fieldKey: string
  dataType: CustomFieldDataType
  folderId: string
  optionsText: string
}

const customFieldEditorTypes: Array<{ value: CustomFieldDataType; label: string; detail: string }> = [
  { value: 'text', label: 'Texto corto', detail: 'Una línea de texto.' },
  { value: 'textarea', label: 'Párrafo', detail: 'Texto largo o notas.' },
  { value: 'radio', label: 'Radio buttons', detail: 'Una opción visible.' },
  { value: 'dropdown', label: 'Dropdown', detail: 'Una opción en lista.' },
  { value: 'checkboxes', label: 'Checkboxes', detail: 'Varias opciones.' },
  { value: 'number', label: 'Número', detail: 'Solo cantidad numérica.' },
  { value: 'currency', label: 'Moneda', detail: 'Importe de dinero.' },
  { value: 'date', label: 'Fecha', detail: 'Día o fecha.' },
  { value: 'email', label: 'Email', detail: 'Correo electrónico.' },
  { value: 'phone', label: 'Teléfono', detail: 'Número de contacto.' }
]

const customFieldChoiceTypes = new Set<CustomFieldDataType>(['radio', 'dropdown', 'checkboxes', 'select', 'multiselect'])

const normalizeCustomFieldKey = (value: string) => {
  const normalized = value
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '')

  return normalized || 'campo_personalizado'
}

const customFieldOptionsFromText = (value: string): CustomFieldOption[] => (
  value
    .split('\n')
    .map(line => line.trim())
    .filter(Boolean)
    .map(line => ({ label: line, value: normalizeCustomFieldKey(line) }))
)

const customFieldTokenPreview = (fieldKey: string) => `{{custom.${fieldKey || 'campo_personalizado'}}}`

const getCustomFieldFolderName = (folders: CustomFieldFolder[], folderId: string) => (
  folders.find(folder => folder.id === folderId)?.name || 'Sin carpeta'
)

const customFieldDataTypeForBlock = (blockType: SiteBlockType): CustomFieldDataType => {
  if (blockType === 'paragraph') return 'textarea'
  if (blockType === 'radio') return 'radio'
  if (blockType === 'dropdown') return 'dropdown'
  if (blockType === 'checkboxes') return 'checkboxes'
  if (blockType === 'number') return 'number'
  if (blockType === 'currency') return 'currency'
  if (blockType === 'date') return 'date'
  if (blockType === 'email') return 'email'
  if (blockType === 'phone') return 'phone'
  return 'text'
}

const makeCustomFieldDraftForBlock = (block: SiteBlock): CustomFieldQuickDraft => {
  const label = block.label || 'Campo personalizado'
  const dataType = customFieldDataTypeForBlock(block.blockType)
  const optionsText = isChoiceBlock(block.blockType)
    ? getOptions(block).map(option => option.label || option.value).filter(Boolean).join('\n')
    : ''

  return {
    label,
    fieldKey: normalizeCustomFieldKey(label),
    dataType,
    folderId: '',
    optionsText
  }
}

const buildCustomFieldPayload = (
  draft: CustomFieldQuickDraft,
  folders: CustomFieldFolder[],
  notify: (title: string, message: string) => void
): SaveCustomFieldInput | null => {
  const label = draft.label.trim()
  const fieldKey = normalizeCustomFieldKey(draft.fieldKey || label)
  const options = customFieldChoiceTypes.has(draft.dataType)
    ? customFieldOptionsFromText(draft.optionsText)
    : []

  if (!label) {
    notify('Falta nombre', 'Ponle un nombre al campo.')
    return null
  }

  if (!fieldKey) {
    notify('Falta parámetro', 'El parámetro sirve para guardar y usar el dato del contacto.')
    return null
  }

  if (customFieldChoiceTypes.has(draft.dataType) && options.length === 0) {
    notify('Faltan opciones', 'Agrega al menos una opción para este tipo de campo.')
    return null
  }

  return {
    label,
    fieldKey,
    dataType: draft.dataType,
    folderId: draft.folderId || undefined,
    fieldGroup: draft.folderId ? getCustomFieldFolderName(folders, draft.folderId) : 'general',
    options,
    syncTarget: 'local'
  }
}

const normalizeCustomFieldDataType = (value = '') => {
  if (value === 'select') return 'dropdown'
  if (value === 'multiselect') return 'checkboxes'
  return value
}

const customFieldTypeLabel = (value = '') => {
  const type = normalizeCustomFieldDataType(value)
  if (type === 'text') return 'Texto corto'
  if (type === 'textarea') return 'Párrafo'
  if (type === 'radio') return 'Opción única'
  if (type === 'dropdown') return 'Lista desplegable'
  if (type === 'checkboxes') return 'Varias opciones'
  if (type === 'number') return 'Número'
  if (type === 'currency') return 'Moneda'
  if (type === 'date') return 'Fecha'
  if (type === 'email') return 'Correo'
  if (type === 'phone') return 'Teléfono'
  return value || 'Campo'
}

const CustomFieldBindingControl: React.FC<{
  block: SiteBlock
  customFields: CustomFieldDefinition[]
  customFieldFolders: CustomFieldFolder[]
  onPatchSettings: (patch: Record<string, unknown>) => void
  onCustomFieldCreated: (field: CustomFieldDefinition) => void
  onSave: () => void
}> = ({ block, customFields, customFieldFolders, onPatchSettings, onCustomFieldCreated, onSave }) => {
  const { showToast } = useNotification()
  const settings = block.settings || {}
  const [creatorOpen, setCreatorOpen] = useState(false)
  const [creatorSaving, setCreatorSaving] = useState(false)
  const [creatorDraft, setCreatorDraft] = useState<CustomFieldQuickDraft>(() => makeCustomFieldDraftForBlock(block))
  const systemPreset = getSystemFormFieldPresetForBlock(block)

  useEffect(() => {
    if (!creatorOpen) setCreatorDraft(makeCustomFieldDraftForBlock(block))
  }, [block, creatorOpen])

  const openCreator = () => {
    setCreatorDraft(makeCustomFieldDraftForBlock(block))
    setCreatorOpen(true)
  }

  const closeCreator = () => {
    if (creatorSaving) return
    setCreatorOpen(false)
  }

  const patchCreatorDraft = (patch: Partial<CustomFieldQuickDraft>) => {
    setCreatorDraft(current => ({ ...current, ...patch }))
  }

  const handleCreatorLabelChange = (value: string) => {
    setCreatorDraft(current => ({
      ...current,
      label: value,
      fieldKey: normalizeCustomFieldKey(value)
    }))
  }

  const handleCreateField = async () => {
    const payload = buildCustomFieldPayload(creatorDraft, customFieldFolders, (title, message) => {
      showToast('warning', title, message)
    })
    if (!payload) return

    setCreatorSaving(true)
    try {
      const field = await customFieldsService.createField(payload)
      onCustomFieldCreated(field)
      onPatchSettings({
        customFieldDefinitionId: field.definitionId,
        customFieldKey: field.fieldKey || field.key,
        customFieldLabel: field.label,
        customFieldDataType: field.dataType
      })
      setCreatorOpen(false)
      showToast('success', 'Campo creado', 'Ya quedó ligado a esta pregunta.')
      window.setTimeout(onSave, 0)
    } catch (error) {
      showToast('error', 'No se pudo guardar', error instanceof Error ? error.message : 'Intenta otra vez')
    } finally {
      setCreatorSaving(false)
    }
  }

  if (systemPreset) {
    return (
      <div className={styles.customFieldBinding}>
        <div className={styles.panelSubheader}>Guardado de respuesta</div>
        <div className={styles.systemFieldLock}>
          <span><Lock size={14} /></span>
          <div>
            <strong>{systemPreset.destinationLabel}</strong>
            <p>Este campo es del sistema y se guarda automaticamente al enviar el formulario.</p>
          </div>
        </div>
      </div>
    )
  }

  const currentDefinitionId = getSettingString(settings, 'customFieldDefinitionId')
  const availableFields = customFields
    .filter(field => !field.archived && !isSystemCustomFieldDefinition(field))
    .sort((a, b) => (
      String(a.folderName || '').localeCompare(String(b.folderName || '')) ||
      String(a.label || '').localeCompare(String(b.label || ''))
    ))
  const selectedField = availableFields.find(field => field.definitionId === currentDefinitionId) ||
    customFields.find(field => field.definitionId === currentDefinitionId && !isSystemCustomFieldDefinition(field))
  const groups = availableFields.reduce((acc, field) => {
    const folderName = field.folderName || 'Sin carpeta'
    const current = acc.get(folderName) || []
    current.push(field)
    acc.set(folderName, current)
    return acc
  }, new Map<string, CustomFieldDefinition[]>())

  return (
    <div className={styles.customFieldBinding}>
      <div className={styles.panelSubheader}>Guardado de respuesta</div>
      <label className={styles.field}>
        <span>Guardar respuesta en</span>
        <CustomSelect
          value={currentDefinitionId}
          onChange={(event) => {
            const definitionId = event.target.value
            const field = availableFields.find(item => item.definitionId === definitionId)

            if (!field) {
              onPatchSettings({
                customFieldDefinitionId: '',
                customFieldKey: '',
                customFieldLabel: '',
                customFieldDataType: ''
              })
              window.setTimeout(onSave, 0)
              return
            }

            onPatchSettings({
              customFieldDefinitionId: field.definitionId,
              customFieldKey: field.fieldKey || field.key,
              customFieldLabel: field.label,
              customFieldDataType: field.dataType
            })
            window.setTimeout(onSave, 0)
          }}
          onBlur={onSave}
        >
          <option value="">No guardar en campo personalizado</option>
          {[...groups.entries()].map(([folderName, groupFields]) => (
            <optgroup key={folderName} label={folderName}>
              {groupFields.map(field => (
                <option key={field.definitionId} value={field.definitionId}>
                  {field.label} - {field.fieldKey || field.key}
                </option>
              ))}
            </optgroup>
          ))}
        </CustomSelect>
      </label>
      <div className={styles.customFieldCreateAction}>
        <Button type="button" variant="secondary" size="sm" leftIcon={<Plus size={14} />} onClick={openCreator}>
          Crear campo personalizado
        </Button>
      </div>
      {selectedField ? (
        <p className={styles.customFieldHint}>
          Se guardara como <code>{selectedField.fieldKey || selectedField.key}</code> ({customFieldTypeLabel(selectedField.dataType)}).
        </p>
      ) : (
        <p className={styles.customFieldHint}>
          {availableFields.length
            ? 'Selecciona un campo personalizado para guardar este dato dentro del contacto.'
            : 'No hay campos personalizados todavía. Crea uno para guardar este dato.'}
        </p>
      )}
      {creatorOpen && (
        <div className={customFieldModalStyles.editorOverlay} role="dialog" aria-modal="true" aria-labelledby="sites-custom-field-editor-title">
          <section className={customFieldModalStyles.editorPanel}>
            <div className={customFieldModalStyles.editorHeader}>
              <div>
                <p className={customFieldModalStyles.eyebrow}>Nuevo campo</p>
                <h3 id="sites-custom-field-editor-title">Crear campo personalizado</h3>
              </div>
              <button type="button" className={customFieldModalStyles.iconButton} onClick={closeCreator} aria-label="Cerrar editor">
                <X size={18} />
              </button>
            </div>

            <div className={customFieldModalStyles.editorBody}>
              <label className={customFieldModalStyles.field}>
                <span>Nombre visible</span>
                <input value={creatorDraft.label} placeholder="Ej. Presupuesto mensual" onChange={(event) => handleCreatorLabelChange(event.target.value)} />
                <small className={customFieldModalStyles.parameterPreview}>Parámetro: <code>{customFieldTokenPreview(creatorDraft.fieldKey || normalizeCustomFieldKey(creatorDraft.label))}</code></small>
              </label>

              <label className={customFieldModalStyles.field}>
                <span>Tipo</span>
                <CustomSelect
                  portal
                  value={creatorDraft.dataType}
                  onChange={(event) => patchCreatorDraft({ dataType: event.target.value as CustomFieldDataType })}
                >
                  {customFieldEditorTypes.map(type => (
                    <option key={type.value} value={type.value}>{type.label}</option>
                  ))}
                </CustomSelect>
              </label>

              <div className={customFieldModalStyles.typeHint}>
                <ChevronRight size={15} />
                <span>{customFieldEditorTypes.find(type => type.value === creatorDraft.dataType)?.detail}</span>
              </div>

              <label className={customFieldModalStyles.field}>
                <span>Carpeta</span>
                <CustomSelect portal value={creatorDraft.folderId} onChange={(event) => patchCreatorDraft({ folderId: event.target.value })}>
                  <option value="">Sin carpeta</option>
                  {customFieldFolders.map(folder => (
                    <option key={folder.id} value={folder.id}>{folder.name}</option>
                  ))}
                </CustomSelect>
              </label>

              {customFieldChoiceTypes.has(creatorDraft.dataType) && (
                <label className={customFieldModalStyles.field}>
                  <span>Opciones</span>
                  <textarea
                    rows={5}
                    value={creatorDraft.optionsText}
                    placeholder={'Opción 1\nOpción 2\nOpción 3'}
                    onChange={(event) => patchCreatorDraft({ optionsText: event.target.value })}
                  />
                  <small>Una opción por línea.</small>
                </label>
              )}
            </div>

            <div className={customFieldModalStyles.editorActions}>
              <Button type="button" variant="ghost" onClick={closeCreator}>
                Cancelar
              </Button>
              <Button type="button" onClick={() => void handleCreateField()} loading={creatorSaving} leftIcon={<Save size={16} />}>
                Guardar campo
              </Button>
            </div>
          </section>
        </div>
      )}
    </div>
  )
}

const VideoActionTimeScale: React.FC<{
  timeSeconds: number
  maxSeconds: number
  onChangeTime: (timeSeconds: number) => void
}> = ({ timeSeconds, maxSeconds, onChangeTime }) => {
  const labelSteps = [0, 0.25, 0.5, 0.75, 1].map(step => Math.round(maxSeconds * step))
  const left = `${Math.min(100, Math.max(0, (timeSeconds / maxSeconds) * 100))}%`

  return (
    <div className={styles.videoActionTimeline} aria-label="Linea de tiempo de la accion">
      <div className={styles.videoActionTimelineLabels} aria-hidden="true">
        {labelSteps.map((seconds, index) => (
          <span key={`${seconds}-${index}`}>{formatVideoActionTime(seconds)}</span>
        ))}
      </div>
      <div className={styles.videoActionTimelineTrack}>
        <span className={styles.videoActionTimelineLine} aria-hidden="true" />
        <input
          className={styles.videoActionMarkerInput}
          type="range"
          min={0}
          max={maxSeconds}
          step={1}
          value={Math.min(timeSeconds, maxSeconds)}
          aria-label="Mover momento de la accion"
          data-active="true"
          onChange={(event) => onChangeTime(clampVideoActionTime(event.target.value))}
        />
        <span
          className={styles.videoActionTimelineMarkerLabel}
          data-active="true"
          style={{ ['--video-action-marker-left' as string]: left } as React.CSSProperties}
        >
          {formatVideoActionTime(timeSeconds)}
        </span>
      </div>
    </div>
  )
}

const VideoActionsPanel: React.FC<{
  site: PublicSite
  block: SiteBlock
  blocks: SiteBlock[]
  popupBlocks: SiteBlock[]
  pages: SitePage[]
  activePageId: string
  importedPopupDetected: boolean
  forms?: PublicSite[]
  customFields?: CustomFieldDefinition[]
  customFieldFolders?: CustomFieldFolder[]
  onCustomFieldCreated?: (field: CustomFieldDefinition) => void
  enableVideoFormGateAction?: boolean
  metaPixelConnected: boolean
  onPatchSite: (patch: Partial<PublicSite>) => void
  onSaveSite?: () => void | Promise<void>
  onPatchSettings: (patch: Record<string, unknown>) => void
  onSave: () => void
  onTargetHover?: (blockId: string) => void
  onVideoFormGatePreviewChange?: (blockId: string) => void
  videoFormGateActiveBlockId?: string
  videoFormGateActiveElement?: EmbeddedFormActiveElement
  onVideoFormGateActiveBlockChange?: (blockId: string) => void
  onVideoFormGateSubmitSelect?: () => void
}> = ({
  site,
  block,
  blocks,
  popupBlocks,
  pages,
  activePageId,
  importedPopupDetected,
  forms = [],
  customFields = [],
  customFieldFolders = [],
  onCustomFieldCreated = () => undefined,
  enableVideoFormGateAction = false,
  metaPixelConnected,
  onPatchSite,
  onSaveSite,
  onPatchSettings,
  onSave,
  onTargetHover,
  onVideoFormGatePreviewChange,
  videoFormGateActiveBlockId,
  videoFormGateActiveElement,
  onVideoFormGateActiveBlockChange,
  onVideoFormGateSubmitSelect
}) => {
  const settings = block.settings || {}
  const allRules = useMemo(() => getVideoActionRules(settings), [settings])
  const rules = useMemo(
    () => allRules.filter(rule => (
      (enableVideoFormGateAction || rule.action !== 'open_video_form') &&
      (metaPixelConnected || rule.action !== 'meta_event')
    )),
    [allRules, enableVideoFormGateAction, metaPixelConnected]
  )
  const targets = useMemo(
    () => buildVideoActionTargetOptions(site, blocks, popupBlocks, block.id, importedPopupDetected),
    [site, blocks, popupBlocks, block.id, importedPopupDetected]
  )
  const contentTargets = useMemo(() => targets.filter(target => target.id !== POPUP_SURFACE_ID), [targets])
  const formTargets = useMemo(
    () => contentTargets.filter(target => target.blockType === 'form_embed' || (target.blockType && fieldBlockTypes.has(target.blockType as SiteBlockType))),
    [contentTargets]
  )
  const sectionTargets = useMemo(
    () => contentTargets.filter(target => target.blockType === SECTION_BLOCK_TYPE),
    [contentTargets]
  )
  const pageTargets = useMemo(() => getManualRedirectPages(pages, activePageId), [pages, activePageId])
  const hasPopupTarget = targets.some(target => target.id === POPUP_SURFACE_ID)
  const availablePrimaryVideoActionKinds = useMemo(
    () => primaryVideoActionKinds.filter(action => (
      (enableVideoFormGateAction || action !== 'open_video_form') &&
      (metaPixelConnected || action !== 'meta_event')
    )),
    [enableVideoFormGateAction, metaPixelConnected]
  )
  const [expandedRuleId, setExpandedRuleId] = useState('')
  const [timeInputs, setTimeInputs] = useState<Record<string, string>>({})
  const [videoDurationSeconds, setVideoDurationSeconds] = useState(0)
  const timelineMaxSeconds = useMemo(() => getVideoActionTimelineMax(rules, videoDurationSeconds), [rules, videoDurationSeconds])
  const openVideoFormRuleExpanded = rules.some(rule => rule.id === expandedRuleId && rule.action === 'open_video_form')

  const buildVideoFormGateSettingsPatch = useCallback((nextRules: VideoActionRule[]) => {
    if (!enableVideoFormGateAction) return {}
    const currentSettings = block.settings || {}
    const gateRule = nextRules.find(rule => rule.action === 'open_video_form') || null
    if (!gateRule) {
      return currentSettings.videoFormGateEnabled === true ? { videoFormGateEnabled: false } : {}
    }

    const selectedFormId = getVideoFormGateSourceId(block)
    const selectedQuestions = getEditableVideoFormGateBlocks(block, forms)
    const initialQuestions = selectedQuestions.length ? selectedQuestions : createVideoFormGateBlocks(site.id)
    const hasDraftQuestions = Array.isArray(currentSettings.videoFormGateEmbeddedBlocks)
      && (currentSettings.videoFormGateEmbeddedBlocks as unknown[]).length > 0
    const completionAction = getVideoFormGateCompletionAction(currentSettings)
    const nextSettingsForTheme = { ...currentSettings, completionAction }
    const patch: Record<string, unknown> = {
      videoFormGateEnabled: true,
      videoFormGateTriggerSeconds: gateRule.timeSeconds,
      videoFormGateTitle: getSettingString(currentSettings, 'videoFormGateTitle') || VIDEO_FORM_GATE_DEFAULT_TITLE,
      videoFormGateDescription: getSettingString(currentSettings, 'videoFormGateDescription') || VIDEO_FORM_GATE_DEFAULT_DESCRIPTION,
      videoFormGateNextText: getSettingString(currentSettings, 'videoFormGateNextText') || VIDEO_FORM_GATE_DEFAULT_NEXT_TEXT,
      videoFormGateBackText: getSettingString(currentSettings, 'videoFormGateBackText') || VIDEO_FORM_GATE_DEFAULT_BACK_TEXT,
      videoFormGateSubmitText: getSettingString(currentSettings, 'videoFormGateSubmitText') || VIDEO_FORM_GATE_DEFAULT_SUBMIT_TEXT,
      videoFormGateAnimation: getVideoFormGateAnimation(currentSettings),
      videoFormGateVideoBackground: getVideoFormGateVideoBackground(currentSettings),
      videoFormGateCompletionAction: getVideoFormGateFinalAction(currentSettings),
      videoFormGateRepeatMode: getVideoFormGateRepeatMode(currentSettings),
      videoFormGateStorageValue: getVideoFormGateStorageValue(currentSettings),
      videoFormGateStorageUnit: getVideoFormGateStorageUnit(currentSettings),
      completionAction
    }

    if (!hasDraftQuestions) {
      patch.videoFormGateEmbeddedBlocks = normalizeVideoFormGateBlocks(initialQuestions, selectedFormId || site.id)
    }
    if (!currentSettings.videoFormGateEmbeddedTheme) {
      patch.videoFormGateEmbeddedTheme = buildVideoFormGateSourceTheme(site, nextSettingsForTheme)
    }
    return patch
  }, [block, enableVideoFormGateAction, forms, site])

  useEffect(() => {
    const visibleRuleIds = new Set(rules.map(rule => rule.id))
    setTimeInputs(current => Object.fromEntries(Object.entries(current).filter(([ruleId]) => visibleRuleIds.has(ruleId))))
  }, [rules])

  useEffect(() => {
    if (!onVideoFormGatePreviewChange) return undefined
    onVideoFormGatePreviewChange(openVideoFormRuleExpanded ? block.id : '')
    return () => onVideoFormGatePreviewChange('')
  }, [block.id, onVideoFormGatePreviewChange, openVideoFormRuleExpanded])

  useEffect(() => {
    let timeoutId = 0
    let video: HTMLVideoElement | null = null

    const readDuration = () => {
      const nextDuration = getEditorVideoDuration(block.id)
      setVideoDurationSeconds(current => current === nextDuration ? current : nextDuration)
      return nextDuration
    }

    const bindVideo = (attempt = 0) => {
      video = getEditorVideoElement(block.id)
      const duration = readDuration()
      if (!video && attempt < 8) {
        timeoutId = window.setTimeout(() => bindVideo(attempt + 1), 250)
        return
      }
      if (!video || duration > 0) return
      video.addEventListener('loadedmetadata', readDuration)
      video.addEventListener('durationchange', readDuration)
    }

    bindVideo()

    return () => {
      if (timeoutId) window.clearTimeout(timeoutId)
      if (video) {
        video.removeEventListener('loadedmetadata', readDuration)
        video.removeEventListener('durationchange', readDuration)
      }
    }
  }, [block.id])

  const patchRules = useCallback((nextRules: VideoActionRule[]) => {
    const normalizedVisibleRules = nextRules
      .map((rule, index) => normalizeVideoActionRule(rule, index))
      .filter((rule): rule is VideoActionRule => Boolean(rule))
    const nextVisibleRuleIds = new Set(normalizedVisibleRules.map(rule => rule.id))
    const hiddenRules = allRules.filter(rule => (
      !nextVisibleRuleIds.has(rule.id) &&
      (
        (!enableVideoFormGateAction && rule.action === 'open_video_form') ||
        (!metaPixelConnected && rule.action === 'meta_event')
      )
    ))
    const normalizedRules = [...hiddenRules, ...normalizedVisibleRules]
      .sort((a, b) => a.timeSeconds - b.timeSeconds)

    onPatchSettings({
      [VIDEO_ACTIONS_SETTING_KEY]: normalizedRules,
      ...buildVideoFormGateSettingsPatch(normalizedRules)
    })
    window.setTimeout(onSave, 0)
  }, [allRules, buildVideoFormGateSettingsPatch, enableVideoFormGateAction, metaPixelConnected, onPatchSettings, onSave])

  const patchRule = useCallback((ruleId: string, patch: Partial<VideoActionRule>, options?: { seek?: boolean }) => {
    const nextRules = rules.map(rule => rule.id === ruleId ? { ...rule, ...patch } : rule)
    patchRules(nextRules)
    if (options?.seek && Object.prototype.hasOwnProperty.call(patch, 'timeSeconds')) {
      seekEditorVideoToTime(block.id, patch.timeSeconds)
    }
  }, [block.id, patchRules, rules])

  const saveSiteSoon = useCallback(() => {
    if (!onSaveSite) return
    window.setTimeout(() => { void onSaveSite() }, 0)
  }, [onSaveSite])

  const enableSiteMetaIfNeeded = useCallback(() => {
    if (!metaPixelConnected || site.metaCapiEnabled) return
    onPatchSite({ metaCapiEnabled: true })
    saveSiteSoon()
  }, [metaPixelConnected, onPatchSite, saveSiteSoon, site.metaCapiEnabled])

  const openNewRule = useCallback(() => {
    const timeSeconds = Math.min(timelineMaxSeconds, getCurrentEditorVideoTime(block.id))
    const defaultAction: VideoActionKind = contentTargets.length
      ? 'show'
      : enableVideoFormGateAction && !rules.some(rule => rule.action === 'open_video_form')
        ? 'open_video_form'
        : hasPopupTarget
          ? 'show_popup'
          : pageTargets.length
            ? 'site_page'
            : 'redirect'
    const targetBlockIds = defaultAction === 'show_popup' ? [POPUP_SURFACE_ID] : []
    const nextRule = normalizeVideoActionRule({
      id: makeVideoActionId(),
      timeSeconds,
      targetBlockId: targetBlockIds[0] || '',
      targetBlockIds,
      action: defaultAction,
      before: getRecommendedVideoActionBefore(defaultAction),
      targetPageId: defaultAction === 'site_page' ? pageTargets[0]?.id || '' : '',
      pauseUntilComplete: false
    })
    if (!nextRule) return
    patchRules([...rules, nextRule])
    setExpandedRuleId(nextRule.id)
    setTimeInputs(current => ({ ...current, [nextRule.id]: formatVideoActionTime(timeSeconds) }))
    seekEditorVideoToTime(block.id, timeSeconds)
  }, [block.id, contentTargets.length, enableVideoFormGateAction, hasPopupTarget, pageTargets, patchRules, rules, timelineMaxSeconds])

  const getTargetOptionsForAction = useCallback((action: VideoActionKind) => {
    if (action === 'open_form') return formTargets
    if (action === 'scroll_to') return sectionTargets.length ? sectionTargets : contentTargets
    return contentTargets
  }, [contentTargets, formTargets, sectionTargets])

  const handleChangeAction = useCallback((rule: VideoActionRule, action: VideoActionKind) => {
    if (action === 'meta_event' && !metaPixelConnected) return
    if (action === 'meta_event') enableSiteMetaIfNeeded()
    const previousRecommended = getRecommendedVideoActionBefore(rule.action)
    const nextBefore = action === 'open_video_form'
      ? 'unchanged'
      : rule.before === previousRecommended
        ? getRecommendedVideoActionBefore(action)
        : rule.before
    const candidateTargets = getTargetOptionsForAction(action)
    const candidateTargetIds = new Set(candidateTargets.map(target => target.id))
    const currentTargetIds = getVideoActionTargetIds(rule).filter(targetId => targetId !== POPUP_SURFACE_ID)
    const validCurrentTargetIds = currentTargetIds.filter(targetId => candidateTargetIds.has(targetId))
    const nextTargetIds = action === 'show_popup'
      ? [POPUP_SURFACE_ID]
      : videoActionTargetKinds.has(action)
        ? (videoActionMultiTargetKinds.has(action) ? validCurrentTargetIds : validCurrentTargetIds.slice(0, 1))
        : []

    patchRule(rule.id, {
      action,
      before: nextBefore,
      targetBlockId: nextTargetIds[0] || '',
      targetBlockIds: nextTargetIds,
      targetPageId: action === 'site_page' ? rule.targetPageId || pageTargets[0]?.id || '' : '',
      redirectUrl: action === 'redirect' ? rule.redirectUrl || '' : '',
      pauseUntilComplete: action === 'open_form' ? rule.pauseUntilComplete !== false : false,
      ...(action === 'meta_event' ? {
        metaCapiEnabled: rule.metaCapiEnabled !== false,
        metaEventName: normalizeEnabledMetaEventName(rule.metaEventName),
        metaEventParameters: pruneMetaEventParametersForEvent(rule.metaEventParameters, normalizeEnabledMetaEventName(rule.metaEventName))
      } : {
        metaCapiEnabled: undefined,
        metaEventName: undefined,
        metaEventParameters: undefined
      })
    })
  }, [enableSiteMetaIfNeeded, getTargetOptionsForAction, metaPixelConnected, pageTargets, patchRule])

  const handleTimelineTimeChange = useCallback((ruleId: string, timeSeconds: number) => {
    const nextTime = Math.min(timelineMaxSeconds, clampVideoActionTime(timeSeconds))
    patchRules(rules.map(rule => rule.id === ruleId ? { ...rule, timeSeconds: nextTime } : rule))
    setTimeInputs(current => ({ ...current, [ruleId]: formatVideoActionTime(nextTime) }))
    setExpandedRuleId(ruleId)
    seekEditorVideoToTime(block.id, nextTime)
  }, [block.id, patchRules, rules, timelineMaxSeconds])

  const handleTimeInputChange = useCallback((rule: VideoActionRule, value: string) => {
    setTimeInputs(current => ({ ...current, [rule.id]: value }))
    const nextTime = Math.min(timelineMaxSeconds, parseVideoActionTimeInput(value))
    patchRule(rule.id, { timeSeconds: nextTime }, { seek: true })
  }, [patchRule, timelineMaxSeconds])

  const handleTimeInputBlur = useCallback((rule: VideoActionRule) => {
    setTimeInputs(current => ({ ...current, [rule.id]: formatVideoActionTime(rule.timeSeconds) }))
  }, [])

  const handleCloseRuleEditor = useCallback(() => {
    onSave()
    setExpandedRuleId('')
  }, [onSave])

  const handleDeleteRule = useCallback((ruleId: string) => {
    patchRules(rules.filter(rule => rule.id !== ruleId))
    setExpandedRuleId(current => current === ruleId ? '' : current)
    setTimeInputs(current => {
      const next = { ...current }
      delete next[ruleId]
      return next
    })
    onTargetHover?.('')
  }, [onTargetHover, patchRules, rules])

  const handleToggleTarget = useCallback((rule: VideoActionRule, targetId: string) => {
    const currentIds = getVideoActionTargetIds(rule).filter(id => id !== POPUP_SURFACE_ID)
    const allowsMultiple = videoActionMultiTargetKinds.has(rule.action)
    let nextIds: string[]

    if (allowsMultiple) {
      nextIds = currentIds.includes(targetId)
        ? (currentIds.length > 1 ? currentIds.filter(id => id !== targetId) : currentIds)
        : [...currentIds, targetId]
    } else {
      nextIds = [targetId]
    }

    patchRule(rule.id, {
      targetBlockId: nextIds[0] || '',
      targetBlockIds: nextIds
    })
  }, [patchRule])

  const handleTargetHover = useCallback((targetId: string) => {
    onTargetHover?.(targetId === POPUP_SURFACE_ID ? '' : targetId)
  }, [onTargetHover])

  const renderTargetPicker = (rule: VideoActionRule) => {
    const candidateTargets = getTargetOptionsForAction(rule.action)
    const selectedIds = getVideoActionTargetIds(rule)

    if (!videoActionTargetKinds.has(rule.action)) return null

    if (!candidateTargets.length) {
      return (
        <p className={styles.videoActionHint}>
          {rule.action === 'open_form'
            ? 'Agrega un formulario en la página para poder abrirlo desde el video.'
            : 'Agrega un botón, sección, texto, imagen o formulario para poder controlarlo desde el video.'}
        </p>
      )
    }

    return (
      <div className={styles.videoActionTargetList}>
        {candidateTargets.map(target => {
          const selected = selectedIds.includes(target.id)
          const targetIcon = target.blockType && target.blockType !== 'popup'
            ? blockIcons[target.blockType as SiteBlockType] || <LayoutTemplate size={15} />
            : <LayoutTemplate size={15} />
          return (
            <button
              key={target.id}
              type="button"
              aria-pressed={selected}
              className={`${styles.videoActionTargetChoice} ${selected ? styles.videoActionTargetChoiceActive : ''}`}
              onMouseEnter={() => handleTargetHover(target.id)}
              onMouseLeave={() => handleTargetHover('')}
              onFocus={() => handleTargetHover(target.id)}
              onBlur={() => handleTargetHover('')}
              onClick={() => handleToggleTarget(rule, target.id)}
            >
              <span className={styles.videoActionTargetIcon}>{targetIcon}</span>
              <span className={styles.videoActionTargetText}>
                <span>{target.label}</span>
                <small>{target.kindLabel}</small>
              </span>
              <span className={styles.videoActionTargetCheck} aria-hidden="true">
                {selected ? <Check size={13} /> : null}
              </span>
            </button>
          )
        })}
      </div>
    )
  }

  const renderRuleEditor = (rule: VideoActionRule) => {
    const timeInput = timeInputs[rule.id] ?? formatVideoActionTime(rule.timeSeconds)
    const videoFormActionTaken = rule.action !== 'open_video_form' && rules.some(item => item.action === 'open_video_form')

    return (
      <div className={styles.videoActionInlineEditor}>
        <div className={styles.videoActionTimeControl}>
          <div className={styles.videoActionTimeRow}>
            <label className={styles.videoActionTimeMeta}>
              <span className={styles.videoActionTimeLabel}>Cuando llegue a:</span>
              <input
                className={styles.videoActionTimeInput}
                value={timeInput}
                placeholder="03:45"
                inputMode="numeric"
                onChange={(event) => handleTimeInputChange(rule, event.target.value)}
                onBlur={() => handleTimeInputBlur(rule)}
              />
            </label>
            <Button
              type="button"
              variant="secondary"
              size="sm"
              leftIcon={<X size={14} />}
              className={styles.videoActionCloseButton}
              onClick={handleCloseRuleEditor}
            >
              Cerrar y guardar
            </Button>
          </div>
          <VideoActionTimeScale
            timeSeconds={rule.timeSeconds}
            maxSeconds={timelineMaxSeconds}
            onChangeTime={(timeSeconds) => handleTimelineTimeChange(rule.id, timeSeconds)}
          />
        </div>

        <label className={styles.field}>
          <span>Qué acción quieres tomar</span>
          <CustomSelect
            value={rule.action}
            onChange={(event) => handleChangeAction(rule, event.target.value as VideoActionKind)}
            onBlur={onSave}
          >
            {availablePrimaryVideoActionKinds.map(action => (
              <option
                key={action}
                value={action}
                disabled={(action === 'show_popup' && !hasPopupTarget) || (action === 'open_form' && !formTargets.length) || (action === 'site_page' && !pageTargets.length) || (action === 'open_video_form' && videoFormActionTaken)}
              >
                {videoActionLabels[action]}
              </option>
            ))}
          </CustomSelect>
        </label>

        {rule.action !== 'open_video_form' && rule.action !== 'meta_event' && (
          <label className={styles.field}>
            <span>Antes de este momento</span>
            <CustomSelect
              value={rule.before}
              onChange={(event) => patchRule(rule.id, { before: event.target.value as VideoActionBeforeState })}
              onBlur={onSave}
            >
              {videoActionBeforeStates.map(before => (
                <option key={before} value={before}>{videoActionBeforeLabels[before]}</option>
              ))}
            </CustomSelect>
          </label>
        )}

        {rule.action === 'site_page' && (
          <label className={styles.field}>
            <span>Página destino</span>
            <CustomSelect
              value={rule.targetPageId || ''}
              onChange={(event) => patchRule(rule.id, { targetPageId: event.target.value })}
              onBlur={onSave}
            >
              <option value="">Selecciona una página</option>
              {pageTargets.map(page => (
                <option key={page.id} value={page.id}>{page.title || 'Página'}</option>
              ))}
            </CustomSelect>
          </label>
        )}

        {rule.action === 'redirect' && (
          <label className={styles.field}>
            <span>URL destino</span>
            <input
              value={rule.redirectUrl || ''}
              placeholder="https://tusitio.com/oferta"
              onChange={(event) => patchRule(rule.id, { redirectUrl: event.target.value })}
              onBlur={onSave}
            />
          </label>
        )}

        {rule.action === 'meta_event' && (
          <div className={styles.videoActionStep}>
            <div className={styles.videoActionStepHeader}>
              <span className={styles.videoActionStepTitle}>Evento personalizado de Meta</span>
            </div>
            <MetaVideoEventSettings
              title="Meta Pixel + CAPI"
              description="Se dispara cuando el video llegue a este momento"
              siteMetaEnabled={Boolean(site.metaCapiEnabled)}
              metaPixelConnected={metaPixelConnected}
              eventEnabled={rule.metaCapiEnabled !== false}
              eventName={rule.metaEventName}
              parameters={rule.metaEventParameters}
              onToggle={(enabled) => {
                if (enabled) enableSiteMetaIfNeeded()
                patchRule(rule.id, {
                  metaCapiEnabled: enabled,
                  metaEventName: enabled ? normalizeEnabledMetaEventName(rule.metaEventName) : 'none',
                  metaEventParameters: enabled
                    ? pruneMetaEventParametersForEvent(rule.metaEventParameters, normalizeEnabledMetaEventName(rule.metaEventName))
                    : {}
                })
              }}
              onChangeEvent={(metaEventName) => {
                patchRule(rule.id, {
                  metaCapiEnabled: metaEventName !== 'none',
                  metaEventName,
                  metaEventParameters: pruneMetaEventParametersForEvent(rule.metaEventParameters, metaEventName)
                })
              }}
              onChangeParameters={(metaEventParameters) => patchRule(rule.id, { metaEventParameters })}
              onCommit={onSave}
            />
          </div>
        )}

        {rule.action === 'open_video_form' && (
          <VideoFormGateSettingsPanel
            site={site}
            block={block}
            forms={forms}
            customFields={customFields}
            customFieldFolders={customFieldFolders}
            pages={pages}
            activePageId={activePageId}
            metaPixelConnected={metaPixelConnected}
            completionTargets={contentTargets}
            forceEnabled
            showEnableSwitch={false}
            showTriggerControl={false}
            showCompletionControls
            showDesignControls
            activeBlockId={videoFormGateActiveBlockId}
            activeElement={videoFormGateActiveElement}
            onActiveBlockChange={onVideoFormGateActiveBlockChange}
            onSubmitSelect={onVideoFormGateSubmitSelect}
            onPatchSite={onPatchSite}
            onPatchSettings={onPatchSettings}
            onCustomFieldCreated={onCustomFieldCreated}
            onSaveSite={onSaveSite}
            onSave={onSave}
            onTargetHover={onTargetHover}
          />
        )}

        {videoActionTargetKinds.has(rule.action) && (
          <div className={styles.videoActionStep}>
            <div className={styles.videoActionStepHeader}>
              <span className={styles.videoActionStepTitle}>{rule.action === 'open_form' ? 'Formulario o bloque a abrir' : 'Elementos a controlar'}</span>
            </div>
            {renderTargetPicker(rule)}
          </div>
        )}

        <div className={styles.videoActionRuleActions}>
          <Button
            type="button"
            variant="ghost"
            size="sm"
            leftIcon={<Trash2 size={14} />}
            className={styles.videoActionDeleteButton}
            onClick={() => handleDeleteRule(rule.id)}
          >
            Eliminar acción
          </Button>
          <Button
            type="button"
            variant="secondary"
            size="sm"
            leftIcon={<Save size={14} />}
            onClick={handleCloseRuleEditor}
          >
            Guardar acción
          </Button>
        </div>
      </div>
    )
  }

  const renderRuleSummary = (rule: VideoActionRule) => (
    <button
      type="button"
      className={styles.videoActionRuleSummary}
      onClick={() => {
        setExpandedRuleId(rule.id)
        setTimeInputs(current => ({ ...current, [rule.id]: formatVideoActionTime(rule.timeSeconds) }))
        seekEditorVideoToTime(block.id, rule.timeSeconds)
      }}
    >
      <span className={styles.videoActionRuleSummaryTime}>
        <Clock3 size={13} />
        {formatVideoActionTime(rule.timeSeconds)}
      </span>
      <span className={styles.videoActionRuleSummaryText}>
        <strong>{videoActionLabels[rule.action]}</strong>
        <small>{getVideoActionRuleText(rule, targets, pages)}</small>
      </span>
      <ChevronDown size={15} />
    </button>
  )

  return (
    <div className={styles.videoActionPanel}>
      <div className={styles.videoActionHeader}>
        <div>
          <h3>Acciones de video</h3>
          <p>Controla qué elementos aparecen, se ocultan o cambian mientras el visitante ve este video.</p>
        </div>
        {rules.length === 0 && (
          <Button type="button" variant="secondary" size="sm" fullWidth leftIcon={<Plus size={14} />} onClick={openNewRule}>
            Agregar acción
          </Button>
        )}
      </div>

      {rules.length > 0 && (
        <>
          <div className={styles.videoActionRuleList}>
            {rules.map(rule => (
              <article key={rule.id} className={`${styles.videoActionRule} ${expandedRuleId === rule.id ? styles.videoActionRuleExpanded : ''}`}>
                {expandedRuleId === rule.id ? renderRuleEditor(rule) : renderRuleSummary(rule)}
              </article>
            ))}
          </div>

          <Button type="button" variant="secondary" size="sm" fullWidth leftIcon={<Plus size={14} />} onClick={openNewRule}>
            Agregar acción
          </Button>
        </>
      )}
    </div>
  )
}

const PropertiesPanel: React.FC<PropertiesPanelProps> = ({
  site,
  block,
  surfaceSelectionId,
  blocks,
  allBlocks,
  popupBlocks = [],
  forms,
  calendars,
  customFields,
  customFieldFolders,
  pages,
  activePageId,
  metaPixelConnected,
  importedPopupDetected,
  connectedSocialProfiles,
  loadingSocialProfiles,
  onPatchSite,
  onPatchTheme,
  onSaveSite,
  onPatchBlock,
  onPatchSettings,
  onPatchCategorySettings,
  onSaveCategory,
  onCustomFieldCreated,
  onVideoActionTargetHover,
  onVideoFormGatePreviewChange,
  videoFormGateActiveBlockId,
  videoFormGateActiveElement,
  onVideoFormGateActiveBlockChange,
  onVideoFormGateSubmitSelect,
  onSave
}) => {
  if (surfaceSelectionId === POPUP_SELECTED_ID) {
    return (
      <PopupInspector
        site={site}
        popupBlocks={popupBlocks}
        importedPopupDetected={importedPopupDetected}
        onPatchTheme={onPatchTheme}
        onSaveSite={onSaveSite}
      />
    )
  }

  if (!block) {
    return (
      <PageInspector
        site={site}
        pages={pages}
        activePageId={activePageId}
        metaPixelConnected={metaPixelConnected}
        onPatchSite={onPatchSite}
        onPatchTheme={onPatchTheme}
        onSaveSite={onSaveSite}
      />
    )
  }

  const isField = fieldBlockTypes.has(block.blockType)
  const settings = block.settings || {}
  const hasButtonCopy = block.blockType === 'hero' || block.blockType === 'cta' || block.blockType === 'button'
  const hasListCopy = ['benefits', 'testimonials', 'services', 'faq'].includes(block.blockType)
  const isPrimaryTextBlock = ['headline', 'title'].includes(block.blockType)
  const isSecondaryTextBlock = ['subheading', 'subtitle', 'description'].includes(block.blockType)
  const systemFieldPreset = getSystemFormFieldPresetForBlock(block)
  const showTypographyInEdit = shouldShowBlockTypographyInEdit(block)
  const showBlockNameFirst = showTypographyInEdit || isField || block.blockType === SECTION_BLOCK_TYPE || block.blockType === 'countdown'
  const isMediaBlock = block.blockType === 'image' || block.blockType === 'video'
  const showContentField = block.blockType !== 'calendar_embed' && block.blockType !== 'button' && !isMediaBlock
  const contentLabel = isField
    ? 'Texto de ayuda'
    : block.blockType === SECTION_BLOCK_TYPE
      ? 'Título visible opcional'
      : block.blockType === 'embed'
        ? 'Código externo, iframe o URL'
        : block.blockType === 'hero'
          ? 'Título principal'
          : block.blockType === 'cta'
            ? 'Título'
            : hasListCopy
              ? 'Título de seccion'
              : block.blockType === 'countdown'
                ? 'Título del contador'
              : isPrimaryTextBlock
                ? 'Texto del título'
                : isSecondaryTextBlock
                  ? 'Texto del subtítulo'
                  : block.blockType === 'text'
                    ? 'Texto'
                    : 'Contenido'
  const contentRows = block.blockType === 'embed' ? 7 : isField || block.blockType === SECTION_BLOCK_TYPE ? 2 : 3
  const buttonTextEditorValue = Object.prototype.hasOwnProperty.call(settings, 'buttonText')
    ? getSettingString(settings, 'buttonText')
    : block.blockType === 'button'
      ? block.content
      : ''
  const blockNameField = (
    <label className={styles.field}>
      <span>{isField ? 'Pregunta visible' : block.blockType === SECTION_BLOCK_TYPE ? 'Nombre de la franja' : 'Nombre interno del bloque'}</span>
      <input value={block.label} onChange={(event) => onPatchBlock({ label: event.target.value })} onBlur={onSave} />
    </label>
  )
  const editTypographyControls = showTypographyInEdit ? (
    <InlineBlockStyleControls
      site={site}
      block={block}
      blocks={blocks}
      mode="typography"
      onPatchSettings={onPatchSettings}
      onSave={onSave}
    />
  ) : null
  const contentField = showContentField ? (
    <label className={styles.field}>
      <span>{contentLabel}</span>
      <textarea
        rows={contentRows}
        value={block.content}
        placeholder={block.blockType === 'embed' ? '<iframe src="https://..."></iframe> o código HTML del widget' : undefined}
        onChange={(event) => onPatchBlock({ content: event.target.value })}
        onBlur={onSave}
      />
    </label>
  ) : null

  const blockHasExtraSettingsContent = hasBlockExtraSettingsContent(block)
  const fieldEditControls = isField ? (
    <>
      <div className={styles.settingsGroup}>
        <div className={styles.panelSubheader}>Campo</div>
        {systemFieldPreset ? (
          <label className={styles.field}>
            <span>Texto dentro del campo</span>
            <input value={block.placeholder} onChange={(event) => onPatchBlock({ placeholder: event.target.value })} onBlur={onSave} />
          </label>
        ) : (
          <div className={styles.twoColumn}>
            <label className={styles.field}>
              <span>Texto dentro del campo</span>
              <input value={block.placeholder} onChange={(event) => onPatchBlock({ placeholder: event.target.value })} onBlur={onSave} />
            </label>
            <label className={styles.field}>
              <span>Nombre interno</span>
              <input
                value={getSettingString(settings, 'internalName')}
                onChange={(event) => onPatchSettings({ internalName: event.target.value })}
                onBlur={onSave}
              />
            </label>
          </div>
        )}

        {systemFieldPreset ? (
          <label className={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={block.required}
              onChange={(event) => {
                onPatchBlock({ required: event.target.checked })
                window.setTimeout(onSave, 0)
              }}
            />
            <span>Campo requerido</span>
          </label>
        ) : (
          <div className={styles.twoColumn}>
            <label className={styles.field}>
              <span>Validación</span>
              <CustomSelect
                value={getSettingString(settings, 'validation')}
                onChange={(event) => onPatchSettings({ validation: event.target.value })}
                onBlur={onSave}
              >
                {fieldValidationOptions.map(option => <option key={option.value || 'none'} value={option.value}>{option.label}</option>)}
              </CustomSelect>
            </label>
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={block.required}
                onChange={(event) => {
                  onPatchBlock({ required: event.target.checked })
                  window.setTimeout(onSave, 0)
                }}
              />
              <span>Campo requerido</span>
            </label>
          </div>
        )}

        {block.blockType === 'phone' && !systemFieldPreset && (
          <label className={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={isPhoneCountrySelectorEnabled(block)}
              onChange={(event) => {
                onPatchSettings({ phoneCountrySelectorEnabled: event.target.checked })
                window.setTimeout(onSave, 0)
              }}
            />
            <span>Mostrar país y lada</span>
          </label>
        )}
      </div>

      <CustomFieldBindingControl
        block={block}
        customFields={customFields}
        customFieldFolders={customFieldFolders}
        onPatchSettings={onPatchSettings}
        onCustomFieldCreated={onCustomFieldCreated}
        onSave={onSave}
      />
    </>
  ) : null
  const choiceEditControls = isChoiceBlock(block.blockType) ? (
    <OptionsRulesEditor
      block={block}
      blocks={allBlocks || blocks}
      pages={pages}
      sitePages={pages}
      activeSitePageId={activePageId}
      onPatchBlock={onPatchBlock}
      onSave={onSave}
    />
  ) : null
  const settingsContent = (
    <>
      {!isField && blockHasExtraSettingsContent && (
        <LandingBlockSettings
          site={site}
          block={block}
          blocks={allBlocks || blocks}
          forms={forms}
          calendars={calendars}
          pages={pages}
          activePageId={activePageId}
          connectedSocialProfiles={connectedSocialProfiles}
          loadingSocialProfiles={loadingSocialProfiles}
          onPatchSettings={onPatchSettings}
          onSave={onSave}
        />
      )}
    </>
  )

  const editContent = (
    <>
      {showBlockNameFirst && blockNameField}
      {showBlockNameFirst && editTypographyControls}

      {contentField}

      {block.blockType === 'hero' && (
        <label className={styles.field}>
          <span>Kicker</span>
          <input value={getSettingString(settings, 'kicker')} onChange={(event) => onPatchSettings({ kicker: event.target.value })} onBlur={onSave} />
        </label>
      )}

      {(block.blockType === 'hero' || block.blockType === 'cta') && (
        <label className={styles.field}>
          <span>Subtítulo</span>
          <textarea rows={2} value={getSettingString(settings, 'subtitle')} onChange={(event) => onPatchSettings({ subtitle: event.target.value })} onBlur={onSave} />
        </label>
      )}

      {hasButtonCopy && (
        <div className={styles.buttonEditStack}>
          <div className={styles.twoColumn}>
            <label className={styles.field}>
              <span>Texto del botón</span>
              <input
                value={buttonTextEditorValue}
                onChange={(event) => onPatchSettings({ buttonText: event.target.value })}
                onBlur={onSave}
              />
            </label>
            <label className={styles.field}>
              <span>Subtexto del botón</span>
              <input value={getSettingString(settings, 'buttonSubtitle')} onChange={(event) => onPatchSettings({ buttonSubtitle: event.target.value })} onBlur={onSave} />
            </label>
          </div>
          <ButtonPresetPicker
            site={site}
            settings={settings}
            onPatchSettings={onPatchSettings}
            onSave={onSave}
          />
        </div>
      )}

      {!showBlockNameFirst && blockNameField}
      {!showBlockNameFirst && editTypographyControls}

      {hasListCopy && (
        <label className={styles.field}>
          <span>Items (uno por línea: título | texto | autor)</span>
          <textarea
            rows={5}
            value={stringifyItems(settings)}
            onChange={(event) => onPatchSettings({ items: parseItems(event.target.value) })}
            onBlur={onSave}
          />
        </label>
      )}

      {fieldEditControls}

      {choiceEditControls}

      {blockHasExtraSettingsContent && settingsContent}
    </>
  )

  const designContent = (
    <>
      <InlineBlockStyleControls
        site={site}
        block={block}
        blocks={blocks}
        mode={showTypographyInEdit ? 'design' : 'all'}
        onPatchSettings={onPatchSettings}
        onSave={onSave}
      />

      {isFormSite(site) && isField && (
        <FormGlobalStyleControls site={site} onPatchTheme={onPatchTheme} onSaveSite={onSaveSite} />
      )}

      {block.blockType === 'video' && (
        <VideoPlayerSettingsControls
          settings={settings}
          mediaUrl={getSettingString(settings, 'mediaUrl')}
          sections="chrome"
          onPatchSettings={onPatchSettings}
          onSave={onSave}
        />
      )}
    </>
  )

  const videoActionsContent = block.blockType === 'video' ? (
    <VideoActionsPanel
      site={site}
      block={block}
      blocks={allBlocks || blocks}
      popupBlocks={popupBlocks}
      pages={pages}
      activePageId={activePageId}
      importedPopupDetected={importedPopupDetected}
      metaPixelConnected={metaPixelConnected}
      onPatchSite={onPatchSite}
      onSaveSite={onSaveSite}
      forms={forms}
      customFields={customFields}
      customFieldFolders={customFieldFolders}
      onCustomFieldCreated={onCustomFieldCreated}
      enableVideoFormGateAction
      onPatchSettings={onPatchSettings}
      onSave={onSave}
      onTargetHover={onVideoActionTargetHover}
      onVideoFormGatePreviewChange={onVideoFormGatePreviewChange}
      videoFormGateActiveBlockId={videoFormGateActiveBlockId}
      videoFormGateActiveElement={videoFormGateActiveElement}
      onVideoFormGateActiveBlockChange={onVideoFormGateActiveBlockChange}
      onVideoFormGateSubmitSelect={onVideoFormGateSubmitSelect}
    />
  ) : null

  const inspectorTabs: InspectorTab[] = [
    { value: 'edit', label: 'Editar', icon: <Pencil size={14} />, content: editContent },
    ...(videoActionsContent ? [{ value: 'videoActions' as InspectorTabId, label: 'Acciones de video', icon: <Clock3 size={14} />, content: videoActionsContent }] : []),
    { value: 'design', label: 'Diseño', icon: <Sparkles size={14} />, content: designContent }
  ]

  return (
    <InspectorTabbedPanel
      key={`${block.id}:${block.blockType}`}
      title="Propiedades"
      subtitle={blockLabels[block.blockType]}
      defaultTab="edit"
      tabs={inspectorTabs}
    />
  )
}

interface OptionsRulesEditorProps {
  block: SiteBlock
  blocks: SiteBlock[]
  pages: SitePage[]
  sitePages?: SitePage[]
  activeSitePageId?: string
  onPatchBlock: (patch: Partial<SiteBlock>) => void
  onSave: () => void
}

const OptionsRulesEditor: React.FC<OptionsRulesEditorProps> = ({ block, blocks, pages, sitePages, activeSitePageId, onPatchBlock, onSave }) => {
  const options = getOptions(block)
  const fieldTargets = blocks.filter(item => fieldBlockTypes.has(item.blockType) && item.id !== block.id)
  const pageTargets = getManualRedirectPages(sitePages && sitePages.length ? sitePages : pages, activeSitePageId)
  const getTargetLabel = (target: SiteBlock) => {
    const page = pages.find(item => item.id === getBlockPageId(target, pages))
    return page ? `${target.label} - ${page.title}` : target.label
  }

  const patchOption = (index: number, patch: Partial<SiteBlockOption>) => {
    const next = options.map((option, optionIndex) => optionIndex === index ? { ...option, ...patch } : option)
    onPatchBlock({ options: next })
  }

  const addOption = () => {
    onPatchBlock({
      options: [
        ...options,
        {
          id: `option-${Date.now()}`,
          label: `Opción ${options.length + 1}`,
          value: `Opción ${options.length + 1}`,
          action: 'continue'
        }
      ]
    })
  }

  const removeOption = (index: number) => {
    onPatchBlock({ options: options.filter((_, optionIndex) => optionIndex !== index) })
  }

  const getVisibleRuleAction = (action?: SiteOptionAction) => (
    action && visibleRuleActionValues.has(action) ? action : 'continue'
  )

  const buildRuleActionPatch = (option: SiteBlockOption, action: SiteOptionAction): Partial<SiteBlockOption> => ({
    action,
    targetBlockId: action === 'jump' ? option.targetBlockId || '' : '',
    targetPageId: action === 'site_page' ? option.targetPageId || '' : '',
    redirectUrl: action === 'redirect' ? option.redirectUrl || '' : '',
    submitBeforeAction: exitRuleActions.has(action) ? option.submitBeforeAction !== false : undefined,
    message: action === 'disqualify' || action === 'disqualify_after_submit' ? option.message || '' : '',
    tag: '',
    category: ''
  })

  return (
    <div className={styles.optionRules}>
      <div className={styles.optionRulesHeader}>
        <strong>Opciones y reglas</strong>
        <button type="button" onClick={addOption}>
          <Plus size={14} />
          Agregar
        </button>
      </div>
      {options.map((option, index) => (
        <div key={option.id || index} className={styles.optionRuleCard}>
          <div className={styles.twoColumn}>
            <label className={styles.field}>
              <span>Opción</span>
              <input
                value={option.label}
                onChange={(event) => patchOption(index, { label: event.target.value, value: event.target.value })}
                onBlur={onSave}
              />
            </label>
            <label className={styles.field}>
              <span>Regla</span>
              <CustomSelect
                value={getVisibleRuleAction(option.action)}
                onChange={(event) => {
                  const action = event.target.value as SiteOptionAction
                  patchOption(index, buildRuleActionPatch(option, action))
                }}
                onBlur={onSave}
              >
                {ruleActions.map(action => <option key={action.value} value={action.value}>{action.label}</option>)}
              </CustomSelect>
            </label>
          </div>

          {option.action === 'jump' && (
            <label className={styles.field}>
              <span>Saltar a pregunta</span>
              <CustomSelect value={option.targetBlockId || ''} onChange={(event) => patchOption(index, { targetBlockId: event.target.value })} onBlur={onSave}>
                <option value="">Selecciona una pregunta</option>
                {fieldTargets.map(target => <option key={target.id} value={target.id}>{getTargetLabel(target)}</option>)}
              </CustomSelect>
            </label>
          )}

          {option.action === 'redirect' && (
            <label className={styles.field}>
              <span>URL destino</span>
              <input
                value={option.redirectUrl || ''}
                placeholder="https://tusitio.com"
                onChange={(event) => patchOption(index, { redirectUrl: event.target.value })}
                onBlur={onSave}
              />
            </label>
          )}

          {option.action === 'site_page' && (
            <label className={styles.field}>
              <span>Página del sitio</span>
              <CustomSelect value={option.targetPageId || ''} onChange={(event) => patchOption(index, { targetPageId: event.target.value })} onBlur={onSave}>
                <option value="">Selecciona una página</option>
                {pageTargets.map(page => <option key={page.id} value={page.id}>{page.title || 'Página'}</option>)}
              </CustomSelect>
            </label>
          )}

          {exitRuleActions.has(getVisibleRuleAction(option.action)) && (
            <>
              <label className={styles.field}>
                <span>Datos del formulario</span>
                <CustomSelect
                  value={option.submitBeforeAction === false ? 'skip' : 'submit'}
                  onChange={(event) => patchOption(index, { submitBeforeAction: event.target.value !== 'skip' })}
                  onBlur={onSave}
                >
                  <option value="submit">Guardar datos y luego redirigir</option>
                  <option value="skip">Redirigir sin guardar datos</option>
                </CustomSelect>
              </label>
              <p className={styles.customFieldHint}>
                Si guarda datos, el formulario se envía antes de mandar al usuario al destino.
              </p>
            </>
          )}

          {(option.action === 'disqualify' || option.action === 'disqualify_after_submit') && (
            <label className={styles.field}>
              <span>Mensaje cuando se descalifique</span>
              <textarea
                rows={2}
                value={option.message || ''}
                placeholder={option.action === 'disqualify' ? 'Gracias. Por ahora no califica.' : 'Gracias. Tu información fue recibida.'}
                onChange={(event) => patchOption(index, { message: event.target.value })}
                onBlur={onSave}
              />
            </label>
          )}

          <button type="button" className={styles.removeOption} onClick={() => removeOption(index)}>
            <Trash2 size={14} />
            Quitar opción
          </button>
        </div>
      ))}
    </div>
  )
}

interface LandingBlockSettingsProps {
  site: PublicSite
  block: SiteBlock
  blocks: SiteBlock[]
  forms: PublicSite[]
  calendars: CalendarType[]
  pages: SitePage[]
  activePageId: string
  connectedSocialProfiles: ConnectedSocialProfile[]
  loadingSocialProfiles: boolean
  onPatchSettings: (patch: Record<string, unknown>) => void
  onSave: () => void
}

const ButtonActionFields: React.FC<{
  settings: Record<string, unknown>
  pages: SitePage[]
  activePageId: string
  onPatchSettings: (patch: Record<string, unknown>) => void
  onSave: () => void
}> = ({ settings, pages, activePageId, onPatchSettings, onSave }) => {
  const action = getButtonAction(settings)
  const targetPages = pages.filter(page => page.id !== activePageId)

  return (
    <>
      <label className={styles.field}>
        <span>Acción del botón</span>
        <CustomSelect value={action} onChange={(event) => onPatchSettings({ buttonAction: event.target.value })} onBlur={onSave}>
          <option value="url">Enviar a una URL</option>
          <option value="next_page">Ir a la siguiente página del embudo</option>
          <option value="specific_page">Ir a una página específica del embudo</option>
          <option value="open_popup">Abrir pop up</option>
          <option value="close_popup">Cerrar pop up</option>
        </CustomSelect>
      </label>

      {action === 'url' && (
        <label className={styles.field}>
          <span>URL</span>
          <input value={getSettingString(settings, 'buttonUrl')} onChange={(event) => onPatchSettings({ buttonUrl: event.target.value })} onBlur={onSave} />
        </label>
      )}

      {action === 'specific_page' && (
        <label className={styles.field}>
          <span>Página destino</span>
          <CustomSelect value={getSettingString(settings, 'buttonPageId')} onChange={(event) => onPatchSettings({ buttonPageId: event.target.value })} onBlur={onSave}>
            <option value="">Selecciona una página</option>
            {targetPages.map(page => <option key={page.id} value={page.id}>{page.title}</option>)}
          </CustomSelect>
        </label>
      )}
    </>
  )
}

const SocialProfileSettings: React.FC<{
  site: PublicSite
  settings: Record<string, unknown>
  connectedSocialProfiles: ConnectedSocialProfile[]
  loadingSocialProfiles: boolean
  onPatchSettings: (patch: Record<string, unknown>) => void
  onSave: () => void
}> = ({ site, settings, connectedSocialProfiles, loadingSocialProfiles, onPatchSettings, onSave }) => {
  const platform = normalizeSocialPlatform(settings.platform || platformChromeFor(resolveTemplateId(site)))
  const connectedProfilesForPlatform = connectedSocialProfiles.filter(profile => profile.platform === platform)
  const selectedConnectedProfileId = getSettingString(settings, 'socialSourceProfileId')
  const hasManualSelection = settings.socialAutoSync === false
  const preferredConnectedProfile = getPreferredConnectedSocialProfile(connectedSocialProfiles, platform)

  useEffect(() => {
    if (loadingSocialProfiles) return
    if (hasManualSelection) return
    if (selectedConnectedProfileId) return
    if (!preferredConnectedProfile) return

    onPatchSettings(connectedSocialProfileBlockPatch(preferredConnectedProfile))
    window.setTimeout(onSave, 0)
  }, [
    hasManualSelection,
    loadingSocialProfiles,
    onPatchSettings,
    onSave,
    platform,
    preferredConnectedProfile,
    selectedConnectedProfileId
  ])

  return (
    <div className={styles.settingsGroup}>
      <div className={styles.panelSubheader}>Perfil de red social</div>
      <label className={styles.field}>
        <span>Red social</span>
        <CustomSelect
          value={platform}
          onChange={(event) => onPatchSettings({
            platform: event.target.value,
            socialSourceProfileId: '',
            socialSourcePlatform: '',
            socialSourceId: '',
            socialSourcePageId: '',
            socialSourceName: ''
          })}
          onBlur={onSave}
        >
          {socialPlatformOptions.map(option => (
            <option key={option.value} value={option.value}>{option.label}</option>
          ))}
        </CustomSelect>
      </label>
      <label className={styles.field}>
        <span>Perfil conectado</span>
        <CustomSelect
          value={selectedConnectedProfileId}
          disabled={loadingSocialProfiles || connectedProfilesForPlatform.length === 0}
          onChange={(event) => {
            const profile = connectedProfilesForPlatform.find(item => item.id === event.target.value)
            if (profile) {
              onPatchSettings(connectedSocialProfileBlockPatch(profile))
              window.setTimeout(onSave, 0)
              return
            }
            onPatchSettings({
              socialAutoSync: false,
              socialSourceProfileId: '',
              socialSourcePlatform: '',
              socialSourceId: '',
              socialSourcePageId: '',
              socialSourceName: ''
            })
          }}
          onBlur={onSave}
        >
          <option value="">
            {loadingSocialProfiles
              ? 'Buscando perfiles...'
              : connectedProfilesForPlatform.length > 0
                ? 'Selecciona un perfil conectado'
                : 'Sin perfiles conectados'}
          </option>
          {connectedProfilesForPlatform.map(profile => (
            <option key={profile.id} value={profile.id}>{socialProfileOptionLabel(profile)}</option>
          ))}
        </CustomSelect>
      </label>
      <p className={styles.muted}>
        {connectedProfilesForPlatform.length > 0
          ? 'Elige un perfil conectado para llenar estos datos. Después puedes ajustar texto, foto o seguidores aquí mismo.'
          : 'No hay perfiles conectados para esta red. Puedes llenar este bloque manualmente mientras conectas la cuenta.'}
      </p>
      <label className={styles.field}>
        <span>Nombre que se verá</span>
        <input value={getSettingString(settings, 'brandName')} placeholder={site.title || site.name || 'Tu marca'} onChange={(event) => onPatchSettings({ brandName: event.target.value })} onBlur={onSave} />
      </label>
      <label className={styles.field}>
        <span>Texto secundario</span>
        <input value={getSettingString(settings, 'brandSubtitle')} placeholder={platform === 'instagram' ? 'Publicación pagada' : 'Patrocinado'} onChange={(event) => onPatchSettings({ brandSubtitle: event.target.value })} onBlur={onSave} />
      </label>
      <label className={styles.field}>
        <span>Foto de perfil (URL)</span>
        <input value={getSettingString(settings, 'brandAvatar')} placeholder="Pega la liga de la imagen" onChange={(event) => onPatchSettings({ brandAvatar: event.target.value })} onBlur={onSave} />
      </label>
      <div className={styles.twoColumn}>
        <label className={styles.field}>
          <span>Seguidores</span>
          <input value={getSettingString(settings, 'followers')} placeholder="12 mil" onChange={(event) => onPatchSettings({ followers: event.target.value })} onBlur={onSave} />
        </label>
        <label className={styles.checkboxLabel}>
          <input
            type="checkbox"
            checked={settings.brandVerified !== false}
            onChange={(event) => {
              onPatchSettings({ brandVerified: event.target.checked })
              window.setTimeout(onSave, 0)
            }}
          />
          <span>Mostrar verificado</span>
        </label>
      </div>
    </div>
  )
}

const VideoFormGateSettingsPanel: React.FC<{
  site: PublicSite
  block: SiteBlock
  forms: PublicSite[]
  customFields: CustomFieldDefinition[]
  customFieldFolders: CustomFieldFolder[]
  pages: SitePage[]
  activePageId: string
  metaPixelConnected: boolean
  completionTargets?: VideoActionTargetOption[]
  forceEnabled?: boolean
  showEnableSwitch?: boolean
  showTriggerControl?: boolean
  showCompletionControls?: boolean
  showDesignControls?: boolean
  activeBlockId?: string
  activeElement?: EmbeddedFormActiveElement
  onActiveBlockChange?: (blockId: string) => void
  onSubmitSelect?: () => void
  onPatchSite: (patch: Partial<PublicSite>) => void
  onPatchSettings: (patch: Record<string, unknown>) => void
  onCustomFieldCreated: (field: CustomFieldDefinition) => void
  onSaveSite?: () => void | Promise<void>
  onSave: () => void
  onTargetHover?: (blockId: string) => void
}> = ({
  site,
  block,
  forms,
  customFields,
  customFieldFolders,
  pages,
  activePageId,
  metaPixelConnected,
  completionTargets = [],
  forceEnabled = false,
  showEnableSwitch = true,
  showTriggerControl = true,
  showCompletionControls = false,
  showDesignControls = false,
  activeBlockId,
  activeElement = 'field',
  onActiveBlockChange,
  onSubmitSelect,
  onPatchSite,
  onPatchSettings,
  onCustomFieldCreated,
  onSaveSite,
  onSave,
  onTargetHover
}) => {
  const settings = block.settings || {}
  const enabled = forceEnabled || settings.videoFormGateEnabled === true
  const selectedFormId = getVideoFormGateSourceId(block)
  const questions = getEditableVideoFormGateBlocks(block, forms)
  const questionPages = getVideoFormGateSinglePage()
  const [activeQuestionId, setActiveQuestionId] = useState('')
  const controlledActiveQuestionId = activeBlockId !== undefined ? activeBlockId : activeQuestionId
  const activeQuestion = activeElement === 'submit'
    ? null
    : questions.find(question => question.id === controlledActiveQuestionId) || questions[0] || null
  const activeQuestionSettings = activeQuestion?.settings || {}
  const activeQuestionPreset = activeQuestion ? getSystemFormFieldPresetForBlock(activeQuestion) : null
  const activeQuestionIsField = Boolean(activeQuestion && fieldBlockTypes.has(activeQuestion.blockType))
  const showActiveQuestionTypographyInEdit = shouldShowBlockTypographyInEdit(activeQuestion)
  const videoGateTheme = useMemo(() => buildVideoFormGateSourceTheme(site, settings), [site, settings])
  const videoGateSite = useMemo(() => ({
    ...site,
    siteType: 'standard_form' as SiteType,
    theme: videoGateTheme
  }), [site, videoGateTheme])
  const selectQuestion = (fieldId: string) => {
    onActiveBlockChange?.(fieldId)
    if (activeBlockId === undefined) setActiveQuestionId(fieldId)
  }
  const selectSubmit = () => {
    onSubmitSelect?.()
  }

  useEffect(() => {
    if (!enabled) return
    if (activeElement === 'submit') return
    if (controlledActiveQuestionId && questions.some(question => question.id === controlledActiveQuestionId)) return
    selectQuestion(questions[0]?.id || '')
  }, [activeElement, controlledActiveQuestionId, enabled, questions])

  const patchAndSaveSoon = (patch: Record<string, unknown>) => {
    onPatchSettings(patch)
    window.setTimeout(onSave, 0)
  }

  const saveSiteSoon = () => {
    if (!onSaveSite) return
    window.setTimeout(() => { void onSaveSite() }, 0)
  }

  const enableSiteMetaIfNeeded = () => {
    if (!metaPixelConnected || site.metaCapiEnabled) return
    onPatchSite({ metaCapiEnabled: true })
    saveSiteSoon()
  }

  const patchVideoGateTheme = (patch: Partial<SiteTheme>) => {
    const nextTheme = {
      ...videoGateTheme,
      ...patch
    }
    const settingsPatch: Record<string, unknown> = {
      videoFormGateEmbeddedTheme: nextTheme
    }
    if (patch.submitText !== undefined) settingsPatch.videoFormGateSubmitText = patch.submitText
    if (patch.nextText !== undefined || patch.continueText !== undefined) {
      settingsPatch.videoFormGateNextText = patch.nextText ?? patch.continueText
    }
    if (patch.backText !== undefined) settingsPatch.videoFormGateBackText = patch.backText
    if (patch.formCompletionAction !== undefined) settingsPatch.completionAction = patch.formCompletionAction
    onPatchSettings(settingsPatch)
  }

  const patchButtonCopy = (patch: Record<string, unknown>, themePatch: Partial<SiteTheme>) => {
    onPatchSettings({
      ...patch,
      videoFormGateEmbeddedTheme: {
        ...videoGateTheme,
        ...themePatch
      }
    })
  }

  const patchQuestions = (nextQuestions: SiteBlock[], nextActiveQuestionId?: string) => {
    onPatchSettings({
      videoFormGateFormSiteId: selectedFormId,
      videoFormGateEmbeddedBlocks: normalizeVideoFormGateBlocks(nextQuestions, selectedFormId || site.id)
    })
    if (nextActiveQuestionId !== undefined) selectQuestion(nextActiveQuestionId)
  }

  const enableGate = (nextEnabled: boolean) => {
    if (!nextEnabled) {
      patchAndSaveSoon({ videoFormGateEnabled: false })
      return
    }

    const initialQuestions = questions.length ? questions : createVideoFormGateBlocks(site.id)
    patchAndSaveSoon({
      videoFormGateEnabled: true,
      videoFormGateTitle: getSettingString(settings, 'videoFormGateTitle') || VIDEO_FORM_GATE_DEFAULT_TITLE,
      videoFormGateDescription: getSettingString(settings, 'videoFormGateDescription') || VIDEO_FORM_GATE_DEFAULT_DESCRIPTION,
      videoFormGateTriggerSeconds: getSettingNumber(settings, 'videoFormGateTriggerSeconds', 0, 0, 86399),
      videoFormGateNextText: getSettingString(settings, 'videoFormGateNextText') || VIDEO_FORM_GATE_DEFAULT_NEXT_TEXT,
      videoFormGateBackText: getSettingString(settings, 'videoFormGateBackText') || VIDEO_FORM_GATE_DEFAULT_BACK_TEXT,
      videoFormGateSubmitText: getSettingString(settings, 'videoFormGateSubmitText') || VIDEO_FORM_GATE_DEFAULT_SUBMIT_TEXT,
      videoFormGateAnimation: getVideoFormGateAnimation(settings),
      videoFormGateVideoBackground: getVideoFormGateVideoBackground(settings),
      videoFormGateCompletionAction: getVideoFormGateFinalAction(settings),
      videoFormGateRepeatMode: getVideoFormGateRepeatMode(settings),
      videoFormGateStorageValue: getVideoFormGateStorageValue(settings),
      videoFormGateStorageUnit: getVideoFormGateStorageUnit(settings),
      completionAction: getVideoFormGateCompletionAction(settings),
      videoFormGateEmbeddedBlocks: normalizeVideoFormGateBlocks(initialQuestions, selectedFormId || site.id),
      videoFormGateEmbeddedTheme: buildVideoFormGateSourceTheme(site, settings)
    })
    selectQuestion(initialQuestions[0]?.id || '')
  }

  const selectSourceForm = (formId: string) => {
    const source = forms.find(form => form.id === formId) || null
    const sourceQuestions = source ? getVideoFormGateBlocksFromForm(source) : createVideoFormGateBlocks(site.id)
    const sourceSettingsForTheme = source
      ? { ...settings, videoFormGateEmbeddedTheme: source.theme || {} }
      : settings
    patchAndSaveSoon({
      videoFormGateFormSiteId: formId,
      videoFormGateEmbeddedBlocks: normalizeVideoFormGateBlocks(sourceQuestions, formId || site.id),
      videoFormGateEmbeddedTheme: buildVideoFormGateSourceTheme(source || site, sourceSettingsForTheme)
    })
    selectQuestion(sourceQuestions[0]?.id || '')
  }

  const patchQuestion = (fieldId: string, patch: Partial<SiteBlock>) => {
    patchQuestions(questions.map(question => question.id === fieldId ? { ...question, ...patch } : question), fieldId)
  }

  const patchQuestionSettings = (field: SiteBlock, patch: Record<string, unknown>) => {
    patchQuestion(field.id, {
      settings: {
        ...(field.settings || {}),
        ...patch,
        pageId: VIDEO_FORM_GATE_PAGE_ID
      }
    })
  }

  const removeQuestion = (fieldId: string) => {
    const currentIndex = questions.findIndex(question => question.id === fieldId)
    const nextQuestions = questions.filter(question => question.id !== fieldId)
    const nextActive = nextQuestions[Math.min(Math.max(currentIndex, 0), Math.max(nextQuestions.length - 1, 0))]?.id || ''
    patchQuestions(nextQuestions, nextActive)
    window.setTimeout(onSave, 0)
  }

  const moveQuestion = (fieldId: string, direction: BlockMoveDirection) => {
    const index = questions.findIndex(question => question.id === fieldId)
    const nextIndex = direction === 'up' ? index - 1 : index + 1
    if (index < 0 || nextIndex < 0 || nextIndex >= questions.length) return
    patchQuestions(arrayMove(questions, index, nextIndex), fieldId)
    window.setTimeout(onSave, 0)
  }

  const changeQuestionType = (nextType: SiteBlockType) => {
    if (!activeQuestion || !activeQuestionIsField || activeQuestionPreset) return
    patchQuestion(activeQuestion.id, {
      blockType: nextType,
      settings: {
        ...activeQuestionSettings,
        pageId: VIDEO_FORM_GATE_PAGE_ID,
        validation: nextType === 'email' ? 'email' : nextType === 'phone' ? 'phone' : '',
        ...(nextType === 'phone' ? { phoneCountrySelectorEnabled: true } : {}),
        customFieldDefinitionId: '',
        customFieldKey: '',
        customFieldLabel: '',
        customFieldDataType: ''
      }
    })
  }

  const renderActiveContentControls = () => {
    if (!activeQuestion || activeQuestionIsField) return null

    if (activeQuestion.blockType === 'image') {
      const mediaUrl = getSettingString(activeQuestionSettings, 'mediaUrl') || activeQuestion.content || ''
      return (
        <>
          <InlineBlockStyleControls
            site={videoGateSite}
            block={activeQuestion}
            blocks={questions}
            mode="all"
            onPatchSettings={(patch) => patchQuestionSettings(activeQuestion, patch)}
            onSave={onSave}
          />
          <MediaUploadControl
            kind="image"
            label="Elegir imagen"
            moduleEntityId={site.id}
            currentUrl={mediaUrl}
            onUploaded={(url) => patchQuestion(activeQuestion.id, {
              content: url,
              settings: { ...activeQuestionSettings, mediaUrl: url, pageId: VIDEO_FORM_GATE_PAGE_ID }
            })}
            onCommit={onSave}
          />
          <label className={styles.field}>
            <span>URL de imagen</span>
            <input
              value={mediaUrl}
              placeholder="https://..."
              onChange={(event) => {
                const nextUrl = event.target.value
                patchQuestion(activeQuestion.id, {
                  content: nextUrl,
                  settings: { ...activeQuestionSettings, mediaUrl: nextUrl, pageId: VIDEO_FORM_GATE_PAGE_ID }
                })
              }}
              onBlur={onSave}
            />
          </label>
          <label className={styles.field}>
            <span>Texto alternativo</span>
            <input value={activeQuestion.label || ''} onChange={(event) => patchQuestion(activeQuestion.id, { label: event.target.value })} onBlur={onSave} />
          </label>
        </>
      )
    }

    const textLabel = activeQuestion.blockType === 'title'
      ? 'Texto del título'
      : activeQuestion.blockType === 'subtitle'
        ? 'Texto del subtítulo'
        : 'Texto'

    return (
      <>
        {showActiveQuestionTypographyInEdit && (
          <InlineBlockStyleControls
            site={videoGateSite}
            block={activeQuestion}
            blocks={questions}
            mode="typography"
            onPatchSettings={(patch) => patchQuestionSettings(activeQuestion, patch)}
            onSave={onSave}
          />
        )}
        <label className={styles.field}>
          <span>{textLabel}</span>
          {activeQuestion.blockType === 'text' ? (
            <textarea rows={5} value={activeQuestion.content || ''} onChange={(event) => patchQuestion(activeQuestion.id, { content: event.target.value })} onBlur={onSave} />
          ) : (
            <input value={activeQuestion.content || ''} onChange={(event) => patchQuestion(activeQuestion.id, { content: event.target.value })} onBlur={onSave} />
          )}
        </label>
      </>
    )
  }

  const selectedSubmitContent = (
    <div className={styles.videoFormGateQuestionEditor}>
      <div className={styles.formFieldEditorHeader}>
        <div>
          <strong>Botón seleccionado</strong>
          <small>Texto del avance y envío del formulario</small>
        </div>
      </div>
      <label className={styles.field}>
        <span>Botón final</span>
        <input
          value={getSettingString(settings, 'videoFormGateSubmitText') || VIDEO_FORM_GATE_DEFAULT_SUBMIT_TEXT}
          onChange={(event) => patchButtonCopy({ videoFormGateSubmitText: event.target.value }, { submitText: event.target.value })}
          onBlur={onSave}
        />
      </label>
      <div className={styles.twoColumn}>
        <label className={styles.field}>
          <span>Botón siguiente</span>
          <input
            value={getSettingString(settings, 'videoFormGateNextText') || VIDEO_FORM_GATE_DEFAULT_NEXT_TEXT}
            onChange={(event) => patchButtonCopy({ videoFormGateNextText: event.target.value }, { nextText: event.target.value, continueText: event.target.value })}
            onBlur={onSave}
          />
        </label>
        <label className={styles.field}>
          <span>Botón anterior</span>
          <input
            value={getSettingString(settings, 'videoFormGateBackText') || VIDEO_FORM_GATE_DEFAULT_BACK_TEXT}
            onChange={(event) => patchButtonCopy({ videoFormGateBackText: event.target.value }, { backText: event.target.value })}
            onBlur={onSave}
          />
        </label>
      </div>
      {showDesignControls && (
        <FormSubmitGlobalStyleControls site={videoGateSite} onPatchTheme={patchVideoGateTheme} onSaveSite={onSave} />
      )}
    </div>
  )

  const finalAction = getVideoFormGateFinalAction(settings)
  const repeatMode = getVideoFormGateRepeatMode(settings)
  const completionTargetIds = getVideoFormGateCompletionTargetIds(settings)
  const needsCompletionTargets = finalAction === 'show_targets' || finalAction === 'hide_targets'
  const hasDesignableFields = questions.some(question => fieldBlockTypes.has(question.blockType))
  const hasRadioOrCheckboxFields = questions.some(question => question.blockType === 'radio' || question.blockType === 'checkboxes')
  const hasDropdownFields = questions.some(question => question.blockType === 'dropdown')
  const videoFormGateMetaEnabled = settings.videoFormGateMetaEnabled === true
  const videoFormGateMetaEventName = videoFormGateMetaEnabled
    ? normalizeMetaEventName(getSettingString(settings, 'videoFormGateMetaEventName'), 'Lead')
    : 'none'
  const videoFormGateMetaParameters = pruneMetaEventParametersForEvent(
    settings.videoFormGateMetaEventParameters as SiteMetaEventParameters | undefined,
    videoFormGateMetaEventName
  )

  const patchCompletionTargetIds = (nextIds: string[]) => {
    onPatchSettings({
      videoFormGateCompletionTargetId: nextIds[0] || '',
      videoFormGateCompletionTargetIds: nextIds
    })
  }

  const toggleCompletionTarget = (targetId: string) => {
    const nextIds = completionTargetIds.includes(targetId)
      ? completionTargetIds.filter(id => id !== targetId)
      : [...completionTargetIds, targetId]
    patchCompletionTargetIds(nextIds)
    window.setTimeout(onSave, 0)
  }

  const renderCompletionTargetPicker = () => {
    if (!needsCompletionTargets) return null
    if (!completionTargets.length) {
      return <p className={styles.videoActionHint}>Agrega un elemento en la página para poder mostrarlo u ocultarlo cuando el formulario termine.</p>
    }

    return (
      <div className={styles.videoActionTargetList}>
        {completionTargets.map(target => {
          const selected = completionTargetIds.includes(target.id)
          const targetIcon = target.blockType && target.blockType !== 'popup'
            ? blockIcons[target.blockType as SiteBlockType] || <LayoutTemplate size={15} />
            : <LayoutTemplate size={15} />
          return (
            <button
              key={target.id}
              type="button"
              aria-pressed={selected}
              className={`${styles.videoActionTargetChoice} ${selected ? styles.videoActionTargetChoiceActive : ''}`}
              onMouseEnter={() => onTargetHover?.(target.id)}
              onMouseLeave={() => onTargetHover?.('')}
              onFocus={() => onTargetHover?.(target.id)}
              onBlur={() => onTargetHover?.('')}
              onClick={() => toggleCompletionTarget(target.id)}
            >
              <span className={styles.videoActionTargetIcon}>{targetIcon}</span>
              <span className={styles.videoActionTargetText}>
                <span>{target.label}</span>
                <small>{target.kindLabel}</small>
              </span>
              <span className={styles.videoActionTargetCheck} aria-hidden="true">
                {selected ? <Check size={13} /> : null}
              </span>
            </button>
          )
        })}
      </div>
    )
  }

  return (
    <div className={styles.videoFormGatePanel}>
      <div className={styles.videoFormGateSwitchRow}>
        <div>
          <strong>Formulario de video</strong>
          <span>Bloquea el video y captura respuestas dentro del mismo reproductor.</span>
        </div>
        {showEnableSwitch && (
          <Switch checked={enabled} onChange={enableGate} aria-label="Activar formulario de video" />
        )}
      </div>

      {enabled && (
        <>
          <label className={styles.field}>
            <span>Origen del formulario</span>
            <CustomSelect value={selectedFormId} onChange={(event) => selectSourceForm(event.target.value)} onBlur={onSave}>
              <option value="">Crear nuevo formulario</option>
              {forms.filter(form => form.id !== site.id).map(form => (
                <option key={form.id} value={form.id}>Usar formulario guardado: {form.name}</option>
              ))}
            </CustomSelect>
          </label>

          <div className={styles.settingsGroup}>
            <div className={styles.panelSubheader}>Contenido del formulario</div>
            {showTriggerControl && (
              <label className={styles.field}>
                <span>Mostrar en segundo</span>
                <NumberInput
                  value={getSettingNumber(settings, 'videoFormGateTriggerSeconds', 0, 0, 86399)}
                  min={0}
                  max={86399}
                  step={1}
                  onValueChange={(value) => onPatchSettings({ videoFormGateTriggerSeconds: Math.round(value) })}
                  onBlur={onSave}
                />
              </label>
            )}

            <label className={styles.field}>
              <span>Título</span>
              <input
                value={getSettingString(settings, 'videoFormGateTitle') || VIDEO_FORM_GATE_DEFAULT_TITLE}
                onChange={(event) => onPatchSettings({ videoFormGateTitle: event.target.value })}
                onBlur={onSave}
              />
            </label>

            <label className={styles.field}>
              <span>Descripción</span>
              <textarea
                rows={2}
                value={getSettingString(settings, 'videoFormGateDescription') || VIDEO_FORM_GATE_DEFAULT_DESCRIPTION}
                onChange={(event) => onPatchSettings({ videoFormGateDescription: event.target.value })}
                onBlur={onSave}
              />
            </label>

            <div className={styles.threeColumn}>
              <label className={styles.field}>
                <span>Botón siguiente</span>
                <input
                  value={getSettingString(settings, 'videoFormGateNextText') || VIDEO_FORM_GATE_DEFAULT_NEXT_TEXT}
                  onChange={(event) => patchButtonCopy({ videoFormGateNextText: event.target.value }, { nextText: event.target.value, continueText: event.target.value })}
                  onBlur={onSave}
                />
              </label>
              <label className={styles.field}>
                <span>Botón anterior</span>
                <input
                  value={getSettingString(settings, 'videoFormGateBackText') || VIDEO_FORM_GATE_DEFAULT_BACK_TEXT}
                  onChange={(event) => patchButtonCopy({ videoFormGateBackText: event.target.value }, { backText: event.target.value })}
                  onBlur={onSave}
                />
              </label>
              <label className={styles.field}>
                <span>Botón final</span>
                <input
                  value={getSettingString(settings, 'videoFormGateSubmitText') || VIDEO_FORM_GATE_DEFAULT_SUBMIT_TEXT}
                  onChange={(event) => patchButtonCopy({ videoFormGateSubmitText: event.target.value }, { submitText: event.target.value })}
                  onBlur={onSave}
                />
              </label>
            </div>

            <label className={styles.field}>
              <span>Animación de aparición</span>
              <CustomSelect
                value={getVideoFormGateAnimation(settings)}
                onChange={(event) => onPatchSettings({ videoFormGateAnimation: event.target.value })}
                onBlur={onSave}
              >
                {videoFormGateAnimationOptions.map(option => (
                  <option key={option.value} value={option.value}>{option.label}</option>
                ))}
              </CustomSelect>
            </label>
          </div>

          {showCompletionControls && (
            <div className={styles.settingsGroup}>
              <div className={styles.panelSubheader}>Al terminar</div>
              <label className={styles.field}>
                <span>Cuando se complete el formulario</span>
                <CustomSelect
                  value={finalAction}
                  onChange={(event) => {
                    const action = event.target.value as VideoFormGateCompletionAction
                    const patch: Record<string, unknown> = { videoFormGateCompletionAction: action }
                    if (action === 'redirect' && !getSettingString(settings, 'videoFormGateRedirectUrl') && videoGateTheme.formQualifiedRedirectUrl) {
                      patch.videoFormGateRedirectUrl = videoGateTheme.formQualifiedRedirectUrl
                    }
                    onPatchSettings(patch)
                  }}
                  onBlur={onSave}
                >
                  {videoFormGateCompletionActionOptions.map(option => (
                    <option key={option.value} value={option.value}>{option.label}</option>
                  ))}
                </CustomSelect>
              </label>
              {finalAction === 'redirect' && (
                <label className={styles.field}>
                  <span>URL destino</span>
                  <input
                    type="url"
                    value={getSettingString(settings, 'videoFormGateRedirectUrl') || videoGateTheme.formQualifiedRedirectUrl || ''}
                    placeholder="https://tudominio.com/gracias"
                    onChange={(event) => {
                      onPatchSettings({ videoFormGateRedirectUrl: event.target.value })
                      patchVideoGateTheme({ formQualifiedRedirectUrl: event.target.value })
                    }}
                    onBlur={onSave}
                  />
                </label>
              )}
              {renderCompletionTargetPicker()}
              <div className={styles.twoColumn}>
                <label className={styles.field}>
                  <span>Si ya respondió</span>
                  <CustomSelect
                    value={repeatMode}
                    onChange={(event) => onPatchSettings({ videoFormGateRepeatMode: event.target.value })}
                    onBlur={onSave}
                  >
                    {videoFormGateRepeatModeOptions.map(option => (
                      <option key={option.value} value={option.value}>{option.label}</option>
                    ))}
                  </CustomSelect>
                </label>
                {repeatMode === 'remember_visitor' ? (
                  <div className={styles.inlineFields}>
                    <label className={styles.field}>
                      <span>Guardar por</span>
                      <NumberInput
                        value={getVideoFormGateStorageValue(settings)}
                        min={1}
                        max={730}
                        step={1}
                        onValueChange={(value) => onPatchSettings({ videoFormGateStorageValue: Math.round(value) })}
                        onBlur={onSave}
                      />
                    </label>
                    <label className={styles.field}>
                      <span>Unidad</span>
                      <CustomSelect
                        value={getVideoFormGateStorageUnit(settings)}
                        onChange={(event) => onPatchSettings({ videoFormGateStorageUnit: event.target.value })}
                        onBlur={onSave}
                      >
                        {videoFormGateStorageUnitOptions.map(option => (
                          <option key={option.value} value={option.value}>{option.label}</option>
                        ))}
                      </CustomSelect>
                    </label>
                  </div>
                ) : (
                  <p className={styles.muted}>
                    {repeatMode === 'session'
                      ? 'No vuelve a aparecer hasta que termine esta sesión del navegador.'
                      : 'El formulario vuelve a aparecer cada vez que el visitante entra.'}
                  </p>
                )}
              </div>
            </div>
          )}

          {showCompletionControls && metaPixelConnected && (
            <div className={styles.settingsGroup}>
              <div className={styles.panelSubheader}>Evento Meta al completar</div>
              <MetaVideoEventSettings
                title="Meta Pixel + CAPI"
                description="Solo se envía si la persona completa el formulario sin quedar descalificada"
                siteMetaEnabled={Boolean(site.metaCapiEnabled)}
                metaPixelConnected={metaPixelConnected}
                eventEnabled={videoFormGateMetaEnabled}
                eventName={videoFormGateMetaEventName}
                parameters={videoFormGateMetaParameters}
                onToggle={(enabled) => {
                  if (enabled) enableSiteMetaIfNeeded()
                  patchAndSaveSoon({
                    videoFormGateMetaEnabled: enabled,
                    videoFormGateMetaEventName: enabled ? normalizeEnabledMetaEventName(videoFormGateMetaEventName) : 'none',
                    videoFormGateMetaEventParameters: enabled ? videoFormGateMetaParameters : {}
                  })
                }}
                onChangeEvent={(metaEventName) => {
                  patchAndSaveSoon({
                    videoFormGateMetaEnabled: metaEventName !== 'none',
                    videoFormGateMetaEventName: metaEventName,
                    videoFormGateMetaEventParameters: pruneMetaEventParametersForEvent(videoFormGateMetaParameters, metaEventName)
                  })
                }}
                onChangeParameters={(metaEventParameters) => onPatchSettings({ videoFormGateMetaEventParameters: metaEventParameters })}
                onCommit={onSave}
              />
              <p className={styles.muted}>
                Si una respuesta descalifica el formulario, no se enviará este evento personalizado de Meta.
              </p>
            </div>
          )}

          <div className={styles.settingsGroup}>
            <div className={styles.panelSubheader}>Elementos del formulario</div>
            <p className={styles.muted}>Agrega preguntas, textos o imágenes desde la barra izquierda. Toca un elemento en el video para editarlo aquí.</p>

            <div className={styles.formFieldList}>
              {questions.map((question, index) => {
                const selected = activeElement !== 'submit' && activeQuestion?.id === question.id
                return (
                  <button
                    key={question.id}
                    type="button"
                    className={`${styles.formFieldItem} ${selected ? styles.formFieldItemActive : ''}`}
                    onClick={() => selectQuestion(question.id)}
                  >
                    <span>{blockIcons[question.blockType]}</span>
                    <span>
                      <strong>{question.label || question.content || blockLabels[question.blockType] || 'Elemento'}</strong>
                      <small>{blockLabels[question.blockType]}{question.required && fieldBlockTypes.has(question.blockType) ? ' - requerida' : ''}</small>
                    </span>
                    <em>{index + 1}</em>
                  </button>
                )
              })}
              <button
                type="button"
                className={`${styles.formFieldItem} ${activeElement === 'submit' ? styles.formFieldItemActive : ''}`}
                onClick={selectSubmit}
              >
                <span><MousePointerClick size={14} /></span>
                <span>
                  <strong>Botón del formulario</strong>
                  <small>{getSettingString(settings, 'videoFormGateSubmitText') || VIDEO_FORM_GATE_DEFAULT_SUBMIT_TEXT}</small>
                </span>
                <em>{questions.length + 1}</em>
              </button>
            </div>

            {activeElement === 'submit' ? selectedSubmitContent : activeQuestion ? (
              <div className={styles.videoFormGateQuestionEditor}>
                <div className={styles.formFieldEditorHeader}>
                  <div>
                    <strong>{activeQuestionIsField ? 'Pregunta seleccionada' : 'Elemento seleccionado'}</strong>
                    <small>{blockLabels[activeQuestion.blockType] || 'Elemento'}</small>
                  </div>
                  <div className={styles.formFieldActions}>
                    <button type="button" disabled={questions[0]?.id === activeQuestion.id} onClick={() => moveQuestion(activeQuestion.id, 'up')} aria-label="Subir elemento"><ArrowUp size={14} /></button>
                    <button type="button" disabled={questions[questions.length - 1]?.id === activeQuestion.id} onClick={() => moveQuestion(activeQuestion.id, 'down')} aria-label="Bajar elemento"><ArrowDown size={14} /></button>
                    <button type="button" onClick={() => removeQuestion(activeQuestion.id)} aria-label="Eliminar elemento"><Trash2 size={14} /></button>
                  </div>
                </div>

                {!activeQuestionIsField ? renderActiveContentControls() : (
                  <>
                    <label className={styles.field}>
                      <span>Pregunta visible</span>
                      <input value={activeQuestion.label} onChange={(event) => patchQuestion(activeQuestion.id, { label: event.target.value })} onBlur={onSave} />
                    </label>

                    <label className={styles.field}>
                      <span>Texto de ayuda</span>
                      <textarea rows={2} value={activeQuestion.content} onChange={(event) => patchQuestion(activeQuestion.id, { content: event.target.value })} onBlur={onSave} />
                    </label>

                    {!activeQuestionPreset && (
                      <div className={styles.twoColumn}>
                        <label className={styles.field}>
                          <span>Tipo de campo</span>
                          <CustomSelect value={activeQuestion.blockType} onChange={(event) => changeQuestionType(event.target.value as SiteBlockType)} onBlur={onSave}>
                            {videoFormGateFieldTypes.map(type => <option key={type} value={type}>{blockLabels[type]}</option>)}
                          </CustomSelect>
                        </label>
                        <label className={styles.field}>
                          <span>Validación</span>
                          <CustomSelect value={getSettingString(activeQuestionSettings, 'validation')} onChange={(event) => patchQuestionSettings(activeQuestion, { validation: event.target.value })} onBlur={onSave}>
                            {fieldValidationOptions.map(option => <option key={option.value || 'none'} value={option.value}>{option.label}</option>)}
                          </CustomSelect>
                        </label>
                      </div>
                    )}

                    {!isChoiceBlock(activeQuestion.blockType) && (
                      <label className={styles.field}>
                        <span>Texto dentro del campo</span>
                        <input value={activeQuestion.placeholder} onChange={(event) => patchQuestion(activeQuestion.id, { placeholder: event.target.value })} onBlur={onSave} />
                      </label>
                    )}

                    <label className={styles.checkboxLabel}>
                      <input
                        type="checkbox"
                        checked={Boolean(activeQuestion.required)}
                        onChange={(event) => {
                          patchQuestion(activeQuestion.id, { required: event.target.checked })
                          window.setTimeout(onSave, 0)
                        }}
                      />
                      <span>Campo requerido</span>
                    </label>

                    {activeQuestion.blockType === 'phone' && !activeQuestionPreset && (
                      <label className={styles.checkboxLabel}>
                        <input
                          type="checkbox"
                          checked={isPhoneCountrySelectorEnabled(activeQuestion)}
                          onChange={(event) => {
                            patchQuestionSettings(activeQuestion, { phoneCountrySelectorEnabled: event.target.checked })
                            window.setTimeout(onSave, 0)
                          }}
                        />
                        <span>Mostrar país y lada</span>
                      </label>
                    )}

                    <CustomFieldBindingControl
                      block={activeQuestion}
                      customFields={customFields}
                      customFieldFolders={customFieldFolders}
                      onPatchSettings={(patch) => patchQuestionSettings(activeQuestion, patch)}
                      onCustomFieldCreated={onCustomFieldCreated}
                      onSave={onSave}
                    />

                    {isChoiceBlock(activeQuestion.blockType) && (
                      <OptionsRulesEditor
                        block={activeQuestion}
                        blocks={questions.filter(item => fieldBlockTypes.has(item.blockType))}
                        pages={questionPages}
                        sitePages={pages}
                        activeSitePageId={activePageId}
                        onPatchBlock={(patch) => patchQuestion(activeQuestion.id, patch)}
                        onSave={onSave}
                      />
                    )}
                  </>
                )}
              </div>
            ) : (
              <p className={styles.muted}>Arrastra un elemento desde la barra izquierda para configurar el formulario de video.</p>
            )}
          </div>

          {showDesignControls && (
            <div className={styles.settingsGroup}>
              <div className={styles.panelSubheader}>Diseño del formulario</div>
              <div className={styles.twoColumn}>
                <ColorField
                  label="Fondo del formulario"
                  value={getThemePaint(videoGateTheme, 'backgroundColor', userBgColor(videoGateSite) || resolvedPageBg(videoGateSite))}
                  allowGradient
                  onChange={(value) => patchVideoGateTheme({ backgroundColor: value })}
                  onCommit={onSave}
                />
                <ColorField
                  label="Fondo del video"
                  value={getVideoFormGateVideoBackground(settings)}
                  allowGradient
                  onChange={(value) => onPatchSettings({ videoFormGateVideoBackground: value })}
                  onCommit={onSave}
                />
              </div>
              <div className={styles.twoColumn}>
                <ColorField
                  label="Texto"
                  value={getThemePaint(videoGateTheme, 'textColor', isSiteDark(videoGateSite) ? '#ffffff' : '#111827')}
                  allowGradient
                  onChange={(value) => patchVideoGateTheme({ textColor: value, textColorCustom: true })}
                  onCommit={onSave}
                />
              </div>
              {hasDesignableFields && (
                <FormFieldGlobalStyleControls site={videoGateSite} onPatchTheme={patchVideoGateTheme} onSaveSite={onSave} />
              )}
              {(hasRadioOrCheckboxFields || hasDropdownFields) && (
                <FormOptionGlobalStyleControls
                  site={videoGateSite}
                  showChoiceControls={hasRadioOrCheckboxFields}
                  showSelectControls={hasDropdownFields}
                  onPatchTheme={patchVideoGateTheme}
                  onSaveSite={onSave}
                />
              )}
              <FormSubmitGlobalStyleControls site={videoGateSite} onPatchTheme={patchVideoGateTheme} onSaveSite={onSave} />
            </div>
          )}
        </>
      )}
    </div>
  )
}

const LandingBlockSettings: React.FC<LandingBlockSettingsProps> = ({ site, block, blocks, forms, calendars, pages, activePageId, connectedSocialProfiles, loadingSocialProfiles, onPatchSettings, onSave }) => {
  const settings = block.settings || {}

  if (isPanelBlock(block)) {
    const panelTitle = block.blockType === HEADER_PANEL_BLOCK_TYPE
      ? getHeaderScope(block) === HEADER_SCOPE_GLOBAL ? 'Header global' : 'Header de esta página'
      : 'Panel inferior'
    return (
      <div className={styles.settingsGroup}>
        <div className={styles.panelSubheader}>{panelTitle}</div>
        <label className={styles.field}>
          <span>Enlaces del panel</span>
          <textarea
            rows={4}
            value={stringifyPanelLinks(settings)}
            placeholder="Nombre del enlace | https://..."
            onChange={(event) => onPatchSettings({ panelLinks: parsePanelLinks(event.target.value) })}
            onBlur={onSave}
          />
        </label>
        <p className={styles.muted}>Escribe un enlace por línea. Si no quieres enlaces, deja esta caja vacía.</p>
      </div>
    )
  }

  if (block.blockType === SECTION_BLOCK_TYPE) {
    return (
      <div className={styles.settingsGroup}>
        <div className={styles.panelSubheader}>Tipo de franja</div>
        <label className={styles.field}>
          <span>Columnas</span>
          <CustomSelect
            value={String(getSectionColumns(block))}
            onChange={(event) => onPatchSettings({ sectionColumns: Number(event.target.value) })}
            onBlur={onSave}
          >
            <option value="1">Una columna</option>
            <option value="2">Dos columnas</option>
            <option value="3">Tres columnas</option>
          </CustomSelect>
        </label>
        <DimensionField
          label="Espacio entre columnas"
          value={getSettingNumber(settings, 'sectionGap', DEFAULT_SECTION_GAP, 0, 80)}
          min={0}
          max={80}
          onChange={(value) => onPatchSettings({ sectionGap: value })}
          onCommit={onSave}
        />
      </div>
    )
  }

  if (['hero', 'cta'].includes(block.blockType)) {
    return (
      <div className={styles.settingsGroup}>
        <ButtonActionFields settings={settings} pages={pages} activePageId={activePageId} onPatchSettings={onPatchSettings} onSave={onSave} />
      </div>
    )
  }

  if (block.blockType === 'button') {
    return (
      <div className={styles.settingsGroup}>
        <ButtonActionFields settings={settings} pages={pages} activePageId={activePageId} onPatchSettings={onPatchSettings} onSave={onSave} />
      </div>
    )
  }

  if (block.blockType === 'social_profile') {
    return (
      <SocialProfileSettings
        site={site}
        settings={settings}
        connectedSocialProfiles={connectedSocialProfiles}
        loadingSocialProfiles={loadingSocialProfiles}
        onPatchSettings={onPatchSettings}
        onSave={onSave}
      />
    )
  }

  if (block.blockType === 'countdown') {
    const mode = getCountdownMode(settings)
    const visitorMode = getCountdownVisitorMode(settings)
    const storageUnit = getCountdownStorageUnit(settings)
    const completionAction = getCountdownCompletionAction(settings)
    const targetBlocks = blocks.filter(item => item.id !== block.id && !isPanelBlock(item))
    const selectedTargetId = getSettingString(settings, 'countdownTargetBlockId')

    return (
      <>
        <div className={styles.settingsGroup}>
          <div className={styles.panelSubheader}>Cuenta regresiva</div>
          <label className={styles.field}>
            <span>Tipo de contador</span>
            <CustomSelect value={mode} onChange={(event) => onPatchSettings({ countdownMode: event.target.value })} onBlur={onSave}>
              {countdownModeOptions.map(option => (
                <option key={option.value} value={option.value}>{option.label}</option>
              ))}
            </CustomSelect>
          </label>

          {mode === 'date' ? (
            <label className={styles.field}>
              <span>Fecha final</span>
              <input
                type="datetime-local"
                value={getSettingString(settings, 'countdownTargetDate')}
                onChange={(event) => onPatchSettings({ countdownTargetDate: event.target.value })}
                onBlur={onSave}
              />
            </label>
          ) : (
            <div className={styles.twoColumn}>
              <DimensionField label="Días" value={getSettingNumber(settings, 'countdownDurationDays', 1, 0, 3650)} min={0} max={3650} unit="" onChange={(value) => onPatchSettings({ countdownDurationDays: value })} onCommit={onSave} />
              <DimensionField label="Horas" value={getSettingNumber(settings, 'countdownDurationHours', 0, 0, 23)} min={0} max={23} unit="" onChange={(value) => onPatchSettings({ countdownDurationHours: value })} onCommit={onSave} />
              <DimensionField label="Minutos" value={getSettingNumber(settings, 'countdownDurationMinutes', 0, 0, 59)} min={0} max={59} unit="" onChange={(value) => onPatchSettings({ countdownDurationMinutes: value })} onCommit={onSave} />
              <DimensionField label="Segundos" value={getSettingNumber(settings, 'countdownDurationSeconds', 0, 0, 59)} min={0} max={59} unit="" onChange={(value) => onPatchSettings({ countdownDurationSeconds: value })} onCommit={onSave} />
            </div>
          )}

          <label className={styles.field}>
            <span>Persistencia</span>
            <CustomSelect value={visitorMode} onChange={(event) => onPatchSettings({ countdownVisitorMode: event.target.value })} onBlur={onSave}>
              {countdownVisitorModeOptions.map(option => (
                <option key={option.value} value={option.value}>{option.label}</option>
              ))}
            </CustomSelect>
          </label>

          <div className={styles.twoColumn}>
            <DimensionField
              label="Caducidad"
              value={getSettingNumber(settings, 'countdownStorageValue', 30, 1, 730)}
              min={1}
              max={730}
              unit=""
              onChange={(value) => onPatchSettings({ countdownStorageValue: value })}
              onCommit={onSave}
            />
            <label className={styles.field}>
              <span>Unidad</span>
              <CustomSelect value={storageUnit} onChange={(event) => onPatchSettings({ countdownStorageUnit: event.target.value })} onBlur={onSave}>
                {countdownStorageUnitOptions.map(option => (
                  <option key={option.value} value={option.value}>{option.label}</option>
                ))}
              </CustomSelect>
            </label>
          </div>

          <label className={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={getSettingBoolean(settings, 'countdownRestartOnVisit', false)}
              onChange={(event) => {
                onPatchSettings({ countdownRestartOnVisit: event.target.checked })
                window.setTimeout(onSave, 0)
              }}
            />
            <span>Reiniciar en cada visita</span>
          </label>
          <label className={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={getSettingBoolean(settings, 'countdownResetOnReturn', false)}
              onChange={(event) => {
                onPatchSettings({ countdownResetOnReturn: event.target.checked })
                window.setTimeout(onSave, 0)
              }}
            />
            <span>Restablecer cuando vuelva a entrar</span>
          </label>
          <label className={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={getSettingBoolean(settings, 'countdownAutoExpire', true)}
              onChange={(event) => {
                onPatchSettings({ countdownAutoExpire: event.target.checked })
                window.setTimeout(onSave, 0)
              }}
            />
            <span>Expirar automáticamente el registro</span>
          </label>
          <label className={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={getSettingBoolean(settings, 'countdownShowLabels', true)}
              onChange={(event) => {
                onPatchSettings({ countdownShowLabels: event.target.checked })
                window.setTimeout(onSave, 0)
              }}
            />
            <span>Mostrar etiquetas de tiempo</span>
          </label>
        </div>

        <div className={styles.settingsGroup}>
          <div className={styles.panelSubheader}>Cuando termine</div>
          <label className={styles.field}>
            <span>Acción final</span>
            <CustomSelect value={completionAction} onChange={(event) => onPatchSettings({ countdownCompletionAction: event.target.value })} onBlur={onSave}>
              {countdownCompletionActionOptions.map(option => (
                <option key={option.value} value={option.value}>{option.label}</option>
              ))}
            </CustomSelect>
          </label>

          {completionAction === 'redirect' && (
            <label className={styles.field}>
              <span>URL destino</span>
              <input
                type="url"
                value={getSettingString(settings, 'countdownRedirectUrl')}
                placeholder="https://tudominio.com/oferta"
                onChange={(event) => onPatchSettings({ countdownRedirectUrl: event.target.value })}
                onBlur={onSave}
              />
            </label>
          )}

          {(completionAction === 'hide_target' || completionAction === 'show_target') && (
            <label className={styles.field}>
              <span>Elemento objetivo</span>
              <CustomSelect value={selectedTargetId} onChange={(event) => onPatchSettings({ countdownTargetBlockId: event.target.value })} onBlur={onSave}>
                <option value="">Selecciona un elemento</option>
                {targetBlocks.map(target => (
                  <option key={target.id} value={target.id}>{getElementPanelName(target)}</option>
                ))}
              </CustomSelect>
            </label>
          )}

          <label className={styles.field}>
            <span>Texto al vencer</span>
            <input
              value={getSettingString(settings, 'countdownExpiredText')}
              placeholder="Tiempo terminado"
              onChange={(event) => onPatchSettings({ countdownExpiredText: event.target.value })}
              onBlur={onSave}
            />
          </label>
        </div>
      </>
    )
  }

  if (block.blockType === 'image' || block.blockType === 'video') {
    const mediaKind = block.blockType === 'image' ? 'image' : 'video'
    return (
      <div className={styles.settingsGroup}>
        <MediaUploadControl
          kind={mediaKind}
          label={mediaKind === 'image' ? 'Elegir imagen' : 'Elegir video'}
          moduleEntityId={site.id}
          currentUrl={getSettingString(settings, 'mediaUrl')}
          onUploaded={(url, asset) => onPatchSettings(mediaKind === 'video'
            ? withUploadedVideoSettings(settings, url, asset)
            : { mediaUrl: url })}
          onCommit={onSave}
        />
        <label className={styles.field}>
          <span>{block.blockType === 'image' ? 'URL de imagen' : 'URL de video'}</span>
          <input value={getSettingString(settings, 'mediaUrl')} onChange={(event) => onPatchSettings({ mediaUrl: event.target.value })} onBlur={onSave} />
        </label>
        {block.blockType === 'video' && (
          <VideoPlayerSettingsControls
            settings={settings}
            mediaUrl={getSettingString(settings, 'mediaUrl')}
            sections="playback"
            onPatchSettings={onPatchSettings}
            onSave={onSave}
          />
        )}
      </div>
    )
  }

  if (block.blockType === 'calendar_embed') {
    const selectedCalendarId = getSettingString(settings, 'calendarId')
    const selectedCalendar = calendars.find(calendar => calendar.id === selectedCalendarId)

    return (
      <div className={styles.settingsGroup}>
        <label className={styles.field}>
          <span>Calendario a embeber</span>
          <CustomSelect
            value={selectedCalendarId}
            onChange={(event) => {
              const calendar = calendars.find(item => item.id === event.target.value)
              onPatchSettings({
                calendarId: calendar?.id || '',
                calendarSlug: calendar?.slug || calendar?.widgetSlug || '',
                calendarName: calendar?.name || ''
              })
            }}
            onBlur={onSave}
          >
            <option value="">Selecciona un calendario</option>
            {calendars.map(calendar => (
              <option key={calendar.id} value={calendar.id}>{calendar.name}</option>
            ))}
          </CustomSelect>
        </label>
        {selectedCalendar ? (
          <p className={styles.muted}>
            {selectedCalendar.publicUrlEnabled
              ? `Se mostrará como iframe usando ${selectedCalendar.publicBookingPath || '/calendar/...'}`
              : selectedCalendar.publicUrlUnavailableReason || 'Conecta el dominio público general para que funcione publicamente.'}
          </p>
        ) : (
          <p className={styles.muted}>Este bloque usa la URL pública del calendario en el mismo dominio del site.</p>
        )}
      </div>
    )
  }

  if (block.blockType === 'form_embed') {
    const embeddedBlocks = Array.isArray(settings.embeddedBlocks) ? settings.embeddedBlocks as SiteBlock[] : []

    return (
      <div className={styles.settingsGroup}>
        <label className={styles.field}>
          <span>Origen del formulario</span>
          <CustomSelect value={getSettingString(settings, 'formSiteId')} onChange={(event) => onPatchSettings({ formSiteId: event.target.value, embeddedBlocks: undefined, embeddedPages: undefined })} onBlur={onSave}>
            <option value="">Crear nuevo formulario</option>
            {forms.filter(form => form.id !== site.id).map(form => (
              <option key={form.id} value={form.id}>Usar formulario guardado: {form.name}</option>
            ))}
          </CustomSelect>
        </label>
        <label className={styles.field}>
          <span>Al terminar el formulario</span>
          <CustomSelect value={getFormCompletionAction(settings)} onChange={(event) => onPatchSettings({ completionAction: event.target.value })} onBlur={onSave}>
            <option value="next_page">Ir a la siguiente página al terminar</option>
            <option value="next_page_if_qualified">Ir a la siguiente página solo si califica</option>
            <option value="form_default">Mantener la configuración actual del formulario</option>
          </CustomSelect>
        </label>
        <button
          type="button"
          className={styles.inlineCreateButton}
          onClick={() => {
            onPatchSettings({ formSiteId: '', embeddedPages: normalizePagesForSave(normalizeEmbeddedFormPages()), embeddedBlocks: createEmbeddedBlocks(site.id) })
            window.setTimeout(onSave, 0)
          }}
        >
          <Plus size={15} />
          Crear formulario básico
        </button>
        {embeddedBlocks.length > 0 && (
          <p className={styles.muted}>{embeddedBlocks.length} elementos guardados en este componente.</p>
        )}
      </div>
    )
  }

  return null
}

const FormResponsesQuickPanel: React.FC<{
  forms: PublicSite[]
  selectedFormId: string
  selectedSite: PublicSite | null
  rows: LeadRow[]
  loading: boolean
  onSelectForm: (siteId: string) => void
  onRefresh: () => void
  onClose: () => void
}> = ({
  forms,
  selectedFormId,
  selectedSite,
  rows,
  loading,
  onSelectForm,
  onRefresh,
  onClose
}) => {
  const selectedForm = forms.find(form => form.id === selectedFormId) || null
  const displaySite = selectedSite || selectedForm
  const submissionsCount = displaySite?.submissionsCount ?? selectedForm?.submissionsCount ?? rows.length

  return (
    <section className={styles.formResponsesPanel}>
      <div className={styles.formResponsesHeader}>
        <div>
          <span>Respuestas rápidas</span>
          <h3>{displaySite?.name || 'Elige un formulario'}</h3>
          <p>Selecciona un formulario y revisa sus envíos sin salir de la biblioteca.</p>
        </div>
        <div className={styles.formResponsesActions}>
          <Badge variant="info">{submissionsCount} envíos</Badge>
          <Button variant="secondary" size="sm" loading={loading} onClick={onRefresh} leftIcon={<RefreshCw size={15} />}>
            Refrescar
          </Button>
          <Button variant="ghost" size="sm" onClick={onClose} leftIcon={<X size={15} />}>
            Cerrar
          </Button>
        </div>
      </div>

      <label className={styles.formResponsesPicker} data-ristak-unstyled>
        <span>Formulario</span>
        <CustomSelect
          value={selectedFormId}
          onChange={(event) => onSelectForm(event.target.value)}
          disabled={!forms.length || loading}
        >
          {forms.length ? forms.map(form => (
            <option key={form.id} value={form.id}>
              {form.name} · {form.submissionsCount || 0} envíos
            </option>
          )) : (
            <option value="">Sin formularios</option>
          )}
        </CustomSelect>
      </label>

      <div className={styles.formResponsesSheet} data-ristak-table>
        <table data-ristak-table-element>
          <thead>
            <tr>
              <th>Lead</th>
              <th>Respuestas</th>
              <th>Estado</th>
              <th>Reglas</th>
              <th>Fecha</th>
            </tr>
          </thead>
          <tbody>
            {rows.map(row => {
              const answers = getSubmissionAnswerPreview(row, displaySite)
              return (
                <tr key={row.id}>
                  <td>
                    <div className={styles.formResponsesLead}>
                      <strong>{row.contactName || row.contactEmail || row.contactPhone || 'Lead sin nombre'}</strong>
                      <span>{[row.contactEmail, row.contactPhone].filter(Boolean).join(' · ') || row.domain || 'Sin contacto ligado'}</span>
                    </div>
                  </td>
                  <td>
                    <div className={styles.formResponsesAnswers}>
                      {answers.length ? answers.map(answer => (
                        <span key={`${row.id}-${answer.label}`}>
                          <strong>{answer.label}</strong>
                          {answer.value}
                        </span>
                      )) : (
                        <em>Sin respuestas visibles</em>
                      )}
                    </div>
                  </td>
                  <td>
                    <Badge variant={row.status === 'disqualified' ? 'warning' : 'success'}>
                      {row.status === 'disqualified' ? 'Descalificado' : 'Recibido'}
                    </Badge>
                  </td>
                  <td>{getSubmissionRulesSummary(row)}</td>
                  <td>{formatDate(row.createdAt)}</td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>

      {!rows.length && (
        <div className={styles.formResponsesEmpty}>
          <ListChecks size={24} />
          <strong>{loading ? 'Cargando respuestas...' : 'Sin respuestas todavía'}</strong>
          <p>{loading ? 'Estamos consultando los envíos de este formulario.' : 'Cuando alguien responda este formulario, aparecerá aquí al instante al refrescar.'}</p>
        </div>
      )}
    </section>
  )
}

interface SitesAnalyticsPanelProps {
  sites: PublicSite[]
  allSites: PublicSite[]
  sitesById: Map<string, PublicSite>
  videos: MediaAsset[]
  selectedSiteType: SitesAnalyticsSiteType
  selectedSiteId: string
  selectedVideoId: string
  selectedVideo: MediaAsset | null
  analyticsSummary: SitesAnalyticsSummary | null
  analytics: MediaStreamAnalytics | null
  loadingVideos: boolean
  loadingAnalytics: boolean
  analyticsError: string
  analyticsSummaryError: string
  startDate: string
  endDate: string
  onSiteTypeChange: (value: SitesAnalyticsSiteType) => void
  onSiteChange: (value: string) => void
  onVideoChange: (value: string) => void
  onDateRangeChange: (start: string, end: string) => void
}

const SitesAnalyticsPanel: React.FC<SitesAnalyticsPanelProps> = ({
  sites,
  allSites,
  sitesById,
  videos,
  selectedSiteType,
  selectedSiteId,
  selectedVideoId,
  selectedVideo,
  analyticsSummary,
  analytics,
  loadingVideos,
  loadingAnalytics,
  analyticsError,
  analyticsSummaryError,
  startDate,
  endDate,
  onSiteTypeChange,
  onSiteChange,
  onVideoChange,
  onDateRangeChange
}) => {
  const retentionVideoRef = useRef<HTMLVideoElement | null>(null)
  const retentionScrubbingRef = useRef(false)
  const [retentionPlaybackPercent, setRetentionPlaybackPercent] = useState(0)
  const [retentionCurrentSeconds, setRetentionCurrentSeconds] = useState(0)
  const [retentionDurationSeconds, setRetentionDurationSeconds] = useState(0)
  const [isRetentionPlaying, setIsRetentionPlaying] = useState(false)
  const [isRetentionMuted, setIsRetentionMuted] = useState(false)
  const [isRetentionScrubbing, setIsRetentionScrubbing] = useState(false)
  const retentionPreviewUrl = getSitesAnalyticsStoragePreviewUrl(selectedVideo)
  const syncRetentionVideoPlayback = useCallback((video: HTMLVideoElement) => {
    const duration = Number.isFinite(video.duration) && video.duration > 0 ? video.duration : 0
    const nextPercent = duration > 0 ? clampSitesPercent((video.currentTime / duration) * 100) : 0
    setRetentionPlaybackPercent(nextPercent)
    setRetentionCurrentSeconds(Number.isFinite(video.currentTime) ? video.currentTime : 0)
    setRetentionDurationSeconds(duration)
    setIsRetentionPlaying(!video.paused && !video.ended)
    setIsRetentionMuted(video.muted || video.volume === 0)
  }, [])
  const syncRetentionPlayback = useCallback((event: React.SyntheticEvent<HTMLVideoElement>) => {
    syncRetentionVideoPlayback(event.currentTarget)
  }, [syncRetentionVideoPlayback])
  const seekRetentionPlaybackToPercent = useCallback((percent: number) => {
    const nextPercent = clampSitesPercent(percent)
    setRetentionPlaybackPercent(nextPercent)

    const video = retentionVideoRef.current
    if (!video) return

    const fallbackDuration = readSitesNumber(selectedVideo?.duration)
    const duration = Number.isFinite(video.duration) && video.duration > 0
      ? video.duration
      : fallbackDuration

    if (duration <= 0) return

    video.currentTime = (nextPercent / 100) * duration
  }, [selectedVideo?.duration])
  const seekRetentionPlaybackFromClientX = useCallback((clientX: number, element: HTMLElement) => {
    const rect = element.getBoundingClientRect()
    const width = rect.width > 0 ? rect.width : 1
    seekRetentionPlaybackToPercent(((clientX - rect.left) / width) * 100)
  }, [seekRetentionPlaybackToPercent])
  const stopRetentionScrubbing = useCallback(() => {
    retentionScrubbingRef.current = false
    setIsRetentionScrubbing(false)
  }, [])
  const handleRetentionScrubPointerDown = useCallback((event: React.PointerEvent<HTMLDivElement>) => {
    if (!retentionPreviewUrl || (event.button !== undefined && event.button !== 0)) return
    event.preventDefault()
    retentionScrubbingRef.current = true
    setIsRetentionScrubbing(true)
    event.currentTarget.setPointerCapture(event.pointerId)
    seekRetentionPlaybackFromClientX(event.clientX, event.currentTarget)
  }, [retentionPreviewUrl, seekRetentionPlaybackFromClientX])
  const handleRetentionScrubPointerMove = useCallback((event: React.PointerEvent<HTMLDivElement>) => {
    if (!retentionScrubbingRef.current) return
    event.preventDefault()
    seekRetentionPlaybackFromClientX(event.clientX, event.currentTarget)
  }, [seekRetentionPlaybackFromClientX])
  const handleRetentionScrubPointerUp = useCallback((event: React.PointerEvent<HTMLDivElement>) => {
    if (!retentionScrubbingRef.current) return
    event.preventDefault()
    seekRetentionPlaybackFromClientX(event.clientX, event.currentTarget)
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId)
    }
    stopRetentionScrubbing()
  }, [seekRetentionPlaybackFromClientX, stopRetentionScrubbing])
  const handleRetentionScrubKeyDown = useCallback((event: React.KeyboardEvent<HTMLDivElement>) => {
    if (!retentionPreviewUrl) return

    const step = event.shiftKey ? 5 : 1
    if (event.key === 'ArrowLeft') {
      event.preventDefault()
      seekRetentionPlaybackToPercent(retentionPlaybackPercent - step)
    } else if (event.key === 'ArrowRight') {
      event.preventDefault()
      seekRetentionPlaybackToPercent(retentionPlaybackPercent + step)
    } else if (event.key === 'Home') {
      event.preventDefault()
      seekRetentionPlaybackToPercent(0)
    } else if (event.key === 'End') {
      event.preventDefault()
      seekRetentionPlaybackToPercent(100)
    }
  }, [retentionPlaybackPercent, retentionPreviewUrl, seekRetentionPlaybackToPercent])
  const handleRetentionTogglePlay = useCallback(() => {
    const video = retentionVideoRef.current
    if (!video || !retentionPreviewUrl) return

    if (video.paused || video.ended) {
      if (video.ended) video.currentTime = 0
      void video.play().catch(() => {
        setIsRetentionPlaying(false)
      })
    } else {
      video.pause()
    }

    syncRetentionVideoPlayback(video)
  }, [retentionPreviewUrl, syncRetentionVideoPlayback])
  const handleRetentionToggleMute = useCallback(() => {
    const video = retentionVideoRef.current
    if (!video || !retentionPreviewUrl) return

    video.muted = !video.muted
    syncRetentionVideoPlayback(video)
  }, [retentionPreviewUrl, syncRetentionVideoPlayback])
  const handleRetentionTimelinePointerDown = useCallback((event: React.PointerEvent<HTMLDivElement>) => {
    if (!retentionPreviewUrl || (event.button !== undefined && event.button !== 0)) return
    event.preventDefault()
    seekRetentionPlaybackFromClientX(event.clientX, event.currentTarget)
  }, [retentionPreviewUrl, seekRetentionPlaybackFromClientX])

  useEffect(() => {
    stopRetentionScrubbing()
    setRetentionPlaybackPercent(0)
    setRetentionCurrentSeconds(0)
    setRetentionDurationSeconds(0)
    setIsRetentionPlaying(false)
    setIsRetentionMuted(false)
  }, [selectedVideoId, stopRetentionScrubbing])

  const isVideosView = selectedSiteType === 'videos'
  const isFormsView = selectedSiteType === 'forms'
  const typeLabel = isVideosView ? 'Videos' : isFormsView ? 'Formularios' : 'Sitios'
  const entityLabel = isFormsView ? 'formulario' : 'sitio'
  const entityPluralLabel = isFormsView ? 'formularios' : 'sitios'
  const siteFilterLabel = isVideosView ? 'Origen' : isFormsView ? 'Formulario' : 'Sitio'
  const siteFilterEmptyLabel = isVideosView ? 'Todos los orígenes' : isFormsView ? 'Todos los formularios' : 'Todos los sitios'
  const siteRows = sites.map(site => ({
    site,
    stats: analyticsSummary?.sites?.[site.id] || getSiteAnalyticsStats(site),
    videoCount: videos.filter(asset => getMediaSourceSiteId(asset) === site.id).length
  }))
  const totalSiteViews = siteRows.reduce((total, row) => total + row.stats.views, 0)
  const totalVisitors = siteRows.reduce((total, row) => total + row.stats.visitors, 0)
  const totalSessions = siteRows.reduce((total, row) => total + row.stats.sessions, 0)
  const totalConversions = siteRows.reduce((total, row) => total + row.stats.conversions, 0)
  const conversionRate = totalVisitors > 0 ? Number(((totalConversions / totalVisitors) * 100).toFixed(1)) : 0
  const averageConversions = sites.length > 0 ? totalConversions / sites.length : 0
  const publishedCount = sites.filter(site => site.status === 'published').length
  const draftCount = sites.filter(site => site.status === 'draft').length
  const archivedCount = sites.filter(site => site.status === 'archived').length
  const latestUpdatedSite = [...siteRows]
    .sort((a, b) => new Date(b.site.updatedAt).getTime() - new Date(a.site.updatedAt).getTime())[0]?.site || null
  const rowsByViews = [...siteRows].sort((a, b) => b.stats.views - a.stats.views)
  const rowsByConversions = [...siteRows].sort((a, b) =>
    b.stats.conversions - a.stats.conversions || b.stats.conversionRate - a.stats.conversionRate
  )
  const rowsByConversionRate = [...siteRows].sort((a, b) =>
    b.stats.conversionRate - a.stats.conversionRate || b.stats.conversions - a.stats.conversions
  )
  const rowsByVideoCount = [...siteRows].filter(row => row.videoCount > 0).sort((a, b) => b.videoCount - a.videoCount)
  const aggregateVideoStats = analyticsSummary?.videos || null
  const aggregateVideoSummary = aggregateVideoStats?.summary || null
  const videoRows = buildSitesVideoAggregateRows(videos, sitesById, aggregateVideoStats?.byAssetId || null)
  const videoRowsByViews = [...videoRows].sort((a, b) => b.views - a.views || b.watchTime - a.watchTime)
  const videoRowsByWatchTime = [...videoRows].sort((a, b) => b.watchTime - a.watchTime || b.views - a.views)
  const videoRowsByAverageWatch = [...videoRows].sort((a, b) => b.averageWatchTime - a.averageWatchTime || b.views - a.views)
  const selectedVideoStats = getMediaStreamVideoRecord(selectedVideo)
  const firstPartyTracking = analytics?.firstPartyTracking || null
  const firstPartySummary = firstPartyTracking?.summary || null
  const totalVideoViews = aggregateVideoSummary
    ? readSitesNumber(aggregateVideoSummary.plays)
    : videoRows.reduce((total, row) => total + row.views, 0)
  const totalVideoWatchTime = aggregateVideoSummary
    ? readSitesNumber(aggregateVideoSummary.watchedSeconds)
    : videoRows.reduce((total, row) => total + row.watchTime, 0)
  const selectedVideoMode = Boolean(selectedVideoId && selectedVideo)
  const totalStreamVideos = videoRows.filter(row => row.streamVideoId).length
  const totalVideoOrigins = new Set(videoRows.map(row => row.sourceSiteId).filter(Boolean)).size
  const aggregateAverageWatchTime = aggregateVideoSummary
    ? readSitesNumber(aggregateVideoSummary.averageWatchSeconds)
    : totalVideoViews > 0 ? totalVideoWatchTime / totalVideoViews : 0
  const aggregateEngagementValues = videoRows.map(row => row.engagementScore).filter(value => value > 0)
  const aggregateEngagementScore = aggregateVideoSummary
    ? readSitesNumber(aggregateVideoSummary.avgProgressPercent)
    : aggregateEngagementValues.length
      ? aggregateEngagementValues.reduce((total, value) => total + value, 0) / aggregateEngagementValues.length
      : null
  const aggregateVideoChart = videoRowsByViews
    .slice(0, 10)
    .reverse()
    .map(row => ({
      label: shortenSitesText(getMediaAssetDisplayName(row.asset), 18),
      value: row.views,
      value2: Math.round((row.watchTime / 60) * 10) / 10
    }))
  const videoViews = selectedVideo ? (firstPartySummary?.plays ?? analytics?.summary.views ?? readSitesNumber(selectedVideoStats.views)) : totalVideoViews
  const videoLoads = selectedVideo ? (firstPartySummary?.playbackSessions ?? 0) : (aggregateVideoSummary?.playbackSessions ?? videoRows.reduce((total, row) => total + row.playbackSessions, 0))
  const uniqueVideoViewers = selectedVideo ? (firstPartySummary?.totalViewers ?? 0) : (aggregateVideoSummary?.totalViewers ?? videoRows.reduce((total, row) => total + row.totalViewers, 0))
  const videoWatchTime = selectedVideo ? (firstPartySummary?.watchedSeconds ?? analytics?.summary.watchTime ?? readSitesNumber(selectedVideoStats.totalWatchTime)) : totalVideoWatchTime
  const averageWatchTime = selectedVideo ? (firstPartySummary?.averageWatchSeconds ?? analytics?.summary.averageWatchTime ?? readSitesNumber(selectedVideoStats.averageWatchTime)) : 0
  const engagementScore = selectedVideo ? (firstPartySummary?.avgProgressPercent ?? analytics?.summary.engagementScore ?? null) : null
  const playRate = selectedVideo ? firstPartySummary?.playRatePercent ?? null : null
  const completionRate = selectedVideo ? firstPartySummary?.completionRatePercent ?? null : null
  const dropOffRate = selectedVideo ? firstPartySummary?.dropOffPercent ?? null : null
  const streamVideoId = getMediaStreamVideoId(selectedVideo)
  const viewsChart = buildSitesChartPoints(
    selectSitesChartSource(firstPartyTracking?.viewsChart || [], analytics?.viewsChart || [], readSitesNumber(firstPartySummary?.plays) > 0),
    'count'
  )
  const watchTimeChart = buildSitesChartPoints(
    selectSitesChartSource(firstPartyTracking?.watchTimeChart || [], analytics?.watchTimeChart || [], readSitesNumber(firstPartySummary?.watchedSeconds) > 0),
    'seconds'
  )
  const heatmap = analytics?.heatmap || []
  const retentionSegments = buildSitesRetentionSegments(firstPartyTracking?.retentionSegments || [], heatmap)
  const retentionCurvePoints = buildSitesRetentionCurvePoints(retentionSegments)
  const retentionAreaPath = buildSitesRetentionAreaPath(retentionCurvePoints)
  const retentionPlayheadStyle = {
    '--video-retention-playhead': `${retentionPlaybackPercent}%`
  } as React.CSSProperties
  const retentionControlProgressStyle = {
    '--video-retention-control-progress': `${retentionPlaybackPercent}%`
  } as React.CSSProperties
  const retentionDisplayDuration = retentionDurationSeconds ||
    readSitesNumber(selectedVideo?.duration) ||
    retentionSegments[retentionSegments.length - 1]?.endSeconds ||
    0
  const videoViewers = firstPartyTracking?.viewers || []
  const currentVideoLabel = selectedVideo ? getSiteAnalyticsVideoLabel(selectedVideo, sitesById) : 'Sin video seleccionado'
  const scopeSiteLabel = selectedSiteId
    ? sitesById.get(selectedSiteId)?.name || 'Sitio seleccionado'
    : typeLabel
  const scopeDescription = isVideosView
    ? `${videos.length} video${videos.length === 1 ? '' : 's'} en filtro${selectedVideoMode ? ` · ${currentVideoLabel}` : ' · vista agregada'}`
    : `${allSites.length} sitio${allSites.length === 1 ? '' : 's'} total · ${sites.length} ${entityPluralLabel} en filtro · ${videos.length} video${videos.length === 1 ? '' : 's'} dentro`
  const kpiCards = isVideosView
    ? selectedVideoMode
      ? [
          { key: 'videos', icon: <Video size={16} />, label: 'Videos', value: formatSitesCompactNumber(videos.length) },
          { key: 'plays', icon: <Play size={16} />, label: 'Reproducciones', value: formatSitesCompactNumber(videoViews) },
          { key: 'viewers', icon: <Eye size={16} />, label: 'Visitantes', value: formatSitesCompactNumber(uniqueVideoViewers) },
          { key: 'play-rate', icon: <MousePointerClick size={16} />, label: 'Tasa de reproducción', value: playRate === null ? 'Sin dato' : formatSitesPercent(playRate) },
          { key: 'watch-time', icon: <Clock3 size={16} />, label: 'Tiempo visto', value: formatSitesSeconds(videoWatchTime) },
          { key: 'engagement', icon: <Flame size={16} />, label: 'Interacción', value: engagementScore === null ? 'Sin dato' : formatSitesPercent(engagementScore) }
        ]
      : [
          { key: 'videos', icon: <Video size={16} />, label: 'Videos', value: formatSitesCompactNumber(videos.length) },
          { key: 'plays', icon: <Play size={16} />, label: 'Reproducciones', value: formatSitesCompactNumber(totalVideoViews) },
          { key: 'origins', icon: <LayoutTemplate size={16} />, label: 'Orígenes', value: formatSitesCompactNumber(totalVideoOrigins) },
          { key: 'stream', icon: <CheckCircle2 size={16} />, label: 'Con Stream', value: `${formatSitesCompactNumber(totalStreamVideos)}/${formatSitesCompactNumber(videos.length)}` },
          { key: 'watch-time', icon: <Clock3 size={16} />, label: 'Tiempo visto', value: formatSitesSeconds(totalVideoWatchTime) },
          { key: 'average', icon: <Flame size={16} />, label: 'Promedio visto', value: formatSitesSeconds(aggregateAverageWatchTime) }
        ]
    : isFormsView
      ? [
          { key: 'forms', icon: <FormInput size={16} />, label: 'Formularios', value: formatSitesCompactNumber(sites.length) },
          { key: 'views', icon: <Eye size={16} />, label: 'Vistas', value: formatSitesCompactNumber(totalSiteViews) },
          { key: 'visitors', icon: <Globe2 size={16} />, label: 'Visitantes', value: formatSitesCompactNumber(totalVisitors) },
          { key: 'submissions', icon: <ListChecks size={16} />, label: 'Envíos', value: formatSitesCompactNumber(totalConversions) },
          { key: 'conversion', icon: <BarChart3 size={16} />, label: 'Conversión', value: formatSitesPercent(conversionRate) },
          { key: 'average', icon: <MousePointerClick size={16} />, label: 'Envíos/form', value: formatSitesDecimal(averageConversions) }
        ]
      : [
          { key: 'sites', icon: <LayoutTemplate size={16} />, label: 'Sitios', value: formatSitesCompactNumber(sites.length) },
          { key: 'views', icon: <Eye size={16} />, label: 'Vistas', value: formatSitesCompactNumber(totalSiteViews) },
          { key: 'visitors', icon: <Globe2 size={16} />, label: 'Visitantes', value: formatSitesCompactNumber(totalVisitors) },
          { key: 'sessions', icon: <MousePointerClick size={16} />, label: 'Sesiones', value: formatSitesCompactNumber(totalSessions) },
          { key: 'conversion', icon: <ListChecks size={16} />, label: 'Conversiones', value: formatSitesCompactNumber(totalConversions) },
          { key: 'rate', icon: <BarChart3 size={16} />, label: 'Conversión', value: formatSitesPercent(conversionRate) }
        ]

  const renderDetailRows = (
    rows: Array<{ key: string; icon: React.ReactNode; label: string; value: string }>,
    emptyText: string
  ) => (
    <div className={styles.sitesAnalyticsDetailList}>
      {rows.length ? rows.map(row => (
        <div key={row.key}>
          {row.icon}
          <span>{row.label}</span>
          <strong>{row.value}</strong>
        </div>
      )) : (
        <p className={styles.sitesAnalyticsDetailEmpty}>{emptyText}</p>
      )}
    </div>
  )

  const renderEntityAnalytics = () => {
    if (analyticsSummaryError) {
      return (
        <div className={styles.sitesAnalyticsEmpty}>
          <AlertTriangle size={24} />
          <strong>No se cargaron las analíticas</strong>
          <p>{analyticsSummaryError}</p>
        </div>
      )
    }

    if (!sites.length) {
      return (
        <div className={styles.sitesAnalyticsEmpty}>
          {isFormsView ? <FormInput size={24} /> : <LayoutTemplate size={24} />}
          <strong>Sin {entityPluralLabel} en este filtro</strong>
          <p>Cambia el tipo o el origen para ver analíticas individuales.</p>
        </div>
      )
    }

    return (
      <div className={styles.sitesAnalyticsGrid}>
        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>{isFormsView ? 'Formularios con más envíos' : 'Sitios con más vistas'}</span>
            <strong>{formatSitesCompactNumber(isFormsView ? totalConversions : totalSiteViews)}</strong>
          </div>
          {renderDetailRows(
            (isFormsView ? rowsByConversions : rowsByViews).slice(0, 5).map(row => ({
              key: row.site.id,
              icon: isFormsView ? <ListChecks size={15} /> : <Eye size={15} />,
              label: row.site.name,
              value: isFormsView
                ? `${formatSitesCompactNumber(row.stats.conversions)} envíos`
                : `${formatSitesCompactNumber(row.stats.views)} vistas`
            })),
            `Sin actividad registrada en estos ${entityPluralLabel}.`
          )}
        </div>

        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Conversión por {entityLabel}</span>
            <strong>{formatSitesPercent(conversionRate)}</strong>
          </div>
          {renderDetailRows(
            rowsByConversionRate.slice(0, 5).map(row => ({
              key: row.site.id,
              icon: <BarChart3 size={15} />,
              label: row.site.name,
              value: `${formatSitesPercent(row.stats.conversionRate)} · ${formatSitesCompactNumber(row.stats.conversions)}`
            })),
            `Sin conversiones registradas en estos ${entityPluralLabel}.`
          )}
        </div>

        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Videos dentro de {entityPluralLabel}</span>
            <strong>{formatSitesCompactNumber(videos.length)}</strong>
          </div>
          {renderDetailRows(
            rowsByVideoCount.slice(0, 5).map(row => ({
              key: row.site.id,
              icon: <Video size={15} />,
              label: row.site.name,
              value: `${formatSitesCompactNumber(row.videoCount)} video${row.videoCount === 1 ? '' : 's'}`
            })),
            `No hay videos asociados a estos ${entityPluralLabel}.`
          )}
        </div>

        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Estado</span>
            <strong>{formatSitesCompactNumber(sites.length)} {entityPluralLabel}</strong>
          </div>
          {renderDetailRows([
            { key: 'published', icon: <CheckCircle2 size={15} />, label: 'Publicados', value: formatSitesCompactNumber(publishedCount) },
            { key: 'draft', icon: <Pencil size={15} />, label: 'Borradores', value: formatSitesCompactNumber(draftCount) },
            { key: 'archived', icon: <Trash2 size={15} />, label: 'Archivados', value: formatSitesCompactNumber(archivedCount) },
            ...(latestUpdatedSite ? [{
              key: 'latest',
              icon: <CalendarDays size={15} />,
              label: `Último cambio: ${latestUpdatedSite.name}`,
              value: getSiteStatusLabel(latestUpdatedSite.status)
            }] : [])
          ], `Sin estado para estos ${entityPluralLabel}.`)}
        </div>
      </div>
    )
  }

  const renderAggregateVideoAnalytics = () => {
    if (analyticsSummaryError) {
      return (
        <div className={styles.sitesAnalyticsEmpty}>
          <AlertTriangle size={24} />
          <strong>No se cargaron los datos de videos</strong>
          <p>{analyticsSummaryError}</p>
        </div>
      )
    }

    if (!videos.length) {
      return (
        <div className={styles.sitesAnalyticsEmpty}>
          <Video size={24} />
          <strong>Sin videos en este filtro</strong>
          <p>Cuando un sitio o formulario use un video sincronizado, aquí saldrán sus métricas agregadas.</p>
        </div>
      )
    }

    return (
      <div className={styles.videoAggregateDashboard}>
        <div className={`${styles.sitesAnalyticsChartBlock} ${styles.videoAggregateChartWide}`}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Rendimiento por video</span>
            <strong>{formatSitesCompactNumber(totalVideoViews)} reproducciones</strong>
          </div>
          {aggregateVideoChart.length ? (
            <AreaChart
              data={aggregateVideoChart}
              height={250}
              color="var(--accent)"
              color2="var(--pos)"
              showLegend
              legendLabels={{ label1: 'Reproducciones', label2: 'Min vistos' }}
              formatValue={(value) => formatSitesCompactNumber(value)}
              formatTooltipValue={(value, key) => (
                key === 'value2'
                  ? `${formatSitesCompactNumber(value)} min vistos`
                  : `${formatSitesCompactNumber(value)} reproducciones`
              )}
            />
          ) : (
            <div className={styles.sitesAnalyticsChartEmpty}>Sin reproducciones sincronizadas todavía.</div>
          )}
        </div>

        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Videos con más reproducciones</span>
            <strong>{formatSitesCompactNumber(videoRowsByViews[0]?.views || 0)} top</strong>
          </div>
          {renderDetailRows(
            videoRowsByViews.slice(0, 6).map(row => ({
              key: row.key,
              icon: <Play size={15} />,
              label: row.label,
              value: `${formatSitesCompactNumber(row.views)} reproducciones`
            })),
            'Sin reproducciones registradas en estos videos.'
          )}
        </div>

        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Tiempo visto por video</span>
            <strong>{formatSitesSeconds(totalVideoWatchTime)}</strong>
          </div>
          {renderDetailRows(
            videoRowsByWatchTime.slice(0, 6).map(row => ({
              key: row.key,
              icon: <Clock3 size={15} />,
              label: row.label,
              value: `${formatSitesSeconds(row.watchTime)} · ${formatSitesSeconds(row.averageWatchTime)} prom.`
            })),
            'Sin tiempo visto registrado.'
          )}
        </div>

        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Orígenes con videos</span>
            <strong>{formatSitesCompactNumber(totalVideoOrigins)}</strong>
          </div>
          {renderDetailRows(
            rowsByVideoCount.slice(0, 6).map(row => ({
              key: row.site.id,
              icon: <LayoutTemplate size={15} />,
              label: row.site.name,
              value: `${formatSitesCompactNumber(row.videoCount)} video${row.videoCount === 1 ? '' : 's'}`
            })),
            'Sin orígenes asociados.'
          )}
        </div>

        <div className={styles.sitesAnalyticsChartBlock}>
          <div className={styles.sitesAnalyticsChartTitle}>
            <span>Calidad de consumo</span>
            <strong>{aggregateEngagementScore === null ? 'Sin interacción' : formatSitesPercent(aggregateEngagementScore)}</strong>
          </div>
          {renderDetailRows([
            { key: 'stream-ready', icon: <CheckCircle2 size={15} />, label: 'Videos listos en Stream', value: `${formatSitesCompactNumber(totalStreamVideos)} de ${formatSitesCompactNumber(videos.length)}` },
            { key: 'average-watch', icon: <Flame size={15} />, label: 'Promedio visto por reproducción', value: formatSitesSeconds(aggregateAverageWatchTime) },
            { key: 'top-average', icon: <BarChart3 size={15} />, label: videoRowsByAverageWatch[0]?.label || 'Top promedio', value: videoRowsByAverageWatch[0] ? formatSitesSeconds(videoRowsByAverageWatch[0].averageWatchTime) : 'Sin dato' },
            { key: 'storage-only', icon: <Video size={15} />, label: 'Sólo storage / sin Stream', value: formatSitesCompactNumber(Math.max(0, videos.length - totalStreamVideos)) }
          ], 'Sin métricas suficientes.')}
        </div>
      </div>
    )
  }

  const renderVideoAnalytics = () => {
    if (!selectedVideoId) {
      return renderAggregateVideoAnalytics()
    }

    if (!selectedVideo) {
      return (
        <div className={styles.sitesAnalyticsEmpty}>
          <Video size={24} />
          <strong>Video no disponible</strong>
          <p>El video seleccionado ya no existe en este filtro. Elige otro video o vuelve a todos.</p>
        </div>
      )
    }

    if (!streamVideoId) {
      return (
        <div className={styles.sitesAnalyticsEmpty}>
          <BarChart3 size={24} />
          <strong>Video sin analíticas</strong>
          <p>Este archivo existe en storage, pero todavía no tiene ID de Stream para consultar reproducciones.</p>
        </div>
      )
    }

    if (analyticsError) {
      return (
        <div className={styles.sitesAnalyticsEmpty}>
          <AlertTriangle size={24} />
          <strong>No se cargaron los datos del video</strong>
          <p>{analyticsError}</p>
        </div>
      )
    }

    const primaryVideoMetrics = [
      { key: 'average', icon: <Clock3 size={15} />, label: 'Promedio visto', value: formatSitesSeconds(averageWatchTime), hint: 'Tiempo promedio por reproducción.' },
      { key: 'viewers', icon: <Eye size={15} />, label: 'Visitantes únicos', value: formatSitesCompactNumber(uniqueVideoViewers), hint: 'Personas o visitantes distintos detectados.' },
      { key: 'loads', icon: <MousePointerClick size={15} />, label: 'Cargas del reproductor', value: formatSitesCompactNumber(videoLoads), hint: 'Veces que el reproductor quedó listo en la página.' },
      { key: 'engagement', icon: <Flame size={15} />, label: 'Interacción promedio', value: engagementScore === null ? 'Sin dato' : formatSitesPercent(engagementScore), hint: 'Promedio del máximo visto por sesión.' },
      { key: 'plays', icon: <Play size={15} />, label: 'Reproducciones', value: formatSitesCompactNumber(videoViews), hint: `${formatSitesCompactNumber(videoLoads)} cargas detectadas.` },
      { key: 'play-rate', icon: <MousePointerClick size={15} />, label: 'Tasa de reproducción', value: playRate === null ? 'Sin dato' : formatSitesPercent(playRate), hint: 'Sesiones que sí reprodujeron el video.' },
      { key: 'completion', icon: <CheckCircle2 size={15} />, label: 'Finalización', value: completionRate === null ? 'Sin dato' : formatSitesPercent(completionRate), hint: `${firstPartySummary?.completions ?? 0} reproducciones completas.` },
      { key: 'drop-off', icon: <ArrowDown size={15} />, label: 'Abandono', value: dropOffRate === null ? 'Sin dato' : formatSitesPercent(dropOffRate), hint: 'Promedio que se perdió antes del final.' },
      { key: 'identified', icon: <Eye size={15} />, label: 'Contactos identificados', value: formatSitesCompactNumber(firstPartySummary?.identifiedContacts ?? 0), hint: `${formatSitesCompactNumber(firstPartySummary?.anonymousVisitors ?? 0)} visitantes anónimos.` }
    ]

    return (
      <div className={styles.videoEngagementDashboard}>
        <div className={styles.videoEngagementHero}>
          <section className={styles.videoDetailPanel}>
            <div className={styles.videoAnalyticsSectionHeader}>
              <div>
                <span>Detalle del video</span>
                <strong>{formatSitesSeconds(videoWatchTime)} vistos</strong>
              </div>
            </div>
            <div className={styles.videoDetailBody}>
              <div className={styles.videoDetailEngagementBlock}>
                <div className={styles.videoDetailBreakdownTitle}>
                  <Flame size={15} />
                  <span>Interacción del video</span>
                </div>
                <div className={styles.videoEngagementMetricList}>
                  {primaryVideoMetrics.map(metric => (
                    <div key={metric.key} className={styles.videoEngagementMetric}>
                      <span className={styles.videoEngagementMetricIcon}>{metric.icon}</span>
                      <span>{metric.label}</span>
                      <strong>{metric.value}</strong>
                      <small>{metric.hint}</small>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </section>

          <div className={styles.videoRetentionPanel}>
            <div className={styles.videoRetentionHeader}>
              <div>
                <span>Curva de retención</span>
                <strong>{retentionSegments.length ? `${formatSitesPercent(retentionSegments[retentionSegments.length - 1]?.retentionPercent || 0)} llega al final` : 'Sin datos'}</strong>
              </div>
              {loadingAnalytics && <em>Actualizando...</em>}
            </div>
            <div className={styles.videoRetentionChart}>
              {retentionPreviewUrl ? (
                <video
                  ref={retentionVideoRef}
                  className={styles.videoRetentionMedia}
                  src={retentionPreviewUrl}
                  playsInline
                  preload="metadata"
                  muted={isRetentionMuted}
                  data-no-track="true"
                  data-rstk-video-track="false"
                  data-rstk-analytics-preview="true"
                  onLoadedMetadata={syncRetentionPlayback}
                  onPlay={syncRetentionPlayback}
                  onTimeUpdate={syncRetentionPlayback}
                  onSeeking={syncRetentionPlayback}
                  onSeeked={syncRetentionPlayback}
                  onPause={syncRetentionPlayback}
                  onEnded={syncRetentionPlayback}
                  onVolumeChange={syncRetentionPlayback}
                />
              ) : (
                <div className={styles.videoRetentionMediaEmpty}>
                  <Video size={28} />
                  <span>Sin preview disponible</span>
                </div>
              )}
              <div className={styles.videoRetentionShade} aria-hidden="true" />
              <div
                className={styles.videoRetentionPlot}
                style={retentionPlayheadStyle}
                role="slider"
                tabIndex={retentionPreviewUrl ? 0 : -1}
                aria-label="Navegador de reproducción del video"
                aria-valuemin={0}
                aria-valuemax={100}
                aria-valuenow={Math.round(retentionPlaybackPercent)}
                aria-valuetext={`${formatSitesPercent(retentionPlaybackPercent)} del video`}
                aria-disabled={!retentionPreviewUrl}
                data-scrubbing={isRetentionScrubbing ? 'true' : undefined}
                onPointerDown={handleRetentionScrubPointerDown}
                onPointerMove={handleRetentionScrubPointerMove}
                onPointerUp={handleRetentionScrubPointerUp}
                onPointerCancel={stopRetentionScrubbing}
                onLostPointerCapture={stopRetentionScrubbing}
                onKeyDown={handleRetentionScrubKeyDown}
              >
                {retentionSegments.length && retentionCurvePoints ? (
                  <>
                    <svg className={styles.videoRetentionCurve} viewBox="0 0 100 100" preserveAspectRatio="none">
                      <path d={retentionAreaPath} />
                      <polyline points={retentionCurvePoints} />
                    </svg>
                    <div className={styles.videoRetentionGrid}>
                      <span>100%</span>
                      <span>75%</span>
                      <span>50%</span>
                      <span>25%</span>
                    </div>
                  </>
                ) : null}
                <span className={styles.videoRetentionPlayhead} aria-hidden="true" />
              </div>
              {!retentionSegments.length || !retentionCurvePoints ? (
                <div className={styles.videoRetentionEmptyNote}>Aún no hay suficientes reproducciones para dibujar retención.</div>
              ) : null}
              {retentionPreviewUrl ? (
                <div className={styles.videoRetentionControls}>
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className={styles.videoRetentionControlButton}
                    onClick={handleRetentionTogglePlay}
                    aria-label={isRetentionPlaying ? 'Pausar video' : 'Reproducir video'}
                  >
                    {isRetentionPlaying ? <Pause size={15} /> : <Play size={15} />}
                  </Button>
                  <div
                    className={styles.videoRetentionControlTimeline}
                    style={retentionControlProgressStyle}
                    role="progressbar"
                    aria-label="Progreso de reproducción"
                    aria-valuemin={0}
                    aria-valuemax={100}
                    aria-valuenow={Math.round(retentionPlaybackPercent)}
                    onPointerDown={handleRetentionTimelinePointerDown}
                  >
                    <span />
                  </div>
                  <span className={styles.videoRetentionControlTime}>
                    {formatSitesTimecode(retentionCurrentSeconds)} / {formatSitesTimecode(retentionDisplayDuration)}
                  </span>
                  <Button
                    type="button"
                    variant="ghost"
                    size="sm"
                    className={styles.videoRetentionControlButton}
                    onClick={handleRetentionToggleMute}
                    aria-label={isRetentionMuted ? 'Activar sonido' : 'Silenciar video'}
                  >
                    {isRetentionMuted ? <VolumeX size={15} /> : <Volume2 size={15} />}
                  </Button>
                </div>
              ) : null}
            </div>
          </div>
        </div>

        <div className={styles.videoEngagementGrid}>
          <section className={styles.videoAnalyticsSection}>
            <div className={styles.videoAnalyticsSectionHeader}>
              <div>
                <span>Mapas de calor por visitante</span>
                <strong>{formatSitesCompactNumber(videoViewers.length)} recientes</strong>
              </div>
              <div className={styles.viewerHeatmapLegend}>
                <span><i className={styles.viewerHeatmapPlayed} />Visto</span>
                <span><i className={styles.viewerHeatmapReplayed} />Repetido</span>
                <span><i className={styles.viewerHeatmapSkipped} />Saltado</span>
              </div>
            </div>
            {videoViewers.length ? (
              <div className={styles.viewerHeatmapList}>
                {videoViewers.slice(0, 8).map(viewer => (
                  <div key={viewer.key} className={styles.viewerHeatmapRow}>
                    <div className={styles.viewerIdentity}>
                      <strong>{getSitesViewerName(viewer)}</strong>
                      <span>{getSitesViewerMeta(viewer)}</span>
                    </div>
                    <div className={styles.viewerHeatmapTrack} aria-label={`Mapa de calor de ${getSitesViewerName(viewer)}`}>
                      {buildSitesViewerHeatmapSegments(viewer).map(segment => (
                        <span
                          key={segment.index}
                          className={
                            segment.state === 'replayed'
                              ? styles.viewerHeatmapReplayed
                              : segment.state === 'played'
                                ? styles.viewerHeatmapPlayed
                                : styles.viewerHeatmapSkipped
                          }
                          title={`${segment.label}: ${segment.state === 'skipped' ? 'saltado' : segment.state === 'replayed' ? 'repetido' : 'visto'}`}
                        />
                      ))}
                    </div>
                    <strong className={styles.viewerProgress}>{formatSitesPercent(viewer.maxProgressPercent)}</strong>
                  </div>
                ))}
              </div>
            ) : (
              <div className={styles.sitesAnalyticsChartEmpty}>Sin visitantes identificados todavía.</div>
            )}
          </section>
        </div>

        {(viewsChart.length || watchTimeChart.length) && (
          <div className={styles.videoStreamCharts}>
            {viewsChart.length ? (
              <div className={styles.sitesAnalyticsChartBlock}>
                <div className={styles.sitesAnalyticsChartTitle}>
                  <span>Reproducciones por periodo</span>
                  <strong>{formatSitesCompactNumber(videoViews)}</strong>
                </div>
                <AreaChart
                  data={viewsChart}
                  height={190}
                  showLegend={false}
                  formatValue={(value) => formatSitesCompactNumber(value)}
                  formatTooltipValue={(value) => `${formatSitesCompactNumber(value)} reproducciones`}
                />
              </div>
            ) : null}
            {watchTimeChart.length ? (
              <div className={styles.sitesAnalyticsChartBlock}>
                <div className={styles.sitesAnalyticsChartTitle}>
                  <span>Tiempo visto por periodo</span>
                  <strong>{formatSitesSeconds(videoWatchTime)}</strong>
                </div>
                <AreaChart
                  data={watchTimeChart}
                  height={190}
                  color="var(--pos)"
                  showLegend={false}
                  formatValue={(value) => `${formatSitesCompactNumber(value)}m`}
                  formatTooltipValue={(value) => `${formatSitesCompactNumber(value)} min vistos`}
                />
              </div>
            ) : null}
          </div>
        )}
      </div>
    )
  }

  return (
    <section className={`${styles.dataPanel} ${styles.sitesAnalyticsPanel}`} aria-busy={loadingVideos || (isVideosView && loadingAnalytics)}>
      <div className={styles.builderHeader}>
        <div>
          <h2>Analíticas</h2>
          <p>Rendimiento individual de sitios, formularios y videos publicados en Stream.</p>
        </div>
        <div className={styles.sitesAnalyticsHeaderActions}>
          <DateRangePicker
            startDate={startDate}
            endDate={endDate}
            onChange={onDateRangeChange}
          />
        </div>
      </div>

      <div className={styles.sitesAnalyticsFilters}>
        <div className={styles.sitesAnalyticsTypePicker}>
          <span>Tipo</span>
          <TabList
            tabs={sitesAnalyticsTypeTabs}
            activeTab={selectedSiteType}
            onTabChange={(value) => {
              if (isSitesAnalyticsSiteType(value)) onSiteTypeChange(value)
            }}
            variant="compact"
            fullWidth
            className={styles.sitesAnalyticsTypeToggle}
          />
        </div>

        <div className={`${styles.sitesAnalyticsFilterControls} ${isVideosView ? styles.sitesAnalyticsFilterControlsVideo : ''}`}>
          <label className={styles.field}>
            <span>{siteFilterLabel}</span>
            <CustomSelect value={selectedSiteId} onChange={(event) => onSiteChange(event.target.value)} disabled={sites.length === 0} portal>
              <option value="">{siteFilterEmptyLabel}</option>
              {sites.map(site => (
                <option key={site.id} value={site.id}>{site.name}</option>
              ))}
            </CustomSelect>
          </label>
          {isVideosView && (
            <label className={styles.field}>
              <span>Video</span>
              <CustomSelect
                value={selectedVideoId}
                onChange={(event) => onVideoChange(event.target.value)}
                disabled={videos.length === 0}
                className={styles.sitesAnalyticsVideoSelect}
                portal
              >
                {videos.length === 0 ? (
                  <option value="">Sin videos</option>
                ) : (
                  <>
                    <option value="">Todos los videos</option>
                    {videos.map(asset => (
                      <option key={asset.id} value={asset.id}>{getSiteAnalyticsVideoLabel(asset, sitesById)}</option>
                    ))}
                  </>
                )}
              </CustomSelect>
            </label>
          )}
        </div>
      </div>

      <div className={styles.sitesAnalyticsKpis}>
        {kpiCards.map(card => (
          <div key={card.key}>
            {card.icon}
            <span>{card.label}</span>
            <strong>{card.value}</strong>
          </div>
        ))}
      </div>

      <div className={styles.sitesAnalyticsScope}>
        <strong>{scopeSiteLabel}</strong>
        <span>{scopeDescription}</span>
      </div>

      {isVideosView ? renderVideoAnalytics() : renderEntityAnalytics()}
    </section>
  )
}

interface DomainsPanelProps {
  domainConfig: SitesDomainConfig
  domainInput: string
  verifying: boolean
  onDomainChange: (value: string) => void
  onVerifyDomain: () => void
}

const DomainsPanel: React.FC<DomainsPanelProps> = ({
  domainConfig,
  domainInput,
  verifying,
  onDomainChange,
  onVerifyDomain
}) => {
  const domainStatus: { label: string; variant: BadgeVariant } = !domainConfig.domain
    ? { label: 'Sin dominio', variant: 'neutral' }
    : domainConfig.renderDomainVerified
      ? { label: 'Verificado', variant: 'success' }
      : { label: 'Pendiente', variant: 'warning' }

  return (
    <section className={styles.dataPanel}>
      <div className={styles.builderHeader}>
        <div>
          <h2>Dominios</h2>
          <p>Conecta un solo dominio general para enrutar todos los formularios y sitios web.</p>
        </div>
        <Badge variant={domainStatus.variant}>{domainStatus.label}</Badge>
      </div>

      <div className={styles.domainEditor}>
        <label className={styles.field}>
          <span>Dominio público general</span>
          <input
            value={domainInput}
            placeholder="www.doctorramirez.com"
            onChange={(event) => onDomainChange(event.target.value)}
          />
        </label>
        {domainConfig.renderDomainError && <p className={styles.domainError}>{domainConfig.renderDomainError}</p>}
        <div className={styles.editorActions}>
          <Button onClick={onVerifyDomain} loading={verifying} disabled={!domainInput.trim()}>
            <CheckCircle2 size={16} />
            Verificar dominio
          </Button>
        </div>
      </div>
    </section>
  )
}
